-- Poems batch 35
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('e4b48f4e-3ce8-424a-9b21-81d6d8a5bf38','報何澤','崔安潛','唐','唐诗','tang','','[]','四十九年前及第，同年唯有老夫存。',32,'全唐诗/poet.tang.33000.json','["四十九年前及第，同年唯有老夫存。", "今日殷勤訪吾子，穩將鬐鬣上龍門。"]'),
('29a0b2d4-bcd6-4240-ad33-3e61152efae0','題文翁石室','裴鉶','唐','唐诗','tang','','[]','文翁石室有儀形，庠序千秋播德馨。',64,'全唐诗/poet.tang.33000.json','["文翁石室有儀形，庠序千秋播德馨。", "古柏尚留今日翠，高岷猶藹舊時青。", "人心未肯拋羶蟻，弟子依前學聚螢。", "更歎沱江無限水，爭流祗願到滄溟。"]'),
('e9586ded-0bcc-4376-8be2-9141eb600420','憤惋詩三首 一','劉損','唐','唐诗','tang','','[]','寶釵分股合無緣，魚在深淵日在天。',64,'全唐诗/poet.tang.33000.json','["寶釵分股合無緣，魚在深淵日在天。", "得意紫鸞休舞鏡，斷蹤青鳥罷銜箋。", "金杯倒覆難收水，玉軫傾攲嬾續弦。", "從此蘼蕪山下過，祗應將淚比黃泉。"]'),
('5fca2ab7-0e3d-4090-9cb7-401ea1c52047','憤惋詩三首 二','劉損','唐','唐诗','tang','','[]','鸞辭舊伴知何止，鳳得新梧想稱心。',64,'全唐诗/poet.tang.33000.json','["鸞辭舊伴知何止，鳳得新梧想稱心。", "紅粉尚存香幕幕，白雲將散信沈沈。", "已休磨琢投泥玉，嬾更經營買笑金。", "願作山頭似人石，丈夫衣上淚痕深。"]'),
('94a12de7-13b3-467e-8110-94d4cb276b25','憤惋詩三首 三','劉損','唐','唐诗','tang','','[]','舊嘗游處徧尋看，覩物傷情死一般。',64,'全唐诗/poet.tang.33000.json','["舊嘗游處徧尋看，覩物傷情死一般。", "買笑樓前花已謝，畫眉窗下月空殘。", "雲歸巫峽音容斷，路隔星河去住難。", "莫道詩成無淚下，淚如泉滴亦須乾。"]'),
('9871668d-9976-4317-ab31-64ea5aa25d79','幼作','鄭愚','唐','唐诗','tang','','[]','臺山初罷霧，岐海正分流。',24,'全唐诗/poet.tang.33000.json','["臺山初罷霧，岐海正分流。", "漁浦颺來笛，鴻逵翼去舟。"]'),
('c62bacd9-1b2d-42c8-8e21-00ff845411f4','茶詩','鄭愚','唐','唐诗','tang','','[]','嫩芽香且靈，吾謂草中英。',36,'全唐诗/poet.tang.33000.json','["嫩芽香且靈，吾謂草中英。", "夜臼和煙擣，寒爐對雪烹。", "惟憂碧粉散，嘗見綠花生。"]'),
('9c7ee228-88eb-4cc5-a801-b849aa72c322','郡樓望九華歌','霍總','唐','唐诗','tang','','[]','樓上坐見九子峰，翠雲赤日光溶溶。',112,'全唐诗/poet.tang.33000.json','["樓上坐見九子峰，翠雲赤日光溶溶。", "有時朝昏變疎密，八峰和煙一峰出。", "有時風卷天雨晴，聚立連連如弟兄。", "陽烏生子偶成數，丹鳳養雛同此名。", "日日遙看機已靜，未離塵躅思真境。", "子明龍駕騰九垓，陵陽相對空崔嵬。", "玉漿瑤草不可見，自有神仙風馬來。"]'),
('f524312b-9379-465b-a9ec-fb3e990f60a8','塞下曲','霍總','唐','唐诗','tang','','[]','曾當一面戰，頻出九重圍。',48,'全唐诗/poet.tang.33000.json','["曾當一面戰，頻出九重圍。", "但見爭鋒處，長須得勝歸。", "雪沾旗尾落，風斷節毛稀。", "豈要銘燕石，平生重武威。"]'),
('21aa65f5-6337-4c44-9adb-1434c662de9c','關山月','霍總','唐','唐诗','tang','','[]','珠瓏翡翠牀，白皙侍中郎。',48,'全唐诗/poet.tang.33000.json','["珠瓏翡翠牀，白皙侍中郎。", "五日來花下，雙童問道傍。", "到門車馬狹，連夜管弦長。", "每笑東家子，窺他宋玉牆。"]'),
('9c833a5a-c741-4171-9cdd-a971698eb7f8','驄馬','霍總','唐','唐诗','tang','','[]','青驪八尺高，俠客倚雄豪。',48,'全唐诗/poet.tang.33000.json','["青驪八尺高，俠客倚雄豪。", "踏雪生珠汗，障泥護錦袍。", "路傍看驟影，鞍底卷旋毛。", "豈獨連錢貴，酬恩更代勞。"]'),
('057eb3cc-a5e3-4f6c-b010-74c2fcf23cb2','雉朝飛','霍總','唐','唐诗','tang','','[]','五色有名翬，清晨挾兩雌。',48,'全唐诗/poet.tang.33000.json','["五色有名翬，清晨挾兩雌。", "羣羣飛自樂，步步飲相隨。", "覘葉逢人處，驚媒妬寵時。", "綠毛春鬬盡，強敵願君知。"]'),
('03b55ce0-77f8-4f9b-b52b-eed1c64d913c','木芙蓉','霍總','唐','唐诗','tang','','[]','本自江湖遠，常開霜露餘。',48,'全唐诗/poet.tang.33000.json','["本自江湖遠，常開霜露餘。", "爭春候穠李，得水異紅蕖。", "孤秀曾無偶，當門幸不鋤。", "誰能政搖落，繁綵照堦除。"]'),
('4482045e-3a96-4ba4-a413-df327778447f','採蓮女','霍總','唐','唐诗','tang','','[]','舟中採蓮女，兩兩催妝梳。',24,'全唐诗/poet.tang.33000.json','["舟中採蓮女，兩兩催妝梳。", "聞早渡江去，日高來起居。"]'),
('66f6514c-ad10-458e-8f44-dbbc62581fac','別僧','陳琡','唐','唐诗','tang','','[]','行若獨輪車，常畏大道覆。',36,'全唐诗/poet.tang.33000.json','["行若獨輪車，常畏大道覆。", "止若員底器，常恐他物觸。", "行止既如此，安得不離俗。"]'),
('e83cd7e3-9644-4051-b426-7d97af9aed04','早春殘雪','裴虔餘','唐','唐诗','tang','','[]','霽日彫瓊彩，幽庭減夜寒。',72,'全唐诗/poet.tang.33000.json','["霽日彫瓊彩，幽庭減夜寒。", "梅飄餘片積，日墮晚光殘。", "零落偏依桂，霏微不掩蘭。", "陰林披霧縠，小沼破冰盤。", "曲檻霜凝砌，疎篁玉碎竿。", "已聞三徑好，猶可訪袁安。"]'),
('d78306b9-595e-4e5e-8bbc-ef1be756d546','柳枝詞詠篙水濺妓衣','裴虔餘','唐','唐诗','tang','','[]','半額微黃金縷衣，玉搔頭褭鳳雙飛。',32,'全唐诗/poet.tang.33000.json','["半額微黃金縷衣，玉搔頭褭鳳雙飛。", "從教水濺羅裙濕，還道朝來行雨歸。"]'),
('76d1d979-7ae2-4695-80c8-8757de740b02','獻淮南師','李嶸','唐','唐诗','tang','','[]','雞樹煙含瑞氣凝，鳳池波待玉山澄。',32,'全唐诗/poet.tang.33000.json','["雞樹煙含瑞氣凝，鳳池波待玉山澄。", "國人久倚東關望，擬築沙堤到廣陵。"]'),
('35f4accd-0acf-4735-888c-d2f9a4ec8bb6','月','袁郊','唐','唐诗','tang','','[]','嫦娥竊藥出人間，藏在蟾宮不放還。',32,'全唐诗/poet.tang.33000.json','["嫦娥竊藥出人間，藏在蟾宮不放還。", "后羿遍尋無覓處，誰知天上却容奸。"]'),
('ee3055f1-8836-423b-86be-44390b228dc7','霜','袁郊','唐','唐诗','tang','','[]','古今何事不思量，盡信鄒生感彼蒼。',32,'全唐诗/poet.tang.33000.json','["古今何事不思量，盡信鄒生感彼蒼。", "但想燕山吹暖律，炎天豈不解飛霜。"]'),
('39b55630-d684-4c89-bfc9-b7a88df51a26','露','袁郊','唐','唐诗','tang','','[]','湛湛騰空下碧霄，地卑濕處更偏饒。',32,'全唐诗/poet.tang.33000.json','["湛湛騰空下碧霄，地卑濕處更偏饒。", "菅茅豐草皆霑潤，不道良田有旱苗。"]'),
('06a7e246-9c7a-46b4-8b44-fc6c27d637f6','雲','袁郊','唐','唐诗','tang','','[]','楚甸嘗聞旱魃侵，從龍應合解爲霖。',32,'全唐诗/poet.tang.33000.json','["楚甸嘗聞旱魃侵，從龍應合解爲霖。", "荒淫却入陽臺夢，惑亂懷襄父子心。"]'),
('6b288394-192c-472e-b86e-85f781ca94f0','游東觀山','張叢','唐','唐诗','tang','','[]','巖岫碧孱顏，靈蹤若可攀。',36,'全唐诗/poet.tang.33000.json','["巖岫碧孱顏，靈蹤若可攀。", "樓臺煙靄外，松竹翠微間。", "玉液寒深洞，秋光秀遠山。"]'),
('cfd9b680-d424-4485-9019-2151d92cc23b','擲盧作','馮衮','唐','唐诗','tang','','[]','八尺臺盤照面新，千金一擲鬬精神。',32,'全唐诗/poet.tang.33000.json','["八尺臺盤照面新，千金一擲鬬精神。", "合是賭時須賭取，不妨回首乞閑人。"]'),
('c0522f7b-b41f-4bfe-9a76-e74151b12231','戲酒妓','馮衮','唐','唐诗','tang','','[]','醉眼從伊百度斜，是他家屬是他家。',32,'全唐诗/poet.tang.33000.json','["醉眼從伊百度斜，是他家屬是他家。", "低聲向道人知也，隔坐剛拋豆蔻花。"]'),
('370f1c67-24a6-4015-892a-8764ed779dfe','老僧','鄭綮','唐','唐诗','tang','','[]','日照四山雪，老僧門未開。',48,'全唐诗/poet.tang.33000.json','["日照四山雪，老僧門未開。", "凍缾黏柱礎，宿火陷爐灰。", "童子病歸去，鹿麑寒入來。", "齋鐘知漸近，枝鳥下生臺。"]'),
('5109cbea-0495-4599-9ec8-236877556a0d','題盧州郡齋','鄭綮','唐','唐诗','tang','','[]','九衢塵裏一書生，多達逢時擁斾旌。',32,'全唐诗/poet.tang.33000.json','["九衢塵裏一書生，多達逢時擁斾旌。", "醉裏眼開金使字，紫旂風動耀天明。"]'),
('bac87ad4-5c7e-46eb-b236-966aa4585662','別郡後寄席中三蘭','鄭綮','唐','唐诗','tang','','[]','淮淝兩水不相通，隔岸臨流望向東。',32,'全唐诗/poet.tang.33000.json','["淮淝兩水不相通，隔岸臨流望向東。", "千顆淚珠無寄處，一時彈與渡前風。"]'),
('07bffb76-c688-4d8f-aec8-c4a088291cb6','觀山燈獻徐尚書 一','溫庭皓','唐','唐诗','tang','','[]','一峰當勝地，萬點照嚴城。',48,'全唐诗/poet.tang.33000.json','["一峰當勝地，萬點照嚴城。", "勢異崑岡發，光疑玄圃生。", "焚書翻見字，舉燧不招兵。", "況遇新春夜，何勞秉燭行。"]'),
('d3c08c65-a9da-4504-b4b0-ea7e1fc4e631','觀山燈獻徐尚書 二','溫庭皓','唐','唐诗','tang','','[]','九枝應並耀，午夜忽潛然。',48,'全唐诗/poet.tang.33000.json','["九枝應並耀，午夜忽潛然。", "景集青山外，螢分碧草前。", "輝華侵月影，歷亂寫星躔。", "望極高樓上，搖光滿綺筵。"]'),
('e8d4e30d-807a-48d0-aa19-3c21bad1d7a5','觀山燈獻徐尚書 三','溫庭皓','唐','唐诗','tang','','[]','春山收暝色，爝火集餘輝。',48,'全唐诗/poet.tang.33000.json','["春山收暝色，爝火集餘輝。", "麗景饒紅焰，祥光出翠微。", "白榆行自比，青桂影相依。", "唯有偷光客，追游欲忘歸。"]'),
('12361079-c3ed-48a8-8f55-1e11dbb6f2e1','梅','溫庭皓','唐','唐诗','tang','','[]','一樹寒林外，何人此地栽。',96,'全唐诗/poet.tang.33000.json','["一樹寒林外，何人此地栽。", "春光先自煖，陽豔暗相催。", "曉覺霜添白，寒迷月借開。", "餘香低惹袖，墮蘂逐流杯。", "零落移新煖，飄颺上故臺。", "雪繁鶯不識，風裊蝶空迴。", "羌吹應愁起，征徒異渴來。", "莫貪題詠興，商鼎待鹽梅。"]'),
('c90ef407-98fc-4c75-b0ac-90db92cd1d6d','言懷','高駢','唐','唐诗','tang','','[]','恨乏平戎策，慙登拜將壇。',48,'全唐诗/poet.tang.33000.json','["恨乏平戎策，慙登拜將壇。", "手持金鉞冷，身挂鐵衣寒。", "主聖扶持易，恩深報效難。", "三邊猶未靜，何敢便休官。"]'),
('0425c5c7-4346-494d-b6b8-06a3c8c20dd1','寄鄠杜李遂良處士','高駢','唐','唐诗','tang','','[]','小隱堪忘世上情，可能休夢入重城。',64,'全唐诗/poet.tang.33000.json','["小隱堪忘世上情，可能休夢入重城。", "池邊寫字師前輩，座右題銘律後生。", "吟社客歸秦渡晚，醉鄉漁去渼陂晴。", "春來不得山中信，盡日無人傍水行。"]'),
('b1e6614d-8dd3-4444-82ff-6da2d8fa9806','和王昭符進士贈洞庭趙先生','高駢','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','爲愛君山景最靈，角冠秋禮一壇星。',64,'全唐诗/poet.tang.33000.json','["爲愛君山景最靈，角冠秋禮一壇星。", "藥將雞犬雲間試，琴許魚龍月下聽。", "自要乘風隨羽客，誰同種玉驗仙經。", "煙霞澹泊無人到，唯有漁翁過洞庭。"]'),
('39def9ab-7dc5-4ba0-a61c-691e77402189','依韻奉酬李迪','高駢','唐','唐诗','tang','','[]','柳下官資顏子居，閑情入骨若爲除。',64,'全唐诗/poet.tang.33000.json','["柳下官資顏子居，閑情入骨若爲除。", "詩成斬將奇難敵，酒熟封侯快未如。", "只見絲綸終日降，不知功業是誰書。", "而今共飲醇滋味，消得揶揄勢利疎。"]'),
('a302a9bc-922d-49d7-a6c4-56846a636444','留別彰德軍從事范校書','高駢','唐','唐诗','tang','','[]','無金寄與白頭親，節概猶誇似古人。',64,'全唐诗/poet.tang.33000.json','["無金寄與白頭親，節概猶誇似古人。", "未出塵埃真落魄，不趨權勢正因循。", "桂攀明月曾觀國，蓬轉西風却問津。", "匹馬東歸羨知己，燕王臺上結交新。"]'),
('11bee415-b8fe-4463-8ea8-323cca6a73a0','途次內黃馬病寄僧舍呈諸友人','高駢','唐','唐诗','tang','','[]','官閑馬病客深秋，肯學張衡詠四愁。',64,'全唐诗/poet.tang.33000.json','["官閑馬病客深秋，肯學張衡詠四愁。", "紅葉寺多詩景致，白衣人盡酒交游。", "依違諷刺因行得，澹泊供需不在求。", "好與高陽結吟社，況無名跡達珠旒。"]'),
('ff1aa6db-1c83-4337-bde5-18230bede22d','遣興','高駢','唐','唐诗','tang','','[]','浮世忙忙蟻子羣，莫嗔頭上雪紛紛。',64,'全唐诗/poet.tang.33000.json','["浮世忙忙蟻子羣，莫嗔頭上雪紛紛。", "沈憂萬種與千種，行樂十分無一分。", "越外險巇防俗事，就中拘檢信人文。", "醉鄉日月終須覓，去作先生號白雲。"]'),
('4b39fa18-666a-40d2-81e0-011d806d9eb0','南海神祠','高駢','唐','唐诗','tang','','[]','滄溟八千里，今古畏波濤。',24,'全唐诗/poet.tang.33000.json','["滄溟八千里，今古畏波濤。", "此日征南將，安然渡萬艘。"]'),
('00f5350f-c2d7-459e-b2fb-9d3694bb5b91','送春','高駢','唐','唐诗','tang','','[]','水淺魚爭躍，花深鳥競啼。',24,'全唐诗/poet.tang.33000.json','["水淺魚爭躍，花深鳥競啼。", "春光看欲盡，判却醉如泥。"]'),
('44c2fe89-b18a-474a-9fe0-1e9b175bddbf','海翻','高駢','唐','唐诗','tang','','[]','幾經人事變，又見海濤翻。',24,'全唐诗/poet.tang.33000.json','["幾經人事變，又見海濤翻。", "徒起如山浪，何曾洗至冤。"]'),
('aafd856c-592c-4b32-976f-e8253590db4f','筇竹杖寄僧','高駢','唐','唐诗','tang','','[]','堅輕筇竹杖，一枝有九節。',24,'全唐诗/poet.tang.33000.json','["堅輕筇竹杖，一枝有九節。", "寄與沃洲人，閑步青山月。"]'),
('f30b73a4-2d1e-47d5-b8da-bcd58918606d','遣興','高駢','唐','唐诗','tang','','[]','把盞非憐酒，持竿不爲魚。',24,'全唐诗/poet.tang.33000.json','["把盞非憐酒，持竿不爲魚。", "唯應嵇叔夜，似我性慵疎。"]'),
('1070066d-2d61-49b6-a324-52bbb1fe452f','歎征人','高駢','唐','唐诗','tang','','[]','心堅膽壯箭頭親，十載沙場受苦辛。',32,'全唐诗/poet.tang.33000.json','["心堅膽壯箭頭親，十載沙場受苦辛。", "力盡路傍行不得，廣張紅斾是何人。"]'),
('5ad05947-e0c3-4bc8-9a95-cceaf1aa1496','湘妃廟','高駢','唐','唐诗','tang','','[]','帝舜南巡去不還，二妃幽怨水雲間。',32,'全唐诗/poet.tang.33000.json','["帝舜南巡去不還，二妃幽怨水雲間。", "當時珠淚垂多少，直到如今竹尚斑。"]'),
('f28b2b78-a4c3-4945-9089-01d7a1397cff','赴安南却寄台司','高駢','唐','唐诗','tang','','[]','曾驅萬馬上天山，風去雲回頃刻間。',32,'全唐诗/poet.tang.33000.json','["曾驅萬馬上天山，風去雲回頃刻間。", "今日海門南面事，莫教還似鳳林關。"]'),
('4b48d9b9-045d-41ce-941f-7c851417cf1b','閨怨','高駢','唐','唐诗','tang','','[]','人世悲歡不可知，夫君初破黑山歸。',32,'全唐诗/poet.tang.33000.json','["人世悲歡不可知，夫君初破黑山歸。", "如今又獻征南策，早晚催縫帶號衣。"]'),
('e9634c6e-0f21-45c0-be2e-d3f46c5c4f79','馬嵬驛','高駢','唐','唐诗','tang','','[]','玉顏雖掩馬嵬塵，冤氣和煙鎖渭津。',32,'全唐诗/poet.tang.33000.json','["玉顏雖掩馬嵬塵，冤氣和煙鎖渭津。", "蟬鬢不隨鑾駕去，至今空感往來人。"]'),
