('c67e5b2e-187a-45ce-8e13-67e6e9b69080','寫懷二首 一','高駢','唐','唐诗','tang','','[]','漁竿消日酒消愁，一醉忘情萬事休。',32,'全唐诗/poet.tang.33000.json','["漁竿消日酒消愁，一醉忘情萬事休。", "却恨韓彭興漢室，功成不向五湖遊。"]'),
('6fc15ec6-54e0-4998-b3c8-fac7c8d976d4','寫懷二首 二','高駢','唐','唐诗','tang','','[]','花滿西園月滿池，笙歌搖曳畫船移。',32,'全唐诗/poet.tang.33000.json','["花滿西園月滿池，笙歌搖曳畫船移。", "如今暗與心相約，不動征旗動酒旗。"]'),
('24d676e4-2c3e-49c7-95bf-a201e40635f8','池上送春','高駢','唐','唐诗','tang','','[]','持竿閑坐思沈吟，釣得江鱗出碧潯。',32,'全唐诗/poet.tang.33000.json','["持竿閑坐思沈吟，釣得江鱗出碧潯。", "回首看花花欲盡，可憐寥落送春心。"]'),
('443d0a47-5fdd-4f07-9d22-ed1036e805a8','南征敘懷','高駢','唐','唐诗','tang','','[]','萬里驅兵過海門，此生今日報君恩。',32,'全唐诗/poet.tang.33000.json','["萬里驅兵過海門，此生今日報君恩。", "回期直待烽煙靜，不遣征衣有淚痕。"]'),
('b09dcc66-784c-4ce3-9e0c-37d70f592e52','風箏','高駢','唐','唐诗','tang','','[]','夜靜弦聲響碧空，宮商信任往來風。',32,'全唐诗/poet.tang.33000.json','["夜靜弦聲響碧空，宮商信任往來風。", "依稀似曲才堪聽，又被移將別調中。"]'),
('4e9daa29-9ca8-44c6-85e8-bb5f79503f48','平流園席上','高駢','唐','唐诗','tang','','[]','畫舸搖煙水滿塘，柳絲輕軟小桃香。',32,'全唐诗/poet.tang.33000.json','["畫舸搖煙水滿塘，柳絲輕軟小桃香。", "却緣龍節爲縈絆，好是狂時不得狂。"]'),
('54bfdbcd-641f-44a9-b587-36b78fb1527b','聞河中王鐸加都統','高駢','唐','唐诗','tang','','[]','煉汞燒鉛四十年，至今猶在藥爐前。',32,'全唐诗/poet.tang.33000.json','["煉汞燒鉛四十年，至今猶在藥爐前。", "不知子晉緣何事，只學吹簫便得仙。"]'),
('9cdfe035-5017-406e-ba3f-00885c146743','句','高駢','唐','唐诗','tang','','[]','人間無限傷心事，不得尊前折一枝。',64,'全唐诗/poet.tang.33000.json','["人間無限傷心事，不得尊前折一枝。", "滿宮多少承恩者，似有容華妾也無。", "滿身珠翠將何用，唯與豪家拂象牀。", "何人種得西施花，千古春風開不盡。"]'),
('7d20122c-fa19-4466-83a8-1435a3d3d16b','青樓曲','于濆','唐','唐诗','tang','','[]','青樓臨大道，一上一回老。',24,'全唐诗/poet.tang.33000.json','["青樓臨大道，一上一回老。", "所思終不來，極目傷春草。"]'),
('5e558955-09fb-4207-8e64-06ad06f69557','塞下曲','于濆','唐','唐诗','tang','','[]','紫塞曉屯兵，黃沙披甲臥。',48,'全唐诗/poet.tang.33000.json','["紫塞曉屯兵，黃沙披甲臥。", "戰鼓聲未齊，烏鳶已相賀。", "燕然山上雲，半是離鄉魂。", "衛霍待富貴，豈能無乾坤。"]'),
('264df1a0-65ce-4b2a-99e2-0d46673957d1','山村曉思','于濆','唐','唐诗','tang','','[]','開門省禾黍，鄰翁水頭住。',48,'全唐诗/poet.tang.33000.json','["開門省禾黍，鄰翁水頭住。", "今朝南澗波，昨夜西川雨。", "牧童披短蓑，腰笛期煙渚。", "不問水邊人，騎牛傍山去。"]'),
('2802b5a3-9262-4bd3-a787-7aef6a082930','馬嵬驛','于濆','唐','唐诗','tang','','[]','常經馬嵬驛，見說坡前客。',48,'全唐诗/poet.tang.33000.json','["常經馬嵬驛，見說坡前客。", "一從屠貴妃，生女愁傾國。", "是日芙蓉花，不如秋草色。", "當時嫁匹夫，不妨得頭白。"]'),
('4a6ece46-435b-4dcd-8d64-ff59b3de06be','苦辛吟','于濆','唐','唐诗','tang','','[]','壠上扶犂兒，手種腹長飢。',48,'全唐诗/poet.tang.33000.json','["壠上扶犂兒，手種腹長飢。", "窗下拋梭女，手織身無衣。", "我願燕趙姝，化爲嫫母姿。", "一笑不值錢，自然家國肥。"]'),
('c21e1277-9995-4dd6-8c6b-c923aa666ce6','野蠶','于濆','唐','唐诗','tang','','[]','野蠶食青桑，吐絲亦成繭。',36,'全唐诗/poet.tang.33000.json','["野蠶食青桑，吐絲亦成繭。", "無功及生人，何異偷飽暖。", "我願均爾絲，化爲寒者衣。"]'),
('ce56c3eb-f35e-421d-b586-145b7600f63f','秦原覽古','于濆','唐','唐诗','tang','','[]','耕者戮力地，龍虎曾角逐。',72,'全唐诗/poet.tang.33000.json','["耕者戮力地，龍虎曾角逐。", "火德道將亨，夜逢虵母哭。", "昔日望夷宮，是處尋桑穀。", "漢祖竟爲龍，趙高徒指鹿。", "當時行路人，已合傷心目。", "漢祚又千年，秦原草還綠。"]'),
('f0036842-0804-429f-bc72-daeaaa6709eb','古宴曲','于濆','唐','唐诗','tang','','[]','雉扇合蓬萊，朝車回紫陌。',72,'全唐诗/poet.tang.33000.json','["雉扇合蓬萊，朝車回紫陌。", "重門集嘶馬，言宴金張宅。", "燕娥奉巵酒，低鬟若無力。", "十戶手胼胝，鳳凰釵一隻。", "高樓齊下視，日照羅衣色。", "笑指負薪人，不信生中國。"]'),
('68f4eb8f-4364-48e9-8ff5-2f99a9803e3d','南越謠','于濆','唐','唐诗','tang','','[]','迢迢東南天，巨浸無津壖。',72,'全唐诗/poet.tang.33000.json','["迢迢東南天，巨浸無津壖。", "雄風卷昏霧，干戈滿樓船。", "此時尉佗心，兒童待幽燕。", "三寸陸賈舌，萬里漢山川。", "若令交趾貨，盡生虞芮田。", "天意苟如此，遐人誰肯憐。"]'),
('94269318-57e2-4c9f-841b-7e63dcb70c56','述己歎','于濆','唐','唐诗','tang','','[]','不長不成人，及長老逼身。',36,'全唐诗/poet.tang.33000.json','["不長不成人，及長老逼身。", "履善本求樂，及善尤苦辛。", "如何幽幷兒，一箭取功勳。"]'),
('dc89556d-e5f8-4b43-8243-f01c5e2bb69f','遼陽行','于濆','唐','唐诗','tang','','[]','遼陽在何處，妾欲隨君去。',36,'全唐诗/poet.tang.33000.json','["遼陽在何處，妾欲隨君去。", "義合齊死生，本不誇機杼。", "誰能守空閨，虛問遼陽路。"]'),
('eb10c918-bd71-43a4-8adb-6f715af803d7','旅館秋思','于濆','唐','唐诗','tang','','[]','旅館坐孤寂，出門成苦吟。',48,'全唐诗/poet.tang.33000.json','["旅館坐孤寂，出門成苦吟。", "何事覺歸晚，黃花秋意深。", "寒蝶戀衰草，軫我離鄉心。", "更見庭前樹，南枝巢宿禽。"]'),
('1358844c-25c3-4a94-9607-ae3c547a0e99','長城','于濆','唐','唐诗','tang','','[]','秦皇豈無德，蒙氏非不武。',72,'全唐诗/poet.tang.33000.json','["秦皇豈無德，蒙氏非不武。", "豈將版築功，萬里遮胡虜。", "團沙世所難，作壘明知苦。", "死者倍堪傷，僵屍猶抱杵。", "十年居上郡，四海誰爲主。", "縱使骨爲塵，冤名不入土。"]'),
('cff71821-a614-4df8-bb78-2be7e127770b','田翁歎','于濆','唐','唐诗','tang','','[]','手植千樹桑，文杏作中梁。',72,'全唐诗/poet.tang.33000.json','["手植千樹桑，文杏作中梁。", "頻年徭役重，盡屬富家郎。", "富家田業廣，用此買金章。", "昨日門前過，軒車滿垂楊。", "歸來說向家，兒孫竟咨嗟。", "不見千樹桑，一浦芙蓉花。"]'),
('b33fb162-b0f7-48bb-9763-cf8d78c14052','沙場夜','于濆','唐','唐诗','tang','','[]','城上更聲發，城下杵聲歇。',72,'全唐诗/poet.tang.33000.json','["城上更聲發，城下杵聲歇。", "征人燒斷蓬，對泣沙中月。", "耕牛朝輓甲，戰馬夜銜鐵。", "士卒浣戎衣，交河水爲血。", "輕裘兩都客，洞房愁宿別。", "何況遠辭家，生死猶未決。"]'),
('2fc493ab-8564-48e6-9edf-e058fc9e01e1','里中女','于濆','唐','唐诗','tang','','[]','吾聞池中魚，不識海水深。',84,'全唐诗/poet.tang.33000.json','["吾聞池中魚，不識海水深。", "吾聞桑下女，不識華堂陰。", "貧窗苦機杼，富家鳴杵砧。", "天與雙明眸，只教識蒿簪。", "徒惜越娃貌，亦蘊韓娥音。", "珠玉不到眼，遂無奢侈心。", "豈知趙飛燕，滿髻釵黃金。"]'),
('3ad228a0-cdf4-4e0c-affd-ca65e5f95e0f','寒食','于濆','唐','唐诗','tang','','[]','二月野中芳，凡花亦能香。',48,'全唐诗/poet.tang.33000.json','["二月野中芳，凡花亦能香。", "素娥哭新塚，樵柯鳴柔桑。", "田父引黃犬，尋狐上高岡。", "墳前呼犬歸，不知頭似霜。"]'),
('d7f492ab-32e7-4b66-8f7a-9558b15901cd','邊遊錄戍卒言','于濆','唐','唐诗','tang','','[]','二十屬盧龍，三十防沙漠。',60,'全唐诗/poet.tang.33000.json','["二十屬盧龍，三十防沙漠。", "平生愛功業，不覺從軍惡。", "今來客鬢改，知學彎弓錯。", "赤肉痛金瘡，他人成衛霍。", "目斷望君門，君門苦寥廓。"]'),
('4a95afce-e957-4bfb-b835-d3c50e317096','古征戰','于濆','唐','唐诗','tang','','[]','高峰凌青冥，深穴萬丈坑。',60,'全唐诗/poet.tang.33000.json','["高峰凌青冥，深穴萬丈坑。", "皇天自山谷，焉得人心平。", "齊魯足兵甲，燕趙多娉婷。", "仍聞麗水中，日日黃金生。", "苟非夷齊心，豈得無戰爭。"]'),
('d3ffc2d1-9cb9-4521-a86d-885c5a99fe0f','山村叟','于濆','唐','唐诗','tang','','[]','古鑿巖居人，一廛稱有產。',48,'全唐诗/poet.tang.33000.json','["古鑿巖居人，一廛稱有產。", "雖霑巾覆形，不及貴門犬。", "驅牛耕白石，課女經黃繭。", "歲暮霜霰濃，畫樓人飽煖。"]'),
('b3146349-87b7-463f-994b-ab5fea5ca2f3','戍客南歸','于濆','唐','唐诗','tang','','[]','北別黃榆塞，南歸白雲鄉。',48,'全唐诗/poet.tang.33000.json','["北別黃榆塞，南歸白雲鄉。", "孤舟下彭蠡，楚月沈滄浪。", "爲子惜功業，滿身刀箭瘡。", "莫渡汨羅水，回君忠孝腸。"]'),
('17fde4fc-7743-4c81-a6d7-31a1716ebe2b','經館娃宮','于濆','唐','唐诗','tang','','[]','館娃宮畔顧，國變生嬌妒。',48,'全唐诗/poet.tang.33000.json','["館娃宮畔顧，國變生嬌妒。", "句踐膽未嘗，夫差心已誤。", "吳亡甘已矣，越勝今何處？", "當時二國君，一種江邊墓。"]'),
('810c5448-44f8-4bba-a88e-d529a5bff9bb','村居晏起','于濆','唐','唐诗','tang','','[]','村舍少聞事，日高猶閉關。',48,'全唐诗/poet.tang.33000.json','["村舍少聞事，日高猶閉關。", "起來花滿地，戴勝鳴桑間。", "居安即永業，何者爲故山。", "朱門與蓬戶，六十頭盡斑。"]'),
('f7003512-b583-40f4-ab9b-87a9bd301747','感懷','于濆','唐','唐诗','tang','','[]','採薇易爲山，何必登首陽。',48,'全唐诗/poet.tang.33000.json','["採薇易爲山，何必登首陽。", "濯纓易爲水，何必泛滄浪。", "貴崇已難慕，諂笑何所長。", "東堂桂欲空，猶有收螢光。"]'),
('43b187c7-f7e5-45be-a019-bf2a24abff7d','金谷感懷','于濆','唐','唐诗','tang','','[]','黃金驕石崇，與晉爭國力。',48,'全唐诗/poet.tang.33000.json','["黃金驕石崇，與晉爭國力。", "更欲住人間，一日買不得。", "行爲忠信主，身是文章宅。", "四者俱不聞，空傳墮樓客。"]'),
('1bc1ba9b-cac7-47cd-9d46-8902d9ccec4a','恨從軍','于濆','唐','唐诗','tang','','[]','不嫁白衫兒，愛君新紫衣。',48,'全唐诗/poet.tang.33000.json','["不嫁白衫兒，愛君新紫衣。", "早知遽相別，何用假光輝。", "已聞都萬騎，又道出重圍。", "一軸金裝字，致君終不歸。"]'),
('9b693a60-bbd9-472f-9100-2b6751f69be5','燒金曲','于濆','唐','唐诗','tang','','[]','天壽畏不永，燒金希長年。',48,'全唐诗/poet.tang.33000.json','["天壽畏不永，燒金希長年。", "積土培枯根，自謂松柏堅。", "南陌試腰褭，西樓歌嬋娟。", "豈知蔓草中，日日開夜泉。"]'),
('cdb5bcbb-529b-4ac7-affc-276e35d993eb','子從軍','于濆','唐','唐诗','tang','','[]','男作鄉中丁，女作鄉男婦。',48,'全唐诗/poet.tang.33000.json','["男作鄉中丁，女作鄉男婦。", "南村與北里，日日見父母。", "豈似從軍兒，一去便白首。", "何當鑄劍戟，盡得丁男力。"]'),
('de6e3b0b-7c60-4197-9866-cee1a5c67915','越溪女','于濆','唐','唐诗','tang','','[]','會稽山上雲，化作越溪人。',72,'全唐诗/poet.tang.33000.json','["會稽山上雲，化作越溪人。", "枉破吳王國，徒爲西子身。", "江邊浣紗伴，黃金扼雙腕。", "倏忽不相期，思傾趙飛燕。", "妾家基業薄，空有如花面。", "嫁盡綠窗人，獨自盤金線。"]'),
('4a833a62-ca8d-456f-9463-05d32867a616','巫山高','于濆','唐','唐诗','tang','','[]','何山無朝雲，彼雲亦悠揚。',60,'全唐诗/poet.tang.33000.json','["何山無朝雲，彼雲亦悠揚。", "何山無暮雨，彼雨亦蒼茫。", "宋玉恃才者，憑虛構高唐。", "自垂文賦名，荒淫歸楚襄。", "峨峨十二峰，永作妖鬼鄉。"]'),
('4ad0d83a-93c2-4717-b38b-737df0e7877c','織素謠','于濆','唐','唐诗','tang','','[]','貧女苦筋力，繰絲夜夜織。',60,'全唐诗/poet.tang.33000.json','["貧女苦筋力，繰絲夜夜織。", "萬梭爲一素，世重韓娥色。", "五侯初買笑，建章方落籍。", "一曲古涼州，六親長血食。", "勸爾畫長眉，學歌飽親戚。"]'),
('974282dd-e9b9-4dfa-87d7-577fd834958b','擬古諷','于濆','唐','唐诗','tang','','[]','洛陽大道傍，甲第何深邃。',72,'全唐诗/poet.tang.33000.json','["洛陽大道傍，甲第何深邃。", "南畝無一廛，東園有餘地。", "春溪化桃李，秋沼生荷芰。", "草木本無情，此時如有爲。", "旱苗當壟死，流水資嘉致。", "餘心甘至愚，不會皇天意。"]'),
('530aec41-f1d5-4fda-9bab-a72bf1888fb9','贈太行開路者','于濆','唐','唐诗','tang','','[]','手斸太行山，心齊太行巔。',36,'全唐诗/poet.tang.33000.json','["手斸太行山，心齊太行巔。", "斸盡太行險，君心更摩天。", "何如回苦辛，自鑿東臯田。"]'),
('b6eea2ba-d150-48c1-a2af-cd15464b0167','戍卒傷春','于濆','唐','唐诗','tang','','[]','連年戍邊塞，過却芳菲節。',72,'全唐诗/poet.tang.33000.json','["連年戍邊塞，過却芳菲節。", "東風氣力盡，不減陰山雪。", "蕭條柳一株，南枝葉微發。", "爲帶故鄉情，依依籍攀折。", "晚風吹磧沙，夜淚啼鄉月。", "凌煙閣上人，未必皆忠烈。"]'),
('0ceb4435-be30-4af0-95ec-b02c497a41b7','','于濆','唐','唐诗','tang','','[]','長聞鄉人語，此家勝良賈。',96,'全唐诗/poet.tang.33000.json','["長聞鄉人語，此家勝良賈。", "骨肉化飢魂，倉中有飽鼠。", "青春滿桑柘，旦夕鳴機杼。", "秋風一夜來，累累聞砧杵。", "西鄰有原憲，蓬蒿遶環堵。", "自樂固窮心，天意在何處？", "當門見堆子，已作桑田主。", "安得四海中，盡爲虞芮土。"]'),
('8e9e3c2a-b93f-48de-9046-5581407a9572','早發','于濆','唐','唐诗','tang','','[]','綠野含曙光，東北雲如茜。',48,'全唐诗/poet.tang.33000.json','["綠野含曙光，東北雲如茜。", "栖鴉林際起，落月水中見。", "此身何自苦，日日凌霜霰。", "流蘇帳裏人，猶在陽臺畔。"]'),
('4176ba2a-a170-47e3-b212-12980171fbc9','季夏逢朝客','于濆','唐','唐诗','tang','','[]','滻水桃李熟，杜曲芙蓉老。',48,'全唐诗/poet.tang.33000.json','["滻水桃李熟，杜曲芙蓉老。", "九天休沐歸，腰玉垂楊道。", "避路迴綺羅，迎風嘶騕褭。", "豈知山谷中，日日吹瑤草。"]'),
('eb379fbb-1d17-48d7-87b4-739b43faa1f4','隴頭水','于濆','唐','唐诗','tang','','[]','行人何徬徨，隴頭水嗚咽。',48,'全唐诗/poet.tang.33000.json','["行人何徬徨，隴頭水嗚咽。", "寒沙戰鬼愁，白骨風霜切。", "薄日朦朧秋，怨氣陰雲結。", "殺成邊將名，名著生靈滅。"]'),
('48806f66-7d46-4345-902a-33d66a2d5b6c','古別離 一','于濆','唐','唐诗','tang','','[]','入室少情意，出門多路岐。',72,'全唐诗/poet.tang.33000.json','["入室少情意，出門多路岐。", "黃鶴有歸日，蕩子無還時。", "人誰無分命，妾身何太奇。", "君爲東南風，妾作西北枝。", "青樓鄰里婦，終年畫長眉。", "自倚對良匹，笑妾空羅幃。"]'),
('535ec7d2-ea81-4944-9f6d-a2614bfb8f05','古別離 二','于濆','唐','唐诗','tang','','[]','郎本東家兒，妾本西家女。',48,'全唐诗/poet.tang.33000.json','["郎本東家兒，妾本西家女。", "對門中道間，終謂無離阻。", "豈知中道間，遣作空閨主。", "自是愛封侯，非關備胡虜。"]'),
('a5e062ef-7e73-4dfb-b00d-21f9662b0a88','擬古意','于濆','唐','唐诗','tang','','[]','白玉若無玷，花顏須及時。',48,'全唐诗/poet.tang.33000.json','["白玉若無玷，花顏須及時。", "國色久在室，良媒亦生疑。", "鴉鬟未成髻，鸞鏡徒相知。", "翻慙效顰者，却笑從人遲。"]'),
('fae3a4a1-0edf-4f3b-b76e-a77132d06fb4','隴頭吟','于濆','唐','唐诗','tang','','[]','借問隴頭水，終年恨何事。',48,'全唐诗/poet.tang.33000.json','["借問隴頭水，終年恨何事。", "深疑嗚咽聲，中有征人淚。", "自古蘊長策，況我非才智。", "無計謝潺湲，一宵空不寐。"]'),
('de826691-3742-4231-a773-e1f4c8b49eee','思歸引','于濆','唐','唐诗','tang','','[]','不耕南畝田，爲愛東堂桂。',48,'全唐诗/poet.tang.33000.json','["不耕南畝田，爲愛東堂桂。", "身同樹上花，一落又經歲。", "交親日相薄，知己恩潛替。", "日開十二門，自是無歸計。"]'),
('67b4c915-7411-47eb-9854-be1e5e4e23e9','秦富人','于濆','唐','唐诗','tang','','[]','高高起華堂，遠遠引流水。',36,'全唐诗/poet.tang.33000.json','["高高起華堂，遠遠引流水。", "糞土視金珍，猶嫌未奢侈。", "陋巷滿蓬蒿，誰憐有顏子。"]'),
('98c78c2e-81ba-45dc-9d4c-6134393d5896','對花','于濆','唐','唐诗','tang','','[]','花開蝶滿枝，花落蝶還稀。',24,'全唐诗/poet.tang.33000.json','["花開蝶滿枝，花落蝶還稀。", "惟有舊巢燕，主人貧亦歸。"]'),
('a0d2dfaf-a7b1-4326-a49e-825250bcae08','宮怨','于濆','唐','唐诗','tang','','[]','妾家望江口，少年家財厚。',120,'全唐诗/poet.tang.33000.json','["妾家望江口，少年家財厚。", "臨江起珠樓，不賣文君酒。", "當年樂貞獨，巢燕時爲友。", "父兄未許人，畏妾事姑舅。", "西牆鄰宋玉，窺見妾眉宇。", "一旦及天聰，恩光生戶牖。", "謂言入漢宮，富貴可長久。", "君王縱有情，不奈陳皇后。", "誰憐頰似桃，孰知腰勝柳。", "今日在長門，從來不如醜。"]'),
('2b3869ad-76b6-4b2e-b8fb-a3caf55296c2','登越王樓即事','牛徵','唐','唐诗','tang','','[]','危樓送遠目，信美奈鄉情。',48,'全唐诗/poet.tang.33000.json','["危樓送遠目，信美奈鄉情。", "轉岸孤舟疾，銜山落照明。", "蕭條看草色，惆悵認江聲。", "誰會登臨恨，從軍白髮生。"]'),
('5be6484b-02ec-4f07-a451-7651b94479b8','及第後寄梁燭處士','伊璠','唐','唐诗','tang','','[]','繡轂尋芳許史家，獨將羈事達江沙。',64,'全唐诗/poet.tang.33000.json','["繡轂尋芳許史家，獨將羈事達江沙。", "十年辛苦一枝桂，二月豔陽千樹花。", "鵬化四溟歸碧落，鶴棲三島接青霞。", "同袍不得同遊翫，今對春風日又斜。"]'),
('11850107-8081-40f9-a114-73283fa83662','春詩','蕭遘','唐','唐诗','tang','','[]','南國韶光早，春風送臘來。',36,'全唐诗/poet.tang.33000.json','["南國韶光早，春風送臘來。", "水堤煙報柳，山寺雪驚梅。", "練色鋪江晚，潮聲逐渚迴。"]'),
('a0c418e3-bc6c-428f-a4b1-937f9ca8749b','和王侍中謁張惡子廟','蕭遘','唐','唐诗','tang','','[]','青骨祀吳誰讓德，紫華居越亦知名。',64,'全唐诗/poet.tang.33000.json','["青骨祀吳誰讓德，紫華居越亦知名。", "未聞一劒傳唐主，長擁千山護蜀城。", "斬馬威稜應掃蕩，截蛟鋒刃俟昇平。", "酇侯爲國親簫鼓，堂上神籌更布兵。"]'),
('32fe3d88-fe52-4d0e-8431-2ff060e5c20b','成都','蕭遘','唐','唐诗','tang','','[]','月曉已開花市合，江平偏見竹簰多。',32,'全唐诗/poet.tang.33000.json','["月曉已開花市合，江平偏見竹簰多。", "好教載取芳菲樹，剩照岷天瑟瑟波。"]'),
('80d731bc-f232-43d7-9f3e-744e8ccbff38','句','蕭遘','唐','唐诗','tang','','[]','吾家九葉相，盡繼明時出。',12,'全唐诗/poet.tang.33000.json','["吾家九葉相，盡繼明時出。"]'),
('0269e415-c1de-43dc-a9a4-02c0fa36b6df','策試夜潛紀長句於都堂西南隅 一','韋承貽','唐','唐诗','tang','','[]','褒衣博帶滿塵埃，獨自都堂納卷回。',64,'全唐诗/poet.tang.33000.json','["褒衣博帶滿塵埃，獨自都堂納卷回。", "蓬巷幾時聞吉語，棘籬何日免重來。", "三條燭盡鐘初動，九轉丹成鼎未開。", "殘月漸低人擾擾，不知誰是謫仙才。"]'),
('155f34b1-c4c0-42b4-b454-cc8e165f361c','策試夜潛紀長句於都堂西南隅 二','韋承貽','唐','唐诗','tang','','[]','白蓮千朵照廊明，一片昇平雅頌聲。',32,'全唐诗/poet.tang.33000.json','["白蓮千朵照廊明，一片昇平雅頌聲。", "才唱第三條燭盡，南宮風月畫難成。"]'),
('bfa92e43-576e-490e-a28d-92e2cf350447','詔放雲南子弟還國','鄭洪業','唐','唐诗','tang','','[]','德被陪臣子，仁垂聖主恩。',72,'全唐诗/poet.tang.33000.json','["德被陪臣子，仁垂聖主恩。", "雕題辭鳳闕，丹服出金門。", "有澤沾殊俗，無征及獷𤟤。", "銅梁分漢土，玉壘駕鸞軒。", "瘴嶺蠶叢盛，巴江越嶲垠。", "萬方同感化，豈獨自南蕃。"]'),
('89980d8a-114b-430e-a46d-6c49a846bfff','中秋夜思鄭延美有作','孫緯','唐','唐诗','tang','','[]','中秋中夜月，世說慴妖精。',48,'全唐诗/poet.tang.33000.json','["中秋中夜月，世說慴妖精。", "顧兔雲初蔽，長虵誰與勍。", "未追良友翫，安用玉輪盈。", "此意人誰喻，裁時穿禁城。"]'),
('7152d142-0875-4275-82dd-ae794b842b01','清曉捲簾','歐陽玭','唐','唐诗','tang','','[]','清曉意未愜，捲簾時一吟。',48,'全唐诗/poet.tang.33000.json','["清曉意未愜，捲簾時一吟。", "檻虛花氣密，地暖竹聲深。", "秀色還朝暮，浮雲自古今。", "石泉驚已躍，會可洗幽心。"]'),
('d7f43b4c-9110-4da1-9b5f-8301a17ac78f','巴陵','歐陽玭','唐','唐诗','tang','','[]','孤城向夕原，春入景初暄。',48,'全唐诗/poet.tang.33000.json','["孤城向夕原，春入景初暄。", "綠樹低官舍，青山在縣門。", "樓臺疑結蜃，枕席更聞猨。", "客路何曾定，棲遲欲斷魂。"]'),
('f0e4795b-9d6d-4bbf-8555-ea7b6372adee','榆溪道上','歐陽玭','唐','唐诗','tang','','[]','初日在斜溪，山雲片片低。',48,'全唐诗/poet.tang.33000.json','["初日在斜溪，山雲片片低。", "鄉愁夢裏失，馬色望中迷。", "澗底淒泉氣，巖前遍綠荑。", "非關秦塞去，無事候晨雞。"]'),
('10d7b11d-ff01-4218-9d09-d7d04ddfc763','新嶺臨眺寄連總進士','歐陽玭','唐','唐诗','tang','','[]','關勢遙臨海，峰巒半入雲。',48,'全唐诗/poet.tang.33000.json','["關勢遙臨海，峰巒半入雲。", "煙中獨鳥下，潭上雜花熏。", "寄遠悲春草，登臨憶使君。", "此時還極目，離思更紛紛。"]'),
('399024aa-e7c2-474f-b87f-b4f2389c586f','幽軒','歐陽玭','唐','唐诗','tang','','[]','幽軒斜映山，空澗復潺潺。',72,'全唐诗/poet.tang.33000.json','["幽軒斜映山，空澗復潺潺。", "重疊巖巒趣，遙來窗戶間。", "桃花飄岫幌，燕子語松關。", "衣桁侵池翠，階痕露蘚斑。", "臨風清瑟奏，對客白雲閑。", "眷戀青春色，含毫俯碧灣。"]'),
('e9e4da94-1edb-406a-be15-b2f252e3a727','社日村居','張演','唐','唐诗','tang','','[]','鵝湖山下稻粱肥，豚穽雞棲對掩扉。',32,'全唐诗/poet.tang.33000.json','["鵝湖山下稻粱肥，豚穽雞棲對掩扉。", "桑拓影斜春社散，家家扶得醉人歸。"]'),
('023db556-73b5-4232-9168-66b400036a46','弔孟昌圖','裴澈','唐','唐诗','tang','','[]','一章何罪死何名，投水惟君與屈平。',32,'全唐诗/poet.tang.33000.json','["一章何罪死何名，投水惟君與屈平。", "從此蜀江煙月夜，杜鵑應作兩般聲。"]'),
('5b43f852-674c-4ff7-9d2f-6c1e5f07994b','婕妤怨','翁綬','唐','唐诗','tang','','[]','讒謗潛來起百憂，朝承恩寵暮仇讎。',64,'全唐诗/poet.tang.33000.json','["讒謗潛來起百憂，朝承恩寵暮仇讎。", "火燒白玉非因玷，霜剪紅蘭不待秋。", "花落昭陽誰共輦，月明長信獨登樓。", "繁華事逐東流水，團扇悲歌萬古愁。"]'),
('7c351fc0-63c0-4593-9caa-ff249e4f8e18','隴頭吟','翁綬','唐','唐诗','tang','','[]','隴水潺湲隴樹黃，征人隴上盡思鄉。',66,'全唐诗/poet.tang.33000.json','["隴水潺湲隴樹黃，征人隴上盡思鄉。", "馬嘶斜[日]朔風急，雁過寒雲邊思長。", "殘月出林明劒戟，平沙隔水見牛羊。", "橫行俱是封侯者，誰斬樓蘭獻未央。"]'),
('ce25f448-a77c-45c6-8994-85ac4ad27bf6','關山月','翁綬','唐','唐诗','tang','','[]','裴回漢月滿邊州，照盡天涯到隴頭。',64,'全唐诗/poet.tang.33000.json','["裴回漢月滿邊州，照盡天涯到隴頭。", "影轉銀河寰海靜，光分玉塞古今愁。", "笳吹遠戍孤烽滅，鴈下平沙萬里秋。", "況是故園搖落夜，那堪少婦獨登樓。"]'),
('61793401-0569-4aaa-a91d-baab41ba0a0f','雨雪曲','翁綬','唐','唐诗','tang','','[]','邊聲四合殷河流，雨雪飛來遍隴頭。',64,'全唐诗/poet.tang.33000.json','["邊聲四合殷河流，雨雪飛來遍隴頭。", "鐵嶺探人迷鳥道，陰山飛將濕貂裘。", "斜飄旌斾過戎帳，半雜風沙入戍樓。", "一自塞垣無李蔡，何人爲解北門憂。"]'),
('8a70bb17-5d6e-41d4-a93c-9be37a738ff5','行路難','翁綬','唐','唐诗','tang','','[]','行路艱難不復歌，故人榮達我蹉跎。',64,'全唐诗/poet.tang.33000.json','["行路艱難不復歌，故人榮達我蹉跎。", "雙輪晚上銅臺雪，一葉春浮瘴海波。", "自古要津皆若此，方今失路欲如何。", "君看西漢翟丞相，鳳沼朝辭暮雀羅。"]'),
('4273ba94-ac01-4282-8572-4e0b5aa50acc','折楊柳','翁綬','唐','唐诗','tang','','[]','紫陌金隄映綺羅，游人處處動離歌。',64,'全唐诗/poet.tang.33000.json','["紫陌金隄映綺羅，游人處處動離歌。", "陰移古戍迷芳草，花帶殘陽落遠波。", "臺上少年吹白雪，樓中思婦歛青蛾。", "殷勤攀折贈行客，此去關山雨雪多。"]'),
('5decafa9-ebc2-4c72-a2b7-d936419925cf','詠酒','翁綬','唐','唐诗','tang','','[]','逃暑迎春復送秋，無非綠蟻滿杯浮。',64,'全唐诗/poet.tang.33000.json','["逃暑迎春復送秋，無非綠蟻滿杯浮。", "百年莫惜千回醉，一醆能消萬古愁。", "幾爲芳菲眠細草，曾因雨雪上高樓。", "平生名利關身者，不識狂歌到白頭。"]'),
('82971b1e-b135-4c83-a2d5-81279a019fe6','白馬','翁綬','唐','唐诗','tang','','[]','渥洼龍種雪霜同，毛骨天生膽氣雄。',64,'全唐诗/poet.tang.33000.json','["渥洼龍種雪霜同，毛骨天生膽氣雄。", "金埒乍調光照地，玉關初別遠嘶風。", "花明錦襜垂楊下，露濕朱纓細草中。", "一夜羽書催轉戰，紫髯騎出佩騂弓。"]'),
('053f5663-c2ae-49a3-a34a-312e2c30d43a','句','翁綬','唐','唐诗','tang','','[]','海國歐鄉浙水東，暫煩良守此憑熊。',16,'全唐诗/poet.tang.33000.json','["海國歐鄉浙水東，暫煩良守此憑熊。"]'),
('e2d44be1-edba-4e02-be87-ee3431e4723d','中秋月','潘緯','唐','唐诗','tang','','[]','古今逢此夜，共冀泬㵳明。',48,'全唐诗/poet.tang.33000.json','["古今逢此夜，共冀泬㵳明。", "豈是月華別，祗應秋氣清。", "影當中土正，輪對八荒平。", "尋客徒留望，璿璣自有程。"]'),
('c4848f7e-fccb-4baf-9246-c5fd420729bb','琴','潘緯','唐','唐诗','tang','','[]','客來鳴素琴，惆悵對遺音。',48,'全唐诗/poet.tang.33000.json','["客來鳴素琴，惆悵對遺音。", "一曲起於古，幾人聽到今。", "盡含風靄遠，自泛月煙深。", "風續水山操，坐生方外心。"]'),
('db665eaa-90ac-46a4-bff7-b8f8221de384','句','潘緯','唐','唐诗','tang','','[]','篆經千古澀，影瀉一堂寒。',12,'全唐诗/poet.tang.33000.json','["篆經千古澀，影瀉一堂寒。"]'),
('19f81e4f-53f0-4f5a-a978-3092d4932ec8','九日衛使君筵上作','武瓘','唐','唐诗','tang','','[]','佳晨登賞喜還鄉，謝宇開筵晚興長。',64,'全唐诗/poet.tang.33000.json','["佳晨登賞喜還鄉，謝宇開筵晚興長。", "滿眼黃花初泛酒，隔煙紅樹欲迎霜。", "千家門戶笙歌發，十里江山白鳥翔。", "共賀安人豐樂歲，幸陪珠履侍銀章。"]'),
('944c059c-6ca6-4727-aab7-28b715aa7c87','勸酒','武瓘','唐','唐诗','tang','','[]','勸君金屈巵，滿酌不須辭。',24,'全唐诗/poet.tang.33000.json','["勸君金屈巵，滿酌不須辭。", "花發多風雨，人生足別離。"]'),
('5d480ad0-a499-41bf-97bb-74550eadd533','感事','武瓘','唐','唐诗','tang','','[]','花開蝶滿枝，花謝蝶還稀。',24,'全唐诗/poet.tang.33000.json','["花開蝶滿枝，花謝蝶還稀。", "惟有舊巢燕，主人貧亦歸。"]'),
('544665e9-d618-4dcb-95e2-7286a387f711','重歸宜春偶成十六韻寄朝中知己','袁皓','唐','唐诗','tang','','[]','水香甘似醴，知是入袁溪。',192,'全唐诗/poet.tang.33000.json','["水香甘似醴，知是入袁溪。", "黃竹成叢密，青蘿夾岸低。", "煖流鸂鶒戲，深樹鷓鴣啼。", "黃犬驚迎客，青牛困臥泥。", "有村皆績紡，無地不耕犂。", "鄉曲多耆舊，逢迎盡杖藜。", "殷勤傾白酒，相勸有黃雞。", "歸老官知忝，還鄉路不迷。", "直言干忌諱，權路恥依棲。", "拙學趨時態，閑思與牧齊。", "稻糧饒燕雀，江海溢鳧鷖。", "昔共逢離亂，今來息鼓鼙。", "恩仁霑品物，教化及雕題。", "上貢貞元祿，曾叨寵記批。", "何須歸紫禁，便是到丹梯。", "珍重長安道，從今息馬嘶。"]'),
('8a0c1549-e870-458c-9f59-f756c5f3a563','及第後作','袁皓','唐','唐诗','tang','','[]','金榜高懸姓字真，分明折得一枝春。',64,'全唐诗/poet.tang.33000.json','["金榜高懸姓字真，分明折得一枝春。", "蓬瀛乍接神仙侶，江海迴思耕釣人。", "九萬摶扶排羽翼，十年辛苦涉風塵。", "昇平時節逢公道，不覺龍門是嶮津。"]'),
('ea2fdc14-6a44-40bd-a25a-8eadc179bb82','重歸宜春經過萍川題梵林寺','袁皓','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','梵林遺址在松蘿，四十年來兩度過。',64,'全唐诗/poet.tang.33000.json','["梵林遺址在松蘿，四十年來兩度過。", "濾水東奔彭蠡浪，萍川西注洞庭波。", "村煙不改居人換，官路無窮行客多。", "拖紫腰金成底事，凭闌惆悵欲如何。"]'),
('5f749761-d4a2-4f4f-af7f-96c939b771ec','寄岳陽嚴使君','袁皓','唐','唐诗','tang','','[]','得意東歸過岳陽，桂枝香惹蘂珠香。',64,'全唐诗/poet.tang.33000.json','["得意東歸過岳陽，桂枝香惹蘂珠香。", "也知暮雨生巫峽，爭奈朝雲屬楚王。", "萬恨只憑期尅手，寸心唯繫別離腸。", "南亭宴罷笙歌散，回首煙波路渺茫。"]'),
('3a863ee1-7532-4b3d-8798-80dcc8dc5da4','賦得郎官上應列宿','公乘億','唐','唐诗','tang','','[]','北極佇文昌，南宮曉拜郎。',72,'全唐诗/poet.tang.33000.json','["北極佇文昌，南宮曉拜郎。", "紫泥乘帝澤，銀印佩天光。", "緯結三台側，鉤連四輔傍。", "佐商依傅說，仕漢笑馮唐。", "委佩搖秋色，峨冠帶晚霜。", "自然符列象，千古耀巖廊。"]'),
('23e19745-689d-43ab-a9b4-bbee518246fb','春風扇微和','公乘億','唐','唐诗','tang','','[]','麗日催遲景，和風扇早春。',72,'全唐诗/poet.tang.33000.json','["麗日催遲景，和風扇早春。", "暖浮丹鳳闕，韶媚黑龍津。", "澹蕩迎仙仗，霏微送畫輪。", "綠搖宮柳散，紅待禁花新。", "舞席潛迴雪，歌筵暗起塵。", "幸當陽候律，一顧及佳晨。"]'),
('365cf5e5-97f6-4c86-a2c3-0638591bec07','賦得秋菊有佳色','公乘億','唐','唐诗','tang','','[]','陶令籬邊菊，秋來色轉佳。',72,'全唐诗/poet.tang.33000.json','["陶令籬邊菊，秋來色轉佳。", "翠攢千片葉，金剪一枝花。", "蘂逐蜂鬚亂，英隨蝶翅斜。", "帶香飄綠綺，和酒上烏紗。", "散漫搖霜彩，嬌妍漏日華。", "芳菲彭澤見，更稱在誰家。"]'),
('e286473f-c950-45f1-b1e0-ab2695ee3313','賦得臨江遲來客','公乘億','唐','唐诗','tang','','[]','江上晚沈沈，煙波一望深。',72,'全唐诗/poet.tang.33000.json','["江上晚沈沈，煙波一望深。", "向來殊未至，何處擬相尋。", "柳結重重眼，萍翻寸寸心。", "暮山期共眺，寒渚待同臨。", "北去魚無信，南飛雁絕音。", "思君不可見，使我獨愁吟。"]'),
('cd1441f8-efa1-489c-859f-f85839fc5634','句','公乘億','唐','唐诗','tang','','[]','十上十年皆落第，一家一半已成塵。',16,'全唐诗/poet.tang.33000.json','["十上十年皆落第，一家一半已成塵。"]'),
('7db92cc3-6601-4b32-9623-51317bb04f5a','九華山謠','王季文','唐','唐诗','tang','','["\u4e5d\u534e\u5c71"]','九華崢嶸占南陸，蓮花擢本山半腹。',194,'全唐诗/poet.tang.33000.json','["九華崢嶸占南陸，蓮花擢本山半腹。", "翠屏橫截萬里天，瀑水落深千丈玉。", "雲梯石磴入杳冥，俯看四極如中庭。", "丹崖壓下廬霍勢，白日隱出牛斗星。", "杉松一歲抽數尺，瓊草夤緣秀層壁。", "南風拂曉煙霧開，滿山葱蒨鋪鮮碧。", "雷霆往往從地發，龍臥豹藏安可別。", "峻極遙看戛昊蒼，挺生豈得無才傑。", "神仙憚險莫敢登，馭風駕鶴循丘陵。", "陽烏不見峰頂樹，大火尚結嵒中冰。", "靈光爽氣曛復旭，晴天倒影西江淥。", "具區彭蠡夾兩傍，正可別作一嶽當少陽。"]'),
('97044873-3b91-4956-adef-8266fc3b9cb5','青出藍','王季文','唐','唐诗','tang','','[]','芳藍滋匹帛，人力半天經。',48,'全唐诗/poet.tang.33000.json','["芳藍滋匹帛，人力半天經。", "浸潤加新氣，光輝勝本青。", "還同冰出水，不共草爲螢。", "翻覆依襟上，偏知造化靈。"]'),
('b12421f5-9ffb-43aa-80e1-035bdb78cecb','題青龍精舍','盧駢','唐','唐诗','tang','','[]','壽夭雖云命，榮枯亦大偏。',24,'全唐诗/poet.tang.33000.json','["壽夭雖云命，榮枯亦大偏。", "不知雷氏劒，何處更衝天。"]'),
('3374d45f-b43e-4d85-bb20-179d6f0e605c','感事','王鐐','唐','唐诗','tang','','[]','擊石易得火，扣人難動心。',24,'全唐诗/poet.tang.33000.json','["擊石易得火，扣人難動心。", "今日朱門者，曾恨朱門深。"]'),
('4722b13d-8c32-4d3f-a6ff-fbe903b14ed3','退朝望終南山','李拯','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','紫宸朝罷綴鴛鸞，丹鳳樓前駐馬看。',32,'全唐诗/poet.tang.33000.json','["紫宸朝罷綴鴛鸞，丹鳳樓前駐馬看。", "惟有終南山色在，晴明依舊滿長安。"]'),
('6b26a0d9-096e-44de-9f3f-4764c1aa445f','月中桂樹','顧封人','唐','唐诗','tang','','[]','芬馥天邊桂，扶疎在月中。',72,'全唐诗/poet.tang.33000.json','["芬馥天邊桂，扶疎在月中。", "能齊大椿長，不與小山同。", "皎皎舒華色，亭亭麗碧空。", "虧盈寧委露，搖落不關風。", "歲晚花應發，春餘質詎豐。", "無因遂攀賞，徒欲望青葱。"]'),
('cd6c9cda-dade-4038-9adf-fc5b46e2b4b9','和陸魯望白菊','司馬都','唐','唐诗','tang','','[]','恥共金英一例開，素芳須待早霜催。',64,'全唐诗/poet.tang.33000.json','["恥共金英一例開，素芳須待早霜催。", "繞籬看見成瑤圃，泛酒須迷傍玉杯。", "映水好將蘋作伴，犯寒疑與雪爲媒。", "夫君每尚風流事，應爲徐妃致此栽。"]'),
('5edbbaf1-37c8-48d7-8f6c-e4e7fe392edb','送羊振文先輩往桂陽歸覲','司馬都','唐','唐诗','tang','','[]','此去歡榮冠士林，離筵休恨酒杯深。',64,'全唐诗/poet.tang.33000.json','["此去歡榮冠士林，離筵休恨酒杯深。", "雲梯萬仞初高步，月桂餘香尚滿襟。", "鳴櫂曉衝蒼靄發，落帆寒動白華吟。", "君家祖德惟清苦，却笑當時問絹心。"]'),
('bcdd39e3-519f-49b1-ba99-ba6a3990913d','書邊事','李昌符','唐','唐诗','tang','','[]','朔野煙塵起，天軍又舉戈。',48,'全唐诗/poet.tang.33000.json','["朔野煙塵起，天軍又舉戈。", "陰風向晚急，殺氣入秋多。", "樹盡禽栖草，冰堅路在河。", "汾陽無繼者，羌虜肯先和。"]'),
('62d40055-f939-4d66-ac26-b0e267a76b9a','遠歸別墅','李昌符','唐','唐诗','tang','','[]','馬省曾行處，連嘶渡晚河。',48,'全唐诗/poet.tang.33000.json','["馬省曾行處，連嘶渡晚河。", "忽驚鄉樹出，漸識路人多。", "細徑穿禾黍，頹垣壓薜蘿。", "乍歸猶似客，鄰叟亦相過。"]'),
('2e902cf0-c49b-4148-82f9-b64f6910ec1a','題友人屋','李昌符','唐','唐诗','tang','','[]','松底詩人宅，閑門遠岫孤。',48,'全唐诗/poet.tang.33000.json','["松底詩人宅，閑門遠岫孤。", "數家分小徑，一水截平蕪。", "竹節偶相對，鳥名多自呼。", "愛君真靜者，欲去又踟躕。"]'),
('2f2c8f85-b2cd-4dbb-b338-2dccb712df87','贈同遊','李昌符','唐','唐诗','tang','','[]','此來風雨後，已覺減年華。',48,'全唐诗/poet.tang.33000.json','["此來風雨後，已覺減年華。", "若待皆無事，應難更有花。", "管弦臨夜急，榆柳向江斜。", "且莫看歸路，同須醉酒家。"]'),
('a9627a6d-5265-4cf8-a922-6f169581eb4f','送人出塞','李昌符','唐','唐诗','tang','','[]','北風吹雨雪，舉目已悽悽。',48,'全唐诗/poet.tang.33000.json','["北風吹雨雪，舉目已悽悽。", "戰鬼秋頻哭，征鴻夜不栖。", "沙平關路直，磧廣郡樓低。", "此去非東魯，人多事鼓鼙。"]'),
('091266bf-de09-4607-91f7-be2f18551844','尋僧元皎因贈','李昌符','唐','唐诗','tang','','[]','此生迷有著，因病得尋師。',48,'全唐诗/poet.tang.33000.json','["此生迷有著，因病得尋師。", "話盡山中事，歸當月上時。", "高松連寺影，亞竹入窗枝。", "閑憶草堂路，相逢非素期。"]'),
('aec8d9b8-6a24-4cdb-b33b-59f64312d006','下第後蒙侍郎示意指於新先輩宣恩感謝','李昌符','唐','唐诗','tang','','[]','才薄命如此，自嗟兼自疑。',48,'全唐诗/poet.tang.33000.json','["才薄命如此，自嗟兼自疑。", "遭逢好文日，黜落至公時。", "倚玉甘無路，穿楊却未期。", "更慙君侍坐，問許可言詩。"]'),
('eab528fa-4fb8-4ecc-aa06-e0a59728c768','夜泊渭津','李昌符','唐','唐诗','tang','','[]','漂漂東去客，一宿渭城邊。',48,'全唐诗/poet.tang.33000.json','["漂漂東去客，一宿渭城邊。", "遠處星垂岸，中流月滿船。", "涼歸夜深簟，秋入雨餘天。", "漸覺家山小，殘程尚幾年。"]'),
('1ab1b2a9-85c9-4e20-b5b5-849400524d83','晚夏逢友人','李昌符','唐','唐诗','tang','','[]','一別同袍友，相思已十年。',48,'全唐诗/poet.tang.33000.json','["一別同袍友，相思已十年。", "長安多在客，久病忽聞蟬。", "驟雨纔沾地，陰雲不徧天。", "微涼堪話舊，移榻晚風前。"]'),
('a731e1d7-bdca-4d32-8e89-0cb720a7497b','秋中夜坐','李昌符','唐','唐诗','tang','','[]','空庭吟坐久，爽氣入荷衣。',48,'全唐诗/poet.tang.33000.json','["空庭吟坐久，爽氣入荷衣。", "病葉先秋落，驚禽背月飛。", "瘴雲晴未散，戍客老將依。", "爲應金門策，多應說戰機。"]'),
('6bdd7dcd-edf2-451b-baed-40552949568f','旅遊傷春','李昌符','唐','唐诗','tang','','[]','酒醒鄉關遠，迢迢聽漏終。',48,'全唐诗/poet.tang.33000.json','["酒醒鄉關遠，迢迢聽漏終。", "曙分林影外，春盡雨聲中。", "鳥思江村路，花殘野岸風。", "十年成底事，羸馬倦西東。"]'),
('0e8de951-46c6-4912-9333-f19d48323dbf','得遠書','李昌符','唐','唐诗','tang','','[]','故人居謫宦，今日一書來。',48,'全唐诗/poet.tang.33000.json','["故人居謫宦，今日一書來。", "良久驚兼喜，殷勤卷更開。", "瘴雲沉去鴈，江雨促新梅。", "滿紙殊鄉淚，非冤不可哀。"]'),
('ba420ba2-434d-48c8-b11f-27a90aafb9ff','贈同席','李昌符','唐','唐诗','tang','','[]','四座列吾友，滿園花照衣。',48,'全唐诗/poet.tang.33000.json','["四座列吾友，滿園花照衣。", "一生知幾度，後到擬先歸。", "急管侵諸樂，嚴城送落暉。", "當歡莫離席，離席却歡稀。"]'),
('60aadee1-96f4-4f3f-9efd-61c72e456ee5','贈供奉僧玄觀','李昌符','唐','唐诗','tang','','[]','自得曹溪法，諸經更不看。',48,'全唐诗/poet.tang.33000.json','["自得曹溪法，諸經更不看。", "已降禪侶久，兼作帝師難。", "夜木侵簷黑，秋燈照雨寒。", "如何嫌有著，一念在林巒。"]'),
('dfbc244a-82e5-47ed-b833-5ee1d90d008a','送琴客','李昌符','唐','唐诗','tang','','[]','楚客抱離思，蜀琴留恨聲。',48,'全唐诗/poet.tang.33000.json','["楚客抱離思，蜀琴留恨聲。", "坐來新月上，聽久覺秋生。", "夜靜騷人語，天高別鶴鳴。", "因君興一歎，竟夕意難平。"]'),
('216fdfd8-5808-4b58-a4fa-dfac986fafb2','別謫者','李昌符','唐','唐诗','tang','','[]','此地聞猶惡，人言是所之。',48,'全唐诗/poet.tang.33000.json','["此地聞猶惡，人言是所之。", "一家書絕久，孤驛夢成遲。", "八月三湘道，聞猿冒雨時。", "不須祠楚相，臣節轉堪疑。"]'),
('2fe8280e-4730-47d2-9b17-9efcf72f81fd','行思','李昌符','唐','唐诗','tang','','[]','千里豈云去，欲歸如路窮。',48,'全唐诗/poet.tang.33000.json','["千里豈云去，欲歸如路窮。", "人間無暇日，馬上又秋風。", "破月銜高岳，流星拂曉空。", "此時皆在夢，行色獨怱怱。"]'),
('4c302ddc-a33c-4d46-80fd-09fb31a48be9','感懷題從舅宅','李昌符','唐','唐诗','tang','','[]','郗家庭樹下，幾度醉春風。',48,'全唐诗/poet.tang.33000.json','["郗家庭樹下，幾度醉春風。", "今日花還發，當時事不同。", "流言應未息，直道竟難通。", "徒遣相思者，悲歌向暮空。"]'),
('3d625aba-40bf-4ea3-ada1-5192afae7eb5','與友人會','李昌符','唐','唐诗','tang','','[]','蟬吟槐蘂落，的的是愁端。',48,'全唐诗/poet.tang.33000.json','["蟬吟槐蘂落，的的是愁端。", "病覺離家遠，貧知處事難。", "真交無所隱，深語有餘歡。", "未必聞歌吹，羈心得暫寬。"]'),
('8a1e7f88-cc7b-4e3c-a63b-228e2d2a0efb','贈春遊侶','李昌符','唐','唐诗','tang','','[]','密林多暗香，輕吹送餘芳。',48,'全唐诗/poet.tang.33000.json','["密林多暗香，輕吹送餘芳。", "啼鳥愁春盡，遊人喜日長。", "浮雲橫暮色，新雨洗韶光。", "欲散垂□恨，應須入醉鄉。"]'),
('42c6ec18-e83b-459d-be63-b5731b81e669','送人遊邊','李昌符','唐','唐诗','tang','','[]','愁指蕭關外，風沙入遠程。',48,'全唐诗/poet.tang.33000.json','["愁指蕭關外，風沙入遠程。", "馬行初有跡，雨落竟無聲。", "地理全歸漢，天威不在兵。", "西京逢故老，暗喜復時平。"]'),
('36784f56-32aa-485f-9150-5df6c71507c2','寄棲白上人','李昌符','唐','唐诗','tang','','[]','剪髪兼成隱，將心更屬文。',72,'全唐诗/poet.tang.33000.json','["剪髪兼成隱，將心更屬文。", "無憀對豪客，不拜謁吾君。", "畫壁惟泉石，經窗半典墳。", "歸林幽鳥狎，乞食病僧分。", "默坐終清夜，凝思念碧雲。", "相逢應未卜，余正走囂氛。"]'),
('ed813572-9cf9-4e6e-be67-8fb00dcaa4ff','送人入新羅使','李昌符','唐','唐诗','tang','','[]','雞林君欲去，立冊付星軺。',72,'全唐诗/poet.tang.33000.json','["雞林君欲去，立冊付星軺。", "越海程難計，征帆影自飄。", "望鄉當落日，懷闕羨迴潮。", "宿霧蒙青嶂，驚波蕩碧霄。", "春生陽氣早，天接祖州遙。", "愁約三年外，相迎上石橋。"]'),
('bc7ef10a-3d5b-4bec-a92b-f41409144fee','詠鐵馬鞭','李昌符','唐','唐诗','tang','','[]','漢將臨流得鐵鞭，鄂侯名字舊雕鐫。',64,'全唐诗/poet.tang.33000.json','["漢將臨流得鐵鞭，鄂侯名字舊雕鐫。", "須爲聖代無雙物，肯逐將軍臥九泉。", "汗馬不侵誅虜血，神功今見補亡篇。", "時來終薦明君用，莫歎沉埋二百年。"]'),
('c9652616-3106-45ff-981d-059cbe54b2f6','送友人','李昌符','唐','唐诗','tang','','[]','舉世誰能與事期，解攜多是正歡時。',64,'全唐诗/poet.tang.33000.json','["舉世誰能與事期，解攜多是正歡時。", "人間不遣有名利，陌上始應無別離。", "晚渡待船愁立久，亂山投店獨行遲。", "我今漂泊還如此，江劒相逢亦未知。"]'),
('f15349ab-a6e5-47b9-ab3f-856871f8c575','南潭','李昌符','唐','唐诗','tang','','[]','匝岸青蕪掩古苔，面山亭樹枕潭開。',64,'全唐诗/poet.tang.33000.json','["匝岸青蕪掩古苔，面山亭樹枕潭開。", "有時弦管收筵促，無數鳧鷖逆浪來。", "路入龍祠羣木老，風驚漁艇一聲迴。", "人傳郭惲多遊此，誰見當初泛玉杯。"]'),
('50c748fc-6d8f-4dad-bfed-b3fdf3d8bceb','秋夜作','李昌符','唐','唐诗','tang','','[]','數畝池塘近杜陵，秋天寂寞夜雲凝。',64,'全唐诗/poet.tang.33000.json','["數畝池塘近杜陵，秋天寂寞夜雲凝。", "芙蓉葉上三更雨，蟋蟀聲中一點燈。", "跡避險巇翻失路，心歸閑澹不因僧。", "既逢上國陳詩日，長守林泉亦未能。"]'),
('2c44188a-7566-4a14-8cfb-4e1fe3dda03d','客恨','李昌符','唐','唐诗','tang','','[]','古原南北舊蕭疎，高木風多小雪餘。',64,'全唐诗/poet.tang.33000.json','["古原南北舊蕭疎，高木風多小雪餘。", "半夜病吟人寢後，百年閑事酒醒初。", "頻招兄弟同佳節，已有兵戈隔遠書。", "肥馬王孫定相笑，不知岐路厭樵漁。"]'),
('b2481eef-ccc9-446d-a7ae-c5fc31491ee2','三月盡日','李昌符','唐','唐诗','tang','','[]','江頭從此管弦稀，散盡遊人獨未歸。',32,'全唐诗/poet.tang.33000.json','["江頭從此管弦稀，散盡遊人獨未歸。", "落日已將春色去，殘花應逐夜風飛。"]'),
('42f2f6ce-da4c-46aa-9cac-4534345ad263','綠珠詠','李昌符','唐','唐诗','tang','','[]','洛陽佳麗與芳華，金谷園中見百花。',32,'全唐诗/poet.tang.33000.json','["洛陽佳麗與芳華，金谷園中見百花。", "誰遣當年墜樓死，無人巧笑破孫家。"]'),
('c850dded-9e51-4f4f-904f-86e3a5b4a202','贈別','李昌符','唐','唐诗','tang','','[]','又將書劒出孤舟，盡日停橈結遠愁。',32,'全唐诗/poet.tang.33000.json','["又將書劒出孤舟，盡日停橈結遠愁。", "莫道江波話離別，江波一去不迴流。"]'),
('69b16c8f-833b-436b-8180-bc0d658e735d','悶書','李昌符','唐','唐诗','tang','','[]','病來難處早秋天，一徑無人樹有蟬。',32,'全唐诗/poet.tang.33000.json','["病來難處早秋天，一徑無人樹有蟬。", "歸計未成書半卷，中宵多夢晝多眠。"]'),
('4c1ab440-1691-44fa-9841-c113e7c709b8','傷春','李昌符','唐','唐诗','tang','','[]','即是春風盡，仍霑夜雨歸。',24,'全唐诗/poet.tang.33000.json','["即是春風盡，仍霑夜雨歸。", "明朝更來此，兼恐落花稀。"]'),
('8cf79ffb-3579-4da7-80b2-19f5460a5d43','登臨洮望蕭關','李昌符','唐','唐诗','tang','','[]','漸覺風沙暗，蕭關欲到時。',48,'全唐诗/poet.tang.33000.json','["漸覺風沙暗，蕭關欲到時。", "兒童能探火，婦女解縫旗。", "川少銜魚鷺，林多帶箭麋。", "暫來戎馬地，不敢苦吟詩。"]'),
('3f1d6819-1620-493e-bc97-7375264a6b5c','彭澤','汪遵','唐','唐诗','tang','','[]','鶴愛孤松雲愛山，宦情微祿免相關。',32,'全唐诗/poet.tang.33000.json','["鶴愛孤松雲愛山，宦情微祿免相關。", "栽成五柳吟歸去，漉酒巾邊伴菊閑。"]'),
('294976dd-9957-45d5-bab7-f9a236a99def','杜郵館','汪遵','唐','唐诗','tang','','[]','殺盡降兵熱血流，一心猶自逞戈矛。',32,'全唐诗/poet.tang.33000.json','["殺盡降兵熱血流，一心猶自逞戈矛。", "功成若解求身退，豈得將軍死杜郵。"]'),
('0ad2796a-48cb-4151-9245-facf265ce53c','細腰宮','汪遵','唐','唐诗','tang','','[]','鼓聲連日燭連宵，貪向春風舞細腰。',32,'全唐诗/poet.tang.33000.json','["鼓聲連日燭連宵，貪向春風舞細腰。", "爭奈君王正沈醉，秦兵江上促征橈。"]'),
('9145cdfe-c305-4a0a-aaca-e07763bc466d','瑤臺','汪遵','唐','唐诗','tang','','[]','仙夢香魂不久留，滿川雲雨滿宮愁。',32,'全唐诗/poet.tang.33000.json','["仙夢香魂不久留，滿川雲雨滿宮愁。", "直須待得荆王死，始向瑤臺一處遊。"]'),
('570052f4-d023-426a-bc61-78d3c2f394db','吳坂','汪遵','唐','唐诗','tang','','[]','踡跼鹽車萬里蹄，忽逢良鑒始能嘶。',32,'全唐诗/poet.tang.33000.json','["踡跼鹽車萬里蹄，忽逢良鑒始能嘶。", "不緣伯樂稱奇骨，幾與駑駘價一齊。"]'),
('bf024664-f2b1-4fce-aa5d-81641efae642','箕山','汪遵','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u63cf\u5199\u5c71", "\u548f\u7269", "\u5199\u5c71"]','薄世臨流洗耳塵，便歸雲洞任天真。',32,'全唐诗/poet.tang.33000.json','["薄世臨流洗耳塵，便歸雲洞任天真。", "一瓢風入猶嫌鬧，何況人間萬種人。"]'),
('3760a4f0-4a87-400e-8b6f-85e36d264eb2','息國','汪遵','唐','唐诗','tang','','[]','家國興亡身獨存，玉容還受楚王恩。',32,'全唐诗/poet.tang.33000.json','["家國興亡身獨存，玉容還受楚王恩。", "銜冤只合甘先死，何待花間不肯言。"]'),
('0a358dfc-47a6-49eb-95a4-e1dc11547bc3','梁寺','汪遵','唐','唐诗','tang','','[]','立國從來爲戰功，一朝何事却談空。',32,'全唐诗/poet.tang.33000.json','["立國從來爲戰功，一朝何事却談空。", "臺城兵匝無人敵，閑臥高僧滿梵宮。"]'),
('c71e895e-ae6e-4263-af87-b77ed5975260','南陽','汪遵','唐','唐诗','tang','','[]','陸困泥蟠未適從，豈妨耕嫁隱高蹤。',32,'全唐诗/poet.tang.33000.json','["陸困泥蟠未適從，豈妨耕嫁隱高蹤。", "若非先主垂三顧，誰識茅廬一臥龍。"]'),
('e3ba9235-0a95-466d-b484-2038c8cf28da','杞梁墓','汪遵','唐','唐诗','tang','','[]','一呌長城萬仞摧，杞梁遺骨逐妻回。',32,'全唐诗/poet.tang.33000.json','["一呌長城萬仞摧，杞梁遺骨逐妻回。", "南鄰北里皆孀婦，誰解堅心繼此來。"]'),
('fd38d52c-5d2b-4333-9e62-44ed49b545bb','夷門','汪遵','唐','唐诗','tang','','[]','晉鄙兵回爲重難，秦師收斾亦西還。',32,'全唐诗/poet.tang.33000.json','["晉鄙兵回爲重難，秦師收斾亦西還。", "今來不是無朱亥，誰降軒車問抱關。"]'),
('50c31d00-b5ea-475a-b273-39655dcc8a4c','汴河','汪遵','唐','唐诗','tang','','[]','隋皇意欲泛龍舟，千里崑崙水別流。',32,'全唐诗/poet.tang.33000.json','["隋皇意欲泛龍舟，千里崑崙水別流。", "還待春風錦帆暖，柳陰相送到迷樓。"]'),
('c591e80b-9628-422a-a259-8c1150d6de10','燕臺','汪遵','唐','唐诗','tang','','[]','禮士招賢萬古名，高臺依舊對燕城。',32,'全唐诗/poet.tang.33000.json','["禮士招賢萬古名，高臺依舊對燕城。", "如今寂寞無人上，春去秋來草自生。"]'),
('47afeb95-375d-407a-91d0-68cdd6bc91c6','聊城','汪遵','唐','唐诗','tang','','[]','刃血攻聊已越年，竟憑儒術罷戈鋋。',32,'全唐诗/poet.tang.33000.json','["刃血攻聊已越年，竟憑儒術罷戈鋋。", "田單漫逞燒牛計，一箭終輸魯仲連。"]'),
('959ebc64-baeb-4319-bb05-520d2350872b','西河','汪遵','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u548f\u53f2", "\u6545\u4e8b"]','花貌年年溺水濱，俗傳河伯娶生人。',32,'全唐诗/poet.tang.33000.json','["花貌年年溺水濱，俗傳河伯娶生人。", "自從明宰投巫後，直至如今鬼不神。"]'),
('994d1a03-de61-4f78-a99e-b9a63de5c320','密縣','汪遵','唐','唐诗','tang','','[]','百里能將濟猛寬，飛蝗不到邑人安。',32,'全唐诗/poet.tang.33000.json','["百里能將濟猛寬，飛蝗不到邑人安。", "至今閭里逢災沴，猶祝當時卓長官。"]'),
('3f85094a-4ef5-4fa7-bd3e-1723c3934dc7','昇仙橋','汪遵','唐','唐诗','tang','','[]','題橋貴欲露先誠，此日人皆笑率情。',32,'全唐诗/poet.tang.33000.json','["題橋貴欲露先誠，此日人皆笑率情。", "應訝臨邛沽酒客，逢時還作漢公卿。"]'),
('f8c5daeb-6765-4903-8d95-e04df95b11ac','破陳','汪遵','唐','唐诗','tang','','[]','獵獵朱旗映綵霞，紛紛白刃入陳家。',32,'全唐诗/poet.tang.33000.json','["獵獵朱旗映綵霞，紛紛白刃入陳家。", "看看打破東平苑，猶舞庭前玉樹花。"]'),
('fc23c9f1-55af-48ad-9b68-b519ee6940ea','白頭吟','汪遵','唐','唐诗','tang','','[]','失却青絲素髪生，合歡羅帶意全輕。',32,'全唐诗/poet.tang.33000.json','["失却青絲素髪生，合歡羅帶意全輕。", "古今人事皆如此，不獨文君與馬卿。"]'),
('d591eb99-a637-411a-b918-037a79f3b523','短歌吟','汪遵','唐','唐诗','tang','','[]','箭飛烏兔競東西，貴賤賢愚不夢齊。',32,'全唐诗/poet.tang.33000.json','["箭飛烏兔競東西，貴賤賢愚不夢齊。", "匣裏有琴樽有酒，人間便是武陵溪。"]'),
('7503ebcd-fc91-41af-b637-015557bc978c','晉河','汪遵','唐','唐诗','tang','','[]','風引征帆管吹高，晉君張[宴]俟雄豪。',34,'全唐诗/poet.tang.33000.json','["風引征帆管吹高，晉君張[宴]俟雄豪。", "舟人笑指千餘客，誰是煙霄六翮毛。"]'),
('2cdf1d0c-eea2-4e6a-b101-689c55aef64b','干將墓','汪遵','唐','唐诗','tang','','[]','橐籥冰霜萬古聞，拍灰松地見餘墳。',32,'全唐诗/poet.tang.33000.json','["橐籥冰霜萬古聞，拍灰松地見餘墳。", "應緣神劒飛揚久，水水山山盡是雲。"]'),
('7f2eb4a9-767e-4c86-a52c-6dbef1abf877','金谷','汪遵','唐','唐诗','tang','','[]','晉臣榮盛更誰過，常向階前舞翠娥。',32,'全唐诗/poet.tang.33000.json','["晉臣榮盛更誰過，常向階前舞翠娥。", "香散豔消如一夢，但留風月伴煙蘿。"]'),
('94604940-162a-489e-a373-f8cd0b21cf42','三閭廟','汪遵','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','爲嫌朝野盡陶陶，不覺官高怨亦高。',32,'全唐诗/poet.tang.33000.json','["爲嫌朝野盡陶陶，不覺官高怨亦高。", "憔悴莫酬漁父笑，浪交千載詠離騷。"]'),
('ef03c2f4-656e-4ce8-b162-63bfe92cf1b1','易水','汪遵','唐','唐诗','tang','','[]','[匕]首空磨事不成，誤留龍袂待琴聲。',34,'全唐诗/poet.tang.33000.json','["[匕]首空磨事不成，誤留龍袂待琴聲。", "斯須却作秦中鬼，青史徒標烈士名。"]'),
('e04319aa-5570-4347-929d-a22c329a0f69','嚴陵臺','汪遵','唐','唐诗','tang','','[]','一釣淒涼在杳冥，故人飛詔入山扃。',32,'全唐诗/poet.tang.33000.json','["一釣淒涼在杳冥，故人飛詔入山扃。", "終將寵辱輕軒冕，高臥五雲爲客星。"]'),
('0a2271fa-6d70-417b-8308-83984fa2c447','淮陰','汪遵','唐','唐诗','tang','','[]','秦季賢愚混不分，只應漂母識王孫。',32,'全唐诗/poet.tang.33000.json','["秦季賢愚混不分，只應漂母識王孫。", "歸榮便累千金贈，爲報當時一飯恩。"]'),
('44e6dd53-f5c2-4cc7-946e-da0e778f109a','雞鳴曲','汪遵','唐','唐诗','tang','','[]','金距花冠傍舍棲，清晨相呌一聲齊。',32,'全唐诗/poet.tang.33000.json','["金距花冠傍舍棲，清晨相呌一聲齊。", "開關自有馮生計，不必天明待汝啼。"]'),
('97f9d225-6876-4e19-b622-055de1a9c0ad','採桑婦','汪遵','唐','唐诗','tang','','[]','爲報躊躇陌上郎，蠶飢日晚妾心忙。',32,'全唐诗/poet.tang.33000.json','["爲報躊躇陌上郎，蠶飢日晚妾心忙。", "本來若愛黃金好，不肯攜籠更採桑。"]'),
('a7bd6a97-1713-4cfc-bb5d-0fb0c6b7cca3','漁父','汪遵','唐','唐诗','tang','','[]','棹月眠流處處通，綠蓑葦帶混元風。',32,'全唐诗/poet.tang.33000.json','["棹月眠流處處通，綠蓑葦帶混元風。", "靈均說盡孤高事，全與逍遙意不同。"]'),
('fd937db1-0c8b-4da7-ab46-6f25f53b5a4f','越女','汪遵','唐','唐诗','tang','','[]','玉貌何曾爲浣沙，只圖句踐獻夫差。',32,'全唐诗/poet.tang.33000.json','["玉貌何曾爲浣沙，只圖句踐獻夫差。", "蘇臺日夜唯歌舞，不覺干戈犯翠華。"]'),
('c643ce83-99c6-4d8b-be7b-491051637def','望思臺','汪遵','唐','唐诗','tang','','[]','不憂家國任姦臣，骨肉翻爲驀路人。',32,'全唐诗/poet.tang.33000.json','["不憂家國任姦臣，骨肉翻爲驀路人。", "巫蠱事行冤莫雪，九層徒築見無因。"]'),
('0d287078-2d29-45bf-b7bd-54dc4aa1822d','比干墓','汪遵','唐','唐诗','tang','','[]','國亂時危道不行，忠賢諫死勝謀生。',32,'全唐诗/poet.tang.33000.json','["國亂時危道不行，忠賢諫死勝謀生。", "一沈冤骨千年後，壠水雖平恨未平。"]'),
('70a3a784-4858-4550-8b05-ecf912727134','郢中','汪遵','唐','唐诗','tang','','[]','莫言白雪少人聽，高調都難稱俗情。',32,'全唐诗/poet.tang.33000.json','["莫言白雪少人聽，高調都難稱俗情。", "不是楚詞詢宋玉，巴歌猶掩繞梁聲。"]'),
('58d56aa6-cb97-4ef8-9183-5dd2631526f9','北海','汪遵','唐','唐诗','tang','','[]','漢臣曾此作縲囚，茹血衣毛十九秋。',32,'全唐诗/poet.tang.33000.json','["漢臣曾此作縲囚，茹血衣毛十九秋。", "鶴髪半垂龍節在，不聞青史說封侯。"]'),
('ebc7b419-b8e4-4579-b446-38626bc8cb84','招屈亭','汪遵','唐','唐诗','tang','','[]','三閭溺處殺懷王，感得荆人盡縞裳。',32,'全唐诗/poet.tang.33000.json','["三閭溺處殺懷王，感得荆人盡縞裳。", "招屈亭邊兩重恨，遠天秋色暮蒼蒼。"]'),
('1f191020-8a68-4bc1-9854-c0fc74be99e0','屈祠','汪遵','唐','唐诗','tang','','[]','不肯迂回入醉鄉，乍吞忠梗沒滄浪。',32,'全唐诗/poet.tang.33000.json','["不肯迂回入醉鄉，乍吞忠梗沒滄浪。", "至今祠畔猨啼月，了了猶疑恨楚王。"]'),
('80d320d2-0328-44a5-9c77-a306ca9021ff','銅雀臺','汪遵','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269"]','銅雀臺成玉座空，短歌長袖盡悲風。',32,'全唐诗/poet.tang.33000.json','["銅雀臺成玉座空，短歌長袖盡悲風。", "不知仙駕歸何處，徒遣顰眉望漢宮。"]'),
('9ff3034d-e93b-4c70-8f1a-90d71b8e3a2f','斑竹祠','汪遵','唐','唐诗','tang','','[]','九處煙霞九處昏，一回延首一銷魂。',32,'全唐诗/poet.tang.33000.json','["九處煙霞九處昏，一回延首一銷魂。", "因憑直節流紅淚，圖得千秋見血痕。"]'),
('6017571a-62cb-4026-a501-1a34d3dbf49f','題李太尉平泉莊','汪遵','唐','唐诗','tang','','[]','水泉花木好高眠，嵩少縱橫滿目前。',32,'全唐诗/poet.tang.33000.json','["水泉花木好高眠，嵩少縱橫滿目前。", "惆悵人間不平事，今朝身在海南邊。"]'),
('7fa397b3-cfad-4fbc-bb38-3b2e9a2b4932','戰城南','汪遵','唐','唐诗','tang','','[]','風沙刮地塞雲愁，平旦交鋒晚未休。',32,'全唐诗/poet.tang.33000.json','["風沙刮地塞雲愁，平旦交鋒晚未休。", "白骨又霑新戰血，青天猶列舊旄頭。"]'),
('c3261e9f-dea4-4289-b099-11b82b4d8b72','延平津','汪遵','唐','唐诗','tang','','[]','三尺晶熒射斗牛，豈隨凡手報冤讎。',32,'全唐诗/poet.tang.33000.json','["三尺晶熒射斗牛，豈隨凡手報冤讎。", "延平一旦爲龍處，看取風雲布九州。"]'),
('5895455a-f2d8-46c5-a3d9-6fcddd2235f8','項亭','汪遵','唐','唐诗','tang','','[]','不修仁德合文明，天道如何擬力爭。',32,'全唐诗/poet.tang.33000.json','["不修仁德合文明，天道如何擬力爭。", "隔岸故鄉歸不得，十年空負拔山名。"]'),
('c9219c42-cfc6-4351-b0d1-f585ab9da82a','烏江','汪遵','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u548f\u7269", "\u6000\u53e4"]','兵散弓殘挫虎威，單槍匹馬突重圍。',32,'全唐诗/poet.tang.33000.json','["兵散弓殘挫虎威，單槍匹馬突重圍。", "英雄去盡羞容在，看却江東不得歸。"]'),
('a76bec87-e535-4e5d-b26d-72e74c80103f','綠珠','汪遵','唐','唐诗','tang','','[]','大抵花顏最怕秋，南家歌歇北家愁。',32,'全唐诗/poet.tang.33000.json','["大抵花顏最怕秋，南家歌歇北家愁。", "從來幾許如君貌，不肯如君墜玉樓。"]'),
('3e0f5f20-6c17-4501-aff5-eecc2367ed02','升仙橋','汪遵','唐','唐诗','tang','','[]','漢朝卿相盡風雲，司馬題橋衆又聞。',32,'全唐诗/poet.tang.33000.json','["漢朝卿相盡風雲，司馬題橋衆又聞。", "何事不如楊得意，解搜賢哲薦明君。"]'),
('419886f2-bbac-4e85-b3ee-7e8e46944c3e','隋柳','汪遵','唐','唐诗','tang','','[]','夾浪分堤萬樹餘，爲迎龍舸到江都。',32,'全唐诗/poet.tang.33000.json','["夾浪分堤萬樹餘，爲迎龍舸到江都。", "君看靖節高眠處，只向衡門種五株。"]'),
('7e0522e2-a7c4-484b-9fb5-9918c96c3521','楊柳','汪遵','唐','唐诗','tang','','["\u548f\u7269", "\u548f\u7269\u8bd7", "\u67f3\u6811"]','亞夫營畔柳濛濛，隋主堤邊四路通。',32,'全唐诗/poet.tang.33000.json','["亞夫營畔柳濛濛，隋主堤邊四路通。", "攀折贈君還有意，翠眉輕嫩怕春風。"]'),
('04788171-e5ce-4eeb-a79d-45d650c4c1ba','桐江','汪遵','唐','唐诗','tang','','[]','光武重興四海寧，漢臣無不受浮榮。',32,'全唐诗/poet.tang.33000.json','["光武重興四海寧，漢臣無不受浮榮。", "嚴陵何事輕軒冕，獨向桐江釣月明。"]'),
('22a9138b-4b55-40b9-bf8a-543991cd83c7','招隱','汪遵','唐','唐诗','tang','','[]','罷聽泉聲看鹿羣，丈夫才策合匡君。',32,'全唐诗/poet.tang.33000.json','["罷聽泉聲看鹿羣，丈夫才策合匡君。", "早攜書劒離巖谷，莫待蒲輪輾白雲。"]'),
('00a2b3ef-4980-4841-bf44-149856512b39','陳宮','汪遵','唐','唐诗','tang','','[]','椒宮荒宴竟無疑，倏忽山河盡入隋。',32,'全唐诗/poet.tang.33000.json','["椒宮荒宴竟無疑，倏忽山河盡入隋。", "留得後庭亡國曲，至今猶與酒家吹。"]'),
('4320cb2a-8e6c-400f-ab61-c208adff0651','樊將軍廟','汪遵','唐','唐诗','tang','','[]','玉輦曾經陷楚營，漢皇心怯擬休兵。',32,'全唐诗/poet.tang.33000.json','["玉輦曾經陷楚營，漢皇心怯擬休兵。", "當時不得將軍力，日月須分一半明。"]'),
('ed04cccc-fd39-49c9-a6f8-e0cc6a247ecd','東海','汪遵','唐','唐诗','tang','','[]','漾舟雪浪映花顏，徐福攜將竟不還。',32,'全唐诗/poet.tang.33000.json','["漾舟雪浪映花顏，徐福攜將竟不還。", "同作危時避秦客，此行何似武陵灘。"]'),
('e68e55e8-8ccf-4876-b5e8-1aa7abb6ddb4','昭君','汪遵','唐','唐诗','tang','','[]','漢家天子鎮寰瀛，塞北羌胡未罷兵。',32,'全唐诗/poet.tang.33000.json','["漢家天子鎮寰瀛，塞北羌胡未罷兵。", "猛將謀臣徒自貴，蛾眉一笑塞塵清。"]'),
('14c56958-de59-44a6-b9ac-16c63ced163f','五湖','汪遵','唐','唐诗','tang','','[]','已立平吳霸越功，片帆高颺五湖風。',32,'全唐诗/poet.tang.33000.json','["已立平吳霸越功，片帆高颺五湖風。", "不知戰國官榮者，誰似陶朱得始終。"]'),
('d1e42d09-6192-4831-9f6a-490e309e9d23','澠池','汪遵','唐','唐诗','tang','','["\u5199\u4eba", "\u548f\u53f2", "\u5199\u4eba\u8bd7"]','西秦北趙各稱高，池上張筵列我曹。',32,'全唐诗/poet.tang.33000.json','["西秦北趙各稱高，池上張筵列我曹。", "何事君王親擊缶，相如有劒可吹毛。"]'),
('0931f471-e4ab-4dae-ae46-4766f309160a','函谷關','汪遵','唐','唐诗','tang','','[]','脫禍東奔壯氣摧，馬如飛電轂如雷。',32,'全唐诗/poet.tang.33000.json','["脫禍東奔壯氣摧，馬如飛電轂如雷。", "當時若不聽彈鋏，那得關門半夜開。"]'),
('f9b84be1-4b3c-4263-b155-fda62af96b04','詠酒二首 一','汪遵','唐','唐诗','tang','','[]','九醞松醪一曲歌，本圖閑放養天和。',32,'全唐诗/poet.tang.33000.json','["九醞松醪一曲歌，本圖閑放養天和。", "後人不識前賢意，破國亡家事甚多。"]'),
('34985a03-b05c-4e90-89bc-ee208ee4a037','詠酒二首 二','汪遵','唐','唐诗','tang','','[]','萬事銷沈向一杯，竹門啞軋爲風開。',32,'全唐诗/poet.tang.33000.json','["萬事銷沈向一杯，竹門啞軋爲風開。", "秋宵睡足芭蕉雨，又是江湖入夢來。"]'),
('c8976102-538f-413b-befe-240d3c9e8da0','蒼頡臺','汪遵','唐','唐诗','tang','','[]','觀跡成文代結繩，皇風儒教浩然興。',32,'全唐诗/poet.tang.33000.json','["觀跡成文代結繩，皇風儒教浩然興。", "幾人從此休耕釣，吟對長安雪夜燈。"]'),
('a121c97e-dab5-4caa-af60-0335913f93ed','長城','汪遵','唐','唐诗','tang','','["\u6292\u60c5", "\u548f\u7269", "\u548f\u7269\u8bd7"]','秦築長城比鐵牢，蕃戎不敢過臨洮。',32,'全唐诗/poet.tang.33000.json','["秦築長城比鐵牢，蕃戎不敢過臨洮。", "雖然萬里連雲際，爭及堯階三尺高。"]'),
('525f7715-adc4-4738-9cc9-bb546c153ae5','過洞庭湖','許棠','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','驚波常不定，半日鬢堪斑。',48,'全唐诗/poet.tang.33000.json','["驚波常不定，半日鬢堪斑。", "四顧疑無地，中流忽有山。", "鳥高恆畏墜，帆遠却如閑。", "漁父閑相引，時歌浩渺間。"]'),
('06a8c311-344b-4e44-a1f8-3d19d3241d91','登渭南縣樓','許棠','唐','唐诗','tang','','[]','近甸名偏著，登城景又寬。',48,'全唐诗/poet.tang.33000.json','["近甸名偏著，登城景又寬。", "半空分太華，極目是長安。", "雪助河流漲，人耕燒色殘。", "閑來時甚少，欲下重憑欄。"]'),
('6d1c5531-71aa-4fe0-82aa-c01e6080fdc5','送李頻之南陵主簿','許棠','唐','唐诗','tang','','[]','赴縣是還鄉，途程豈覺長。',48,'全唐诗/poet.tang.33000.json','["赴縣是還鄉，途程豈覺長。", "聽鶯離灞岸，盪槳入陵陽。", "野蕨生公署，閑雲拂印牀。", "晴天調膳外，垂釣有池塘。"]'),
('1b2f378d-0ee5-4c99-a293-10ba7679a21c','寫懷','許棠','唐','唐诗','tang','','[]','汩沒與辛勤，全鍾在此身。',48,'全唐诗/poet.tang.33000.json','["汩沒與辛勤，全鍾在此身。", "半生爲下客，終老託何人。", "兩鬢關中改，千巖海上春。", "青雲知有路，自是致無因。"]'),
('c077282f-8e6d-4007-bd29-e9befa1436bc','過中條山','許棠','唐','唐诗','tang','','[]','徒爲經異岳，不得訪靈蹤。',48,'全唐诗/poet.tang.33000.json','["徒爲經異岳，不得訪靈蹤。", "日盡行難盡，千重復萬重。", "雲垂多作雨，雷動半和鐘。", "孤竹人藏處，無因認本峰。"]'),
('2b067e07-e74c-4dcb-bc91-cd9abdf9149e','早發洛中','許棠','唐','唐诗','tang','','[]','半夜發清洛，不知過石橋。',48,'全唐诗/poet.tang.33000.json','["半夜發清洛，不知過石橋。", "雲增中岳大，樹隱上陽遙。", "塹黑初沉月，河明欲認潮。", "孤村人尚夢，無處暫停橈。"]'),
('dfe871e6-6b82-4219-ab47-d0ba5d2f7020','汝州郡樓望嵩山','許棠','唐','唐诗','tang','','[]','不共衆山同，岧嶤出迥空。',48,'全唐诗/poet.tang.33000.json','["不共衆山同，岧嶤出迥空。", "幾層高鳥外，萬仞一樓中。", "水落難歸地，雲離便逐風。", "唯應霄漢客，絕頂路方通。"]'),
('01fa2181-579a-4367-b5b9-520a4009dd86','將歸江南留別友人','許棠','唐','唐诗','tang','','[]','連春不得意，所業已疑非。',48,'全唐诗/poet.tang.33000.json','["連春不得意，所業已疑非。", "舊國亂離後，新年惆悵歸。", "雪開還楚地，花惹別秦衣。", "江徼多留滯，高秋會恐違。"]'),
('77e4dcb9-52a2-4c27-b0e4-b8fee1c7fb7e','塞外書事','許棠','唐','唐诗','tang','','[]','征路出窮邊，孤吟傍戍煙。',48,'全唐诗/poet.tang.33000.json','["征路出窮邊，孤吟傍戍煙。", "河光深蕩塞，磧色迥連天。", "殘日沉鵰外，驚蓬到馬前。", "空懷釣魚所，未定卜歸年。"]'),
('fc95c6cd-61e7-4de0-ac05-3b5a05cd3774','日暮江上','許棠','唐','唐诗','tang','','[]','孤帆收廣岸，落照在遙峰。',48,'全唐诗/poet.tang.33000.json','["孤帆收廣岸，落照在遙峰。", "南北渡人少，高低歸鳥重。", "潮回沙出樹，雨過浦沉鐘。", "漁父雖相問，那能話所從。"]'),
('bb826e50-cffe-4a96-a281-4b4fa7bd11aa','客行','許棠','唐','唐诗','tang','','[]','旅食唯草草，此生誰我同。',48,'全唐诗/poet.tang.33000.json','["旅食唯草草，此生誰我同。", "故園魂夢外，長路別離中。", "人事萍隨水，年光鳥過空。", "欲吟先落淚，多是怨途窮。"]'),
('08b03b0a-2c77-4743-a064-3bd62c5cef8e','送李員外知揚子州留務','許棠','唐','唐诗','tang','','[]','帝命分留務，東南向楚天。',48,'全唐诗/poet.tang.33000.json','["帝命分留務，東南向楚天。", "幾程迴送騎，中路見迎船。", "冶例開山鑄，民多酌海煎。", "青雲名素重，此去豈經年。"]'),
('fddf3c33-1130-4929-ad5b-9826b36b5c2e','春暮途次華山下','許棠','唐','唐诗','tang','','[]','他皆宴牡丹，獨又出長安。',48,'全唐诗/poet.tang.33000.json','["他皆宴牡丹，獨又出長安。", "遠道行非易，無圖住自難。", "離城風已暖，近岳雨翻寒。", "此去知誰顧，閑吟祗自寬。"]'),
('6e2fd26b-4016-452e-bd73-1eedba51a47a','旅次滑臺投獻陸侍御','許棠','唐','唐诗','tang','','[]','已是鴻來日，堪驚却背秦。',48,'全唐诗/poet.tang.33000.json','["已是鴻來日，堪驚却背秦。", "天遙三楚樹，路遠兩河人。", "旅夢難歸隱，吟魂不在身。", "霜臺欹冠豸，賴許往來頻。"]'),
('de2a7bdd-a37f-4f4e-a57a-a64e68300a0e','重歸江南','許棠','唐','唐诗','tang','','[]','無成歸故里，不似在他鄉。',48,'全唐诗/poet.tang.33000.json','["無成歸故里，不似在他鄉。", "歲月逐流水，山川空夕陽。", "回潮迷古渡，迸竹過鄰墻。", "耆舊休存省，胡爲止淚行。"]'),
('d5674592-9a68-40d1-ad94-faf25941098e','寄黔南李校書','許棠','唐','唐诗','tang','','[]','從戎巫峽外，吟興更應多。',48,'全唐诗/poet.tang.33000.json','["從戎巫峽外，吟興更應多。", "郡響蠻江漲，山昏蜀雨過。", "公筵饒越味，俗土尚巴歌。", "中夜懷吳夢，知經灩澦波。"]'),
('43bdd58d-99fd-4919-b981-6e700a096611','東歸留辭沈侍郎','許棠','唐','唐诗','tang','','[]','一第久乖期，深心已自疑。',48,'全唐诗/poet.tang.33000.json','["一第久乖期，深心已自疑。", "滄江歸恨遠，紫閣別愁遲。", "稽古成何事，龍鍾負已知。", "依門非近日，不慮舊恩移。"]'),
('94d5ff73-9ac9-49c0-aa0d-c1af4f8cd2c6','題開明里友人居','許棠','唐','唐诗','tang','','[]','城中塵外住，入望是田家。',48,'全唐诗/poet.tang.33000.json','["城中塵外住，入望是田家。", "井出深山水，闌藏異國花。", "風巢和鳥動，雪竹向人斜。", "來往唯君熟，鄉園共海涯。"]'),
('7fbd1f60-13c5-4808-b12d-c4e21ee9923b','遣懷','許棠','唐','唐诗','tang','','[]','此生何處遂，屑屑復悠悠。',48,'全唐诗/poet.tang.33000.json','["此生何處遂，屑屑復悠悠。", "舊國歸無計，他鄉夢亦愁。", "飛塵長滿眼，衰髪暗添頭。", "章句非經濟，終難動五侯。"]'),
('10e9b5ce-d0bf-4cff-8293-ca8128448804','送龍州樊使君','許棠','唐','唐诗','tang','','[]','曾見邛人說，龍州地未深。',48,'全唐诗/poet.tang.33000.json','["曾見邛人說，龍州地未深。", "碧溪飛白鳥，紅斾映青林。", "土產唯宜藥，王租只貢金。", "政成開宴日，誰伴使君吟。"]'),
('9d376e02-fa38-4fb4-84ed-a4141d1e7bef','寄盩厔薛能少府','許棠','唐','唐诗','tang','','[]','滿縣唯雲水，何曾似近畿。',48,'全唐诗/poet.tang.33000.json','["滿縣唯雲水，何曾似近畿。", "曉庭猿集慣，寒署吏衙稀。", "冰色封深澗，樵聲出紫微。", "時聞迎隱者，依舊著山衣。"]'),
('a9efcd3e-1207-42f9-a991-beaf17ec4808','送李左丞巡邊','許棠','唐','唐诗','tang','','[]','狂戎侵內地，左轄去蕭關。',48,'全唐诗/poet.tang.33000.json','["狂戎侵內地，左轄去蕭關。", "走馬衝邊雪，鳴鞞動塞山。", "風收枯草定，月滿廣沙閑。", "西繞河蘭匝，應多隔歲還。"]'),
('6b3b3871-80c0-4313-b8cf-5d34f0b190ff','題青山館','許棠','唐','唐诗','tang','','[]','境概殊諸處，依然是謝家。',48,'全唐诗/poet.tang.33000.json','["境概殊諸處，依然是謝家。", "遺文齊日月，舊井照煙霞。", "水隔平蕪遠，山橫度鳥斜。", "無人能此隱，來往謾興嗟。"]'),
('7c0c4519-736c-46fb-a080-6aaecf6c9d87','鴈門關野望','許棠','唐','唐诗','tang','','[]','高關閑獨望，望久轉愁人。',48,'全唐诗/poet.tang.33000.json','["高關閑獨望，望久轉愁人。", "紫塞唯多雪，胡山不盡春。", "河遙分斷野，樹亂起飛塵。", "時見東來騎，心知近別秦。"]'),
('4fbe45e8-bbff-4b65-81a7-c79680d9a894','五原書事','許棠','唐','唐诗','tang','','[]','西出黃雲外，東懷白浪遙。',48,'全唐诗/poet.tang.33000.json','["西出黃雲外，東懷白浪遙。", "星河愁立夜，雷電獨行朝。", "磧迥人防寇，天空鴈避鵰。", "如何非戰卒，弓劒不離腰。"]'),
('d54d95c1-02cc-468a-9e60-9f0710a9d381','送從弟歸泉州','許棠','唐','唐诗','tang','','[]','問省歸南服，懸帆任北風。',48,'全唐诗/poet.tang.33000.json','["問省歸南服，懸帆任北風。", "何山猶見雪，半路已無鴻。", "瘴雜春雲重，星垂夜海空。", "往來如不住，亦是一年中。"]'),
('fd4c364c-e867-405a-9877-dc8a7f077641','留別故人','許棠','唐','唐诗','tang','','[]','殊立本不偶，非唯今所難。',48,'全唐诗/poet.tang.33000.json','["殊立本不偶，非唯今所難。", "無門閑共老，盡日泣相看。", "鳥畏聞鶗鴂，花慚背牡丹。", "何人知此計，復議出長安。"]'),
('7c58db52-31f5-47e2-9495-bcf586364c8e','塞下二首 一','許棠','唐','唐诗','tang','','[]','胡虜偏狂悍，邊兵不敢閑。',48,'全唐诗/poet.tang.33000.json','["胡虜偏狂悍，邊兵不敢閑。", "防秋朝伏弩，縱火夜搜山。", "鴈逆風鼙振，沙飛獵騎還。", "安西雖有路，難更出陽關。"]'),
('c2fcd682-33e0-4119-8305-d97892d9dbf6','塞下二首 二','許棠','唐','唐诗','tang','','[]','征役已不定，又緣無定河。',48,'全唐诗/poet.tang.33000.json','["征役已不定，又緣無定河。", "塞深烽砦密，山亂犬羊多。", "漢卒聞笳泣，胡兒擊劒歌。", "番情終未測，今昔謾言和。"]'),
('99f7f90c-b956-4cc2-a6a5-6a8b926a186d','題張喬昇平里居','許棠','唐','唐诗','tang','','["\u5e90\u5c71"]','下馬似無人，開門只一身。',48,'全唐诗/poet.tang.33000.json','["下馬似無人，開門只一身。", "心同孤鶴靜，行過老僧真。", "亂水藏幽徑，高原隔遠津。", "匡廬曾共隱，相見自相親。"]'),
('571a741e-535b-49e8-baf3-16363d531471','題鄭拾遺南齋','許棠','唐','唐诗','tang','','[]','明時無事諫，豈事隱明君。',48,'全唐诗/poet.tang.33000.json','["明時無事諫，豈事隱明君。", "每值離丹陛，多陪宴白雲。", "門連蕭洞僻，地與曲江分。", "滿院皆檉竹，期棲鸞鶴羣。"]'),
('924c13fb-af38-40c9-a49a-f376d70b0b8f','渭上送人南歸','許棠','唐','唐诗','tang','','[]','遠役與歸愁，同來渭水頭。',48,'全唐诗/poet.tang.33000.json','["遠役與歸愁，同來渭水頭。", "南浮應到海，北去阻無州。", "楚雨天連地，胡風夏甚秋。", "江人如見問，爲話復貧遊。"]'),
('fd0d2b79-12aa-4720-a028-324836ce830e','寄睦州陸郎中','許棠','唐','唐诗','tang','','[]','下國多高趣，終年半是吟。',48,'全唐诗/poet.tang.33000.json','["下國多高趣，終年半是吟。", "海濤通越分，部伍雜閩音。", "曉郭雲藏市，春山鳥護林。", "東浮雖未遂，日日至中心。"]'),
('23e07dce-686b-4f6f-a62d-074d75191aab','投徐端公','許棠','唐','唐诗','tang','','[]','無謀尋舊友，強喜亦如愁。',48,'全唐诗/poet.tang.33000.json','["無謀尋舊友，強喜亦如愁。", "丹桂阻丹懇，白衣成白頭。", "窮吳迷釣業，大漠事貧遊。", "霄漢期提引，龍鍾未擬休。"]'),
('7f4be3e7-539c-478c-8dcf-c3aca712868c','出塞門','許棠','唐','唐诗','tang','','[]','步步經戎虜，防兵不離身。',48,'全唐诗/poet.tang.33000.json','["步步經戎虜，防兵不離身。", "山多曾戰處，路斷野行人。", "暴雨聲同瀑，奔沙勢異塵。", "片時懷萬慮，白髮數莖新。"]'),
('ff37d448-1e74-4674-9b78-07109a745135','新年呈友','許棠','唐','唐诗','tang','','[]','一月月相似，一年年不同。',48,'全唐诗/poet.tang.33000.json','["一月月相似，一年年不同。", "清晨窺古鏡，旅貌近衰翁。", "處世閑難得，關身事半空。", "浮生能幾許，莫惜醉春風。"]'),
('7f2904f1-b240-48a2-8cdf-31352b17dce3','銀州北書事','許棠','唐','唐诗','tang','','[]','南辭采石遠，北背乞銀深。',48,'全唐诗/poet.tang.33000.json','["南辭采石遠，北背乞銀深。", "磧路雖多險，江人不廢吟。", "鵰依孤堠立，鷗向迥沙沈。", "因共邊人熟，行行起戰心。"]'),
('a3114bfa-0709-4755-b79a-0d65b98c913f','寄趙能卿','許棠','唐','唐诗','tang','','[]','我命同君命，君詩似我詩。',48,'全唐诗/poet.tang.33000.json','["我命同君命，君詩似我詩。", "俱無中道計，各失半生期。", "素業滄江遠，清時白髮垂。", "蹉跎一如此，何處卜棲遲。"]'),
('558f05a6-2d64-4d74-9477-fddfb139a080','夏州道中','許棠','唐','唐诗','tang','','[]','茫茫沙漠廣，漸遠赫連城。',48,'全唐诗/poet.tang.33000.json','["茫茫沙漠廣，漸遠赫連城。", "堡迥烽相見，河移浪旋生。", "無蟬嘶折柳，有寇似防兵。", "不耐饑寒迫，終誰至此行。"]'),
('df7b4d66-1c9c-4410-97fe-8415fed1056b','經故楊太尉舊居','許棠','唐','唐诗','tang','','[]','在漢信垂功，於唐道更隆。',48,'全唐诗/poet.tang.33000.json','["在漢信垂功，於唐道更隆。", "一川留古跡，多代仰高風。", "樹折巢墮鳥，階荒草覆蟲。", "行人過豈少，獨駐夕陽中。"]'),
('e87206e5-44a3-41d3-aaee-eaa71e723047','東歸次采石江','許棠','唐','唐诗','tang','','[]','東下經牛渚，依然是故關。',48,'全唐诗/poet.tang.33000.json','["東下經牛渚，依然是故關。", "客程臨岸盡，鄉思入鷗閑。", "雨漲巴來浪，雲增楚際山。", "漁翁知未達，相顧不開顏。"]'),
('9c31bec8-e8f2-4072-8537-456d66d89320','隴上書事','許棠','唐','唐诗','tang','','[]','城疊連雲壑，人家似隱居。',48,'全唐诗/poet.tang.33000.json','["城疊連雲壑，人家似隱居。", "樹飛鸚鵡衆，川下鶺鴒疎。", "滴夢關山雨，資餐隴水魚。", "誰知江徼客，此景倍相於。"]'),
('5ab0df14-2bb9-4dcc-bfb4-739b572d0677','陳情獻江西李常侍五首 一','許棠','唐','唐诗','tang','','[]','二十二三年，遊秦復滯燕。',48,'全唐诗/poet.tang.33000.json','["二十二三年，遊秦復滯燕。", "徒陪羣彥後，自苦此生前。", "徑折啼猿樹，巖荒噴月泉。", "東堂曾受薦，垂白志猶堅。"]'),
('c68e64e8-011b-419a-8de5-d507ed7eddb7','陳情獻江西李常侍五首 二','許棠','唐','唐诗','tang','','[]','淅淅復棲棲，人間只自迷。',48,'全唐诗/poet.tang.33000.json','["淅淅復棲棲，人間只自迷。", "終年愁遠道，到老去何蹊。", "始見紅葉落，又聞黃鳥啼。", "不因趨大斾，誰肯暫提攜。"]'),
('91415ba5-a44e-4573-8a08-18bd310905f2','陳情獻江西李常侍五首 三','許棠','唐','唐诗','tang','','[]','童蒙即苦辛，未識杏園春。',48,'全唐诗/poet.tang.33000.json','["童蒙即苦辛，未識杏園春。", "謾倚無爲日，還成不偶人。", "鄉程長恨遠，旅夢亦愁貧。", "天地雖云廣，殊難寄此身。"]'),
('54a87d2f-ddd3-4066-b93e-1fb229853af5','陳情獻江西李常侍五首 四','許棠','唐','唐诗','tang','','[]','春闈久已滯，秋賦又逢停。',48,'全唐诗/poet.tang.33000.json','["春闈久已滯，秋賦又逢停。", "選士疑長阻，傷時自不寧。", "秦城還逐夢，楚徼影隨形。", "此去吟雖苦，何人更肯聽。"]'),
('096298d2-37c5-4c60-b29b-c6213c5f62c6','陳情獻江西李常侍五首 五','許棠','唐','唐诗','tang','','[]','孤立時全塞，求名勢轉難。',48,'全唐诗/poet.tang.33000.json','["孤立時全塞，求名勢轉難。", "身多離下國，分合阻長安。", "越鳥啼春早，蠻花送雨寒。", "丘門沾顧重，未別欲闌干。"]'),
('5c4a11dd-8bc6-4ab3-bd36-60331c807963','經八合坂','許棠','唐','唐诗','tang','','[]','躡險入高空，初疑勢不窮。',48,'全唐诗/poet.tang.33000.json','["躡險入高空，初疑勢不窮。", "又緣千嶂盡，還共七盤同。", "下辨東流水，平隨北去鴻。", "天然無此道，應免患窮通。"]'),
('abe37e1d-3483-4bdc-b04b-8011a673681b','送友人北遊','許棠','唐','唐诗','tang','','[]','北出陰關去，何人肯待君。',48,'全唐诗/poet.tang.33000.json','["北出陰關去，何人肯待君。", "無青山擁晉，半濁水通汾。", "鴈塞雖多鴈，雲州却少雲。", "茲遊殊不惡，莫恨暫離羣。"]'),
('9c518a3a-30f3-47ad-a914-789c503e687c','登凌歊臺','許棠','唐','唐诗','tang','','[]','平蕪望已極，況復倚凌歊。',48,'全唐诗/poet.tang.33000.json','["平蕪望已極，況復倚凌歊。", "江截吳山斷，天臨楚澤遙。", "雲帆高出樹，水市迥分橋。", "立久斜陽盡，無言似寂寥。"]'),
('ef7bdab3-c1fa-4a91-85fb-d5c3bb87e21e','曲江三月三日','許棠','唐','唐诗','tang','','[]','滿國賞芳辰，飛蹄復走輪。',48,'全唐诗/poet.tang.33000.json','["滿國賞芳辰，飛蹄復走輪。", "好花皆折盡，明日恐無春。", "鳥避連雲幄，魚驚遠浪塵。", "如何當此節，獨自作愁人。"]'),
('ff5f7001-ac50-450f-bcc7-7e909043b361','贈棲白上人','許棠','唐','唐诗','tang','','[]','閑身却不閑，日日對天顏。',48,'全唐诗/poet.tang.33000.json','["閑身却不閑，日日對天顏。", "已住城中寺，難歸海上山。", "詩傳華夏外，偈布市朝間。", "欲問空門事，空門豈有關。"]'),
('bcc3faf1-36c7-43ff-ba3b-7fb0c0c3ca17','野步','許棠','唐','唐诗','tang','','[]','閑賞步易遠，野吟聲自高。',48,'全唐诗/poet.tang.33000.json','["閑賞步易遠，野吟聲自高。", "路無人到跡，林有鶴遺毛。", "物外趣都別，塵中心枉勞。", "沿溪收墮果，坐石喚飢猱。"]'),
('51fe86db-ddd1-49ab-a972-c1f0ef6907d8','過湍溝谷','許棠','唐','唐诗','tang','','[]','西去窮胡處，嵓崖境不常。',48,'全唐诗/poet.tang.33000.json','["西去窮胡處，嵓崖境不常。", "石形相對聳，天勢一條長。", "棧底鳴流水，林端歛夕陽。", "雖隨兵馬至，未免畏豺狼。"]'),
('10c4c676-d804-4200-a60b-e4ea33a3bfaa','送友人遊蜀','許棠','唐','唐诗','tang','','[]','巴興千萬尋，此去若爲心。',48,'全唐诗/poet.tang.33000.json','["巴興千萬尋，此去若爲心。", "蟋蟀既將定，獼猴應正吟。", "劒門秋斷鴈，褒谷夜多砧。", "自古西南路，艱難直至今。"]'),
('5933f9d5-1ba8-4f09-961d-9960f8632f3f','題秦州城','許棠','唐','唐诗','tang','','[]','聖澤滋遐徼，河隄四向通。',48,'全唐诗/poet.tang.33000.json','["聖澤滋遐徼，河隄四向通。", "大荒收虜帳，遺土復秦風。", "亂燒迷歸路，遙山似夢中。", "此時懷感切，極目思無窮。"]'),
('80707477-bfd6-4b6e-9215-65b38e2fbe31','寄敬亭山清越上人','許棠','唐','唐诗','tang','','[]','南朝山半寺，謝朓故鄉鄰。',48,'全唐诗/poet.tang.33000.json','["南朝山半寺，謝朓故鄉鄰。", "嶺上非無主，秋詩復有人。", "高禪星月近，野火虎狼馴。", "舊許陪閑社，終應待此身。"]'),
('f60fd50d-dd9d-48c0-92fd-6d59ba884652','秋江霽望','許棠','唐','唐诗','tang','','[]','高秋偏入望，霽景倍關情。',48,'全唐诗/poet.tang.33000.json','["高秋偏入望，霽景倍關情。", "落木滿江水，離人懷渭城。", "山高孤戍斷，野極暮天平。", "漁父時相問，羞真道姓名。"]'),
('f6fc7146-3447-47f8-9997-6314ef7f877b','隴州旅中書事寄李中丞','許棠','唐','唐诗','tang','','[]','三伏客吟過，長安未擬還。',48,'全唐诗/poet.tang.33000.json','["三伏客吟過，長安未擬還。", "蛩聲秋不動，燕別思仍閑。", "亂葉隨寒雨，孤蟾起暮關。", "經時高嶺外，來往斾旌間。"]'),
('fdd37b57-bc4c-4bcd-9d14-28ece3f4475e','秋日歸舊山','許棠','唐','唐诗','tang','','[]','山雲蟬滿樹，欲住更何安。',48,'全唐诗/poet.tang.33000.json','["山雲蟬滿樹，欲住更何安。", "上國回將晚，孤峰別自難。", "磧遙鴻未到，江近夜先寒。", "泉石雖堪戀，行人不願看。"]'),
('3247fa57-5b9c-4804-ac44-9701949916af','下黃耳盤','許棠','唐','唐诗','tang','','[]','獨下黃盤路，多虞部落連。',48,'全唐诗/poet.tang.33000.json','["獨下黃盤路，多虞部落連。", "雲晴仍著地，樹古自參天。", "亂鳥飛人上，驚麋起馬前。", "行行無郡邑，唯見虎狼煙。"]'),
('e1391a02-16b8-466f-932f-2944c267d362','旅懷','許棠','唐','唐诗','tang','','[]','終年唯旅舍，只似已無家。',48,'全唐诗/poet.tang.33000.json','["終年唯旅舍，只似已無家。", "白髮除還出，丹霄去轉賒。", "夏遊窮塞路，春醉負秦花。", "應是穹蒼意，空教老若耶。"]'),
('c3f19e1f-93f4-48e3-9eaf-eda6448207e5','題金山寺','許棠','唐','唐诗','tang','','[]','四面波濤匝，中樓日月鄰。',48,'全唐诗/poet.tang.33000.json','["四面波濤匝，中樓日月鄰。", "上窮如出世，下瞷忽驚神。", "剎礙長空鳥，船通外國人。", "房房皆疊石，風掃永無塵。"]'),
('d10cb128-2335-4fa0-8f07-11e1333d19c5','送王侍御赴宣城','許棠','唐','唐诗','tang','','[]','朝回離九陌，島外賞殘春。',48,'全唐诗/poet.tang.33000.json','["朝回離九陌，島外賞殘春。", "經宿留閑客，看雲作主人。", "時清難議隱，位重亦甘貧。", "巖洞真仙境，應休別臥鄰。"]'),
('3ba8def9-f47e-484d-b109-f34c1d8dd8ef','題汧湖二首 一','許棠','唐','唐诗','tang','','[]','偶得湖中趣，都忘隴坻愁。',48,'全唐诗/poet.tang.33000.json','["偶得湖中趣，都忘隴坻愁。", "邊聲風下鴈，楚思浪移舟。", "靜極亭連寺，涼多島近樓。", "吟遊終不厭，還似曲江頭。"]'),
('c0fd12ec-2b8c-46b4-bc64-6ecc8f771467','題汧湖二首 二','許棠','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','隴首時無事，湖邊日縱吟。',48,'全唐诗/poet.tang.33000.json','["隴首時無事，湖邊日縱吟。", "遊魚來復去，浴鳥出還沈。", "蜃氣藏孤嶼，波光到遠林。", "無人見垂釣，暗起洞庭心。"]'),
('b046e21d-7ccd-48c8-9894-3f9580aeace3','宿青山館','許棠','唐','唐诗','tang','','[]','下馬青山下，無言有所思。',48,'全唐诗/poet.tang.33000.json','["下馬青山下，無言有所思。", "雲藏李白墓，苔暗謝公詩。", "烈燒飛荒野，棲鳧宿廣陂。", "東來與西去，皆是不閑時。"]'),
('dc628054-7221-432e-b0cd-2eed4a7d4bca','宿同州厲評事舊業寄華下','許棠','唐','唐诗','tang','','[]','從戎依遠地，無日見家山。',48,'全唐诗/poet.tang.33000.json','["從戎依遠地，無日見家山。", "地近風沙處，城當甸服間。", "阻河通渭水，曲苑帶秦關。", "待月登樓夜，何人相伴閑。"]'),
('7ca2f6a2-42a5-4d5d-a9e2-a7a7478fbc9c','聞蟬十二韻','許棠','唐','唐诗','tang','','[]','造化生微物，常能應候鳴。',144,'全唐诗/poet.tang.33000.json','["造化生微物，常能應候鳴。", "初離何處樹，又發去年聲。", "未蛻唯愁動，纔飛似解驚。", "聞來鄰海徼，恨起過邊城。", "騷屑隨風遠，悠揚類雪輕。", "報秋涼漸至，嘶月思偏清。", "互默疑相荅，微搖似欲行。", "繁音人已厭，朽殼蟻猶爭。", "朝士嚴冠飾，宮嬪逞鬢名。", "亂依西日噪，多引北歸情。", "篠露凝潛吸，蛛絲忽迸縈。", "此時吟立者，不覺萬愁生。"]'),
('b65719f5-c8b3-43aa-b68a-0c305564a423','冬杪歸陵陽別業五首 一','許棠','唐','唐诗','tang','','[]','無媒歸別業，所向自乖心。',48,'全唐诗/poet.tang.33000.json','["無媒歸別業，所向自乖心。", "閭里故人少，田園荒草深。", "浪翻全失岸，竹迸別成林。", "鷗鳥猶相識，時來聽苦吟。"]'),
('a2b0e790-6d63-46ac-9250-6ff3edf88f86','冬杪歸陵陽別業五首 二','許棠','唐','唐诗','tang','','[]','眠雲終未遂，策馬暫休期。',48,'全唐诗/poet.tang.33000.json','["眠雲終未遂，策馬暫休期。", "上國勞魂夢，中心甚別離。", "冰封巖溜斷，雪壓砌松欹。", "骨肉嗟名晚，看歸却淚垂。"]'),
('6fc34297-8e44-420b-8b26-92efaaba2a22','冬杪歸陵陽別業五首 三','許棠','唐','唐诗','tang','','[]','學劒雖無術，吟詩似有魔。',48,'全唐诗/poet.tang.33000.json','["學劒雖無術，吟詩似有魔。", "已貧甘事晚，臨老愛閑多。", "雞犬唯隨鹿，兒童只衣簑。", "時因尋野叟，狂醉復狂歌。"]'),
('9a9238e8-53ff-4beb-88b9-b5ab6a21e1fb','冬杪歸陵陽別業五首 四','許棠','唐','唐诗','tang','','[]','鄉國亂離後，交親半旅遊。',48,'全唐诗/poet.tang.33000.json','["鄉國亂離後，交親半旅遊。", "遠聞誠可念，歸見豈無愁。", "敗葦迷荒徑，寒簑沒壞舟。", "衡門終不掩，倚杖看波流。"]'),
('dfaf9310-de9a-44da-9cdb-3052d6c140ea','冬杪歸陵陽別業五首 五','許棠','唐','唐诗','tang','','[]','遊秦復滯燕，不覺近衰年。',48,'全唐诗/poet.tang.33000.json','["遊秦復滯燕，不覺近衰年。", "旅貌同柴毀，行衣對骨穿。", "籬寒多啄雀，木落斷浮煙。", "楚夜聞鳴鴈，猶疑在塞天。"]'),
('70b09137-def5-4523-9a53-99e5ea78da53','送王侍御赴宣城','許棠','唐','唐诗','tang','','[]','戴豸却驅雞，東南上句溪。',48,'全唐诗/poet.tang.33000.json','["戴豸却驅雞，東南上句溪。", "路過金谷口，帆轉石城西。", "水樹連天暗，山禽繞郡啼。", "江人諳舊化，那復俟招攜。"]'),
('964b60ab-3b87-4c2e-b8c6-24bc24ae591b','春日烏延道中','許棠','唐','唐诗','tang','','[]','邊窮厄未窮，復此逐歸鴻。',48,'全唐诗/poet.tang.33000.json','["邊窮厄未窮，復此逐歸鴻。", "去路多相似，行人半不同。", "山川藏北狄，草木背東風。", "虛負男兒志，無因立戰功。"]'),
('0a417fe1-2881-48e5-a0cf-4bf8bba80c9d','寄華陰劉拾遺','許棠','唐','唐诗','tang','','[]','堅心持諫諍，自古亦艱難。',48,'全唐诗/poet.tang.33000.json','["堅心持諫諍，自古亦艱難。", "寄邑雖行化，眠雲似去官。", "河分中野斷，岳入半天寒。", "瀑布冰成日，誰陪吟復看。"]'),
('218443b5-5d0b-4b72-8364-f60953ec1581','憶江南','許棠','唐','唐诗','tang','','[]','南楚西秦遠，名遲別歲深。',48,'全唐诗/poet.tang.33000.json','["南楚西秦遠，名遲別歲深。", "欲歸難遂去，閑憶自成吟。", "雷電閑傾雨，猿猱鬬墮林。", "眠雲機尚在，未忍負初心。"]'),
('bea1cfd6-14e5-40d4-ab2e-1ec1b1db96df','送前汝州李侍御罷歸宣城','許棠','唐','唐诗','tang','','[]','吟詩早得名，戴豸又加榮。',48,'全唐诗/poet.tang.33000.json','["吟詩早得名，戴豸又加榮。", "下國閑歸去，他人少此情。", "雲移寒嶠出，燒夾夜江明。", "重引池塘思，還登謝朓城。"]'),
('043cdcf0-7296-4ca6-a692-7ab91f2a1138','失題','許棠','唐','唐诗','tang','','[]','獨夜長城下，孤吟近北辰。',48,'全唐诗/poet.tang.33000.json','["獨夜長城下，孤吟近北辰。", "半天初去鴈，窮磧遠來人。", "月黯氛埃積，風羶帳幕鄰。", "惟聞防虜寇，不語暗傷神。"]'),
('3eacfde8-c696-4716-9ef1-4704b6e209fc','送裴拾遺宰下邽','許棠','唐','唐诗','tang','','[]','受謫因延諫，茲行不出關。',48,'全唐诗/poet.tang.33000.json','["受謫因延諫，茲行不出關。", "直廬辭玉陛，上馬向仙山。", "地古桑麻廣，城偏僕御閑。", "縣齋高枕臥，猶夢犯天顏。"]'),
('a13db476-8d88-4257-ba3a-4511d057aaec','隗囂宮晚望','許棠','唐','唐诗','tang','','[]','西顧伊蘭近，方驚滯極邊。',48,'全唐诗/poet.tang.33000.json','["西顧伊蘭近，方驚滯極邊。", "水隨空谷轉，山向夕陽偏。", "磧鳥多依地，胡雲不滿天。", "秋風動衰草，只覺犬羊羶。"]'),
('066a2bda-265a-47fa-a4a4-5eb830613e90','江上行','許棠','唐','唐诗','tang','','[]','片席隨高鳥，連天積浪間。',48,'全唐诗/poet.tang.33000.json','["片席隨高鳥，連天積浪間。", "葦寬雲不匝，風廣雨無閑。", "戍影臨孤浦，潮痕在半山。", "東原歸未得，荏苒滯江關。"]'),
('e6234fd0-ce24-48d1-94f0-5f594f58b87a','登山','許棠','唐','唐诗','tang','','[]','信步上鳥道，不知身忽高。',48,'全唐诗/poet.tang.33000.json','["信步上鳥道，不知身忽高。", "近空無世界，當楚見波濤。", "頂峭松多瘦，崖懸石盡牢。", "獼猴呼獨散，隔水向人號。"]'),
('13b4dcb3-7b8a-49a7-90f6-d3677351e5ee','哭宣城元徵君','許棠','唐','唐诗','tang','','[]','高眠終不起，遠趣固難知。',48,'全唐诗/poet.tang.33000.json','["高眠終不起，遠趣固難知。", "琴劒今無主，園林舊許誰。", "苔封僧坐石，葦漲鶴翹池。", "後代傳青史，方欽道德垂。"]'),
('9bc8a755-e892-47e1-91f7-a6d342e5cc58','寄建州姚員外','許棠','唐','唐诗','tang','','[]','誣譖遭遐謫，明君即自知。',48,'全唐诗/poet.tang.33000.json','["誣譖遭遐謫，明君即自知。", "鄉遙辭劒外，身獨向天涯。", "嶺堠蠻雲積，閩空瘴雨垂。", "南來終不遂，日探北歸期。"]'),
('53947303-41a6-4709-bef4-5ecff9eb7a0f','送厲校書從事鳯翔','許棠','唐','唐诗','tang','','[]','赴辟依丞相，超榮事豈同。',48,'全唐诗/poet.tang.33000.json','["赴辟依丞相，超榮事豈同。", "城池當隴右，山水是關中。", "日有來巴使，秋高出塞鴻。", "旬休隨大斾，應到九成宮。"]'),
('ca4c6d04-8ac9-40bc-b92d-5cd59b944f6f','春夜同厲文學先輩會宿','許棠','唐','唐诗','tang','','[]','江漢久分路，京關重聚吟。',48,'全唐诗/poet.tang.33000.json','["江漢久分路，京關重聚吟。", "更爲他夜約，方盡昔年心。", "月隔明河遠，花藏宿鳥深。", "無眠將及曙，多是說山陰。"]'),
('b65dee2f-f4d0-4819-bd29-e136eb668c40','長安書情','許棠','唐','唐诗','tang','','[]','疎散過閑人，同人不在秦。',48,'全唐诗/poet.tang.33000.json','["疎散過閑人，同人不在秦。", "近來驚白髮，方解惜青春。", "僻寺居將遍，權門到絕因。", "行藏如此輩，何以謂謀身。"]'),
('2c587eba-b94f-41ea-8a36-700c28a8f76d','過故洛城','許棠','唐','唐诗','tang','','[]','七百數還窮，城池一旦空。',36,'全唐诗/poet.tang.33000.json','["七百數還窮，城池一旦空。", "夕陽唯照草，危堞不勝風。", "岸斷河聲別，田荒野色同。"]'),
('aa583569-b65d-4ba3-b4ee-637bdc3b64fc','寄廬山賈處士','許棠','唐','唐诗','tang','','["\u5e90\u5c71"]','時泰亦高眠，人皆謂不然。',48,'全唐诗/poet.tang.33000.json','["時泰亦高眠，人皆謂不然。", "窮經休望辟，餌朮止期仙。", "彭蠡波涵月，爐峰雪照天。", "常聞風雨夜，到曉在漁船。"]'),
('30962e66-2d7d-446b-852c-f00d11ba7f13','下第東歸留別鄭侍郎','許棠','唐','唐诗','tang','','[]','無才副至公，豈是命難通。',48,'全唐诗/poet.tang.33000.json','["無才副至公，豈是命難通。", "分合吟詩老，家宜逐浪空。", "別心懸闕下，歸念極吳東。", "唯畏重回日，初情恐不同。"]'),
('5fb53543-d3f8-4ff5-9e8d-65e72cce228d','泗上早發','許棠','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','獨起無人見，長河夜泛時。',48,'全唐诗/poet.tang.33000.json','["獨起無人見，長河夜泛時。", "平蕪疑自動，落月似相隨。", "楚外離空早，關西去已遲。", "漁歌聞不絕，却軫洞庭思。"]'),
('5c63d051-2a3f-4fde-b05c-7cc089562837','贈天台僧','許棠','唐','唐诗','tang','','[]','赤城霞外寺，不忘舊登年。',48,'全唐诗/poet.tang.33000.json','["赤城霞外寺，不忘舊登年。", "石上吟分海，樓中語近天。", "重遊空有夢，再隱定無緣。", "獨夜休行道，星辰靜照禪。"]'),
('269c5fd4-1215-4486-8f89-6bcf83085d53','冬夜與友人會宿','許棠','唐','唐诗','tang','','[]','君初離鴈塞，我久滯雕陰。',48,'全唐诗/poet.tang.33000.json','["君初離鴈塞，我久滯雕陰。", "隔閏俱勞夢，通宵各話心。", "禁風吹漏出，原樹映星沉。", "白晝常多事，無妨到曉吟。"]'),
('a17a881c-c59c-4166-a2dc-bf5c763c4609','送元遂上人歸吳中','許棠','唐','唐诗','tang','','[]','落髪在王畿，承恩著紫衣。',48,'全唐诗/poet.tang.33000.json','["落髪在王畿，承恩著紫衣。", "印心誰受請，講疏自攜歸。", "泛浦龍驚錫，禪雲虎繞扉。", "吳中知久別，菴樹想成圍。"]'),
('a35f0577-ee8f-4f1e-9006-598450ff168d','贈志空上人','許棠','唐','唐诗','tang','','[]','了了在心中，南宗與北宗。',48,'全唐诗/poet.tang.33000.json','["了了在心中，南宗與北宗。", "行高無外染，骨瘦是真容。", "飯野盂埋雪，禪雲杖倚松。", "常修不住性，必擬老何峰。"]'),
('6abf3000-e6b7-4e12-a5a6-0d5a24083e70','邊城晚望','許棠','唐','唐诗','tang','','[]','廣漠杳無窮，孤城四面空。',48,'全唐诗/poet.tang.33000.json','["廣漠杳無窮，孤城四面空。", "馬行高磧上，日墮迥沙中。", "逼曉人移帳，當川樹列風。", "迢迢河外路，知直去崆峒。"]'),
('b4da124a-1fbf-4a48-bff9-51614c235346','汴上暮秋','許棠','唐','唐诗','tang','','[]','獨立長堤上，西風滿客衣。',48,'全唐诗/poet.tang.33000.json','["獨立長堤上，西風滿客衣。", "日臨秋草廣，山接遠天微。", "岸葉隨波盡，沙雲與鳥飛。", "秦人寧有素，去意自知歸。"]'),
('ba2982e9-cf10-4393-9a1c-6b15947f4db0','春日言懷','許棠','唐','唐诗','tang','','[]','東風萬物新，獨未到幽人。',48,'全唐诗/poet.tang.33000.json','["東風萬物新，獨未到幽人。", "賦命自多蹇，陽和非不均。", "五陵三月暮，百越一家貧。", "早悞閑眠處，無愁異此身。"]'),
('bed42ee7-4f0f-4138-ab25-2dade6390175','奉天寒食書事','許棠','唐','唐诗','tang','','[]','處處無煙火，人家似暫空。',48,'全唐诗/poet.tang.33000.json','["處處無煙火，人家似暫空。", "曉林花落雨，寒谷鳥啼風。", "故里芳洲外，殘春甸服中。", "誰知獨西去，步步泣途窮。"]'),
('e78075d0-f785-4652-ba84-179cde9e25d9','長安寓居','許棠','唐','唐诗','tang','','[]','貧寄帝城居，交朋日自疎。',48,'全唐诗/poet.tang.33000.json','["貧寄帝城居，交朋日自疎。", "愁迎離磧鴈，夢逐出關書。", "經雨蟬聲盡，兼風杵韻餘。", "誰知江徼塞，所憶在樵漁。"]'),
('19dde813-d122-454b-991c-998dc508d3dd','寫懷','許棠','唐','唐诗','tang','','[]','此生居此世，堪笑復堪悲。',48,'全唐诗/poet.tang.33000.json','["此生居此世，堪笑復堪悲。", "在處有岐路，何人無別離。", "長當多難日，愁過少年時。", "窮達都判了，休閑鑷白髭。"]'),
('a9b968e6-ce41-4ed5-bfed-9815700ada3d','白菊','許棠','唐','唐诗','tang','','[]','所尚雪霜姿，非關落帽期。',48,'全唐诗/poet.tang.33000.json','["所尚雪霜姿，非關落帽期。", "香飄風外別，影到月中疑。", "發在林彫後，繁當露冷時。", "人間稀有此，自古乃無詩。"]'),
('15c54cae-3f4f-4dc9-8751-a72db00b428d','中秋夜對月','許棠','唐','唐诗','tang','','[]','月月勢皆圓，中秋朗最偏。',48,'全唐诗/poet.tang.33000.json','["月月勢皆圓，中秋朗最偏。", "萬方期一夕，到曉是經年。", "影蔽星芒盡，光分物狀全。", "惟應苦吟者，目斷向遙天。"]'),
('f78c11ea-f427-4c7d-b4d4-e30ee6cc5643','陪郢州張員外宴白雪樓','許棠','唐','唐诗','tang','','[]','高情日日閑，多宴雪樓間。',48,'全唐诗/poet.tang.33000.json','["高情日日閑，多宴雪樓間。", "灑檻江干雨，當筵天際山。", "帶帆分浪色，駐樂話朝班。", "豈料羈浮者，樽前得解顏。"]'),
('5787c1fc-a94e-40da-b988-8298bad288ee','和薛侍御題興善寺松','許棠','唐','唐诗','tang','','[]','何年斸到城，滿國響高名。',48,'全唐诗/poet.tang.33000.json','["何年斸到城，滿國響高名。", "半寺陰常匝，鄰坊景亦清。", "代多無朽勢，風定有餘聲。", "自得天然狀，非同澗底生。"]'),
('86b7fce3-199e-45e9-b133-d495e9d32835','題鄭侍郎巖隱十韻','許棠','唐','唐诗','tang','','[]','朝退常歸隱，真修大隱情。',120,'全唐诗/poet.tang.33000.json','["朝退常歸隱，真修大隱情。", "園林應得趣，巖谷自爲名。", "野步難尋寺，閑吟少在城。", "樹藏幽洞黑，花照遠村明。", "海石分湖路，風泉遰雨聲。", "性高憐散逸，官達厭公卿。", "架引藤重長，階延笋迸生。", "青門無到客，紫閣有來鶯。", "物外身雖隱，區中望本清。", "終難依此境，坐臥避鈞衡。"]'),
('4f011c51-8964-48f2-944d-e7fc3a1cdd14','宿靈山蘭若','許棠','唐','唐诗','tang','','[]','江心天半寺，一夕萬緣空。',48,'全唐诗/poet.tang.33000.json','["江心天半寺，一夕萬緣空。", "地出浮雲上，星搖積浪中。", "滴漚垂閣雨，吹檜送帆風。", "旦夕聞清磬，唯應是釣翁。"]'),
('00e09799-b2c9-4eb0-90ac-82766c7402fe','親仁里雙鷺','許棠','唐','唐诗','tang','','[]','雙去雙來日已頻，只應知我是江人。',64,'全唐诗/poet.tang.33000.json','["雙去雙來日已頻，只應知我是江人。", "對欹雪頂思尋水，更振霜翎恐染塵。", "三楚幾時初失侶，五陵何樹又棲身。", "天然不與凡禽類，傍砌聽吟性自馴。"]'),
('2daa2155-cd32-40c9-9283-0941a17e0745','成紀書事二首 一','許棠','唐','唐诗','tang','','[]','東吳遠別客西秦，懷舊傷時暗灑巾。',64,'全唐诗/poet.tang.33000.json','["東吳遠別客西秦，懷舊傷時暗灑巾。", "滿野多成無主塚，防邊半是異鄉人。", "山河再闊千餘里，城市曾經一百春。", "閑與將軍議戎事，伊蘭猶未絕胡塵。"]'),
('016a4ee1-0e71-4fcf-9b97-89ccba275655','成紀書事二首 二','許棠','唐','唐诗','tang','','[]','蹉跎遠入犬羊中，荏苒將成白首翁。',64,'全唐诗/poet.tang.33000.json','["蹉跎遠入犬羊中，荏苒將成白首翁。", "三楚田園歸未得，五原岐路去無窮。", "天垂大野鵰盤草，月落孤城角嘯風。", "難問開元向前事，依稀猶認隗囂宮。"]'),
('5a79304b-d2a1-4624-8721-3d1454d2406d','秦中遇友人','許棠','唐','唐诗','tang','','[]','半生南走復西馳，愁過楊朱罷泣岐。',64,'全唐诗/poet.tang.33000.json','["半生南走復西馳，愁過楊朱罷泣岐。", "遠夢亦羞歸海徼，貧遊多是滯邊陲。", "胡雲不聚風無定，隴路難行棧更危。", "旦暮唯聞語征戰，看看已欲廢吟詩。"]'),
('425ef6f9-c6a9-4b14-8dcb-4aff9d68c360','過分水嶺','許棠','唐','唐诗','tang','','[]','隴山高共鳥行齊，瞰險盤空甚躡梯。',64,'全唐诗/poet.tang.33000.json','["隴山高共鳥行齊，瞰險盤空甚躡梯。", "雲勢崩騰時向背，水聲嗚咽若東西。", "風兼雨氣吹人面，石帶冰棱礙馬蹄。", "此去秦川無別路，隔崖窮谷却難迷。"]'),
('38f584ef-a7b5-4308-bdb7-4ed9c2b4286a','講德陳情上淮南李僕射八首 一','許棠','唐','唐诗','tang','','[]','天降賢人佐聖時，自然聲教滿華夷。',64,'全唐诗/poet.tang.33000.json','["天降賢人佐聖時，自然聲教滿華夷。", "英明不獨中朝仰，清重兼聞外國知。", "涼夜酒醒多對月，曉庭公退半吟詩。", "梁城東下雖經戰，風俗猶傳守舊規。"]'),
('e040e802-2855-49c0-9c97-f6b60c21361c','講德陳情上淮南李僕射八首 二','許棠','唐','唐诗','tang','','[]','多朝軒冕冠乾坤，四海皆推聖最尊。',64,'全唐诗/poet.tang.33000.json','["多朝軒冕冠乾坤，四海皆推聖最尊。", "楚玉已曾分卞玉，膺門依舊是龍門。", "筵開樂振高雲動，城掩鼙收落日昏。", "嘗念蒼生如赤子，九州無處不沾恩。"]'),
('72b7bb8c-4fdd-484d-b17c-1585dde29399','講德陳情上淮南李僕射八首 三','許棠','唐','唐诗','tang','','[]','未領春闈望早清，況聯戎閫控強兵。',64,'全唐诗/poet.tang.33000.json','["未領春闈望早清，況聯戎閫控強兵。", "風威遍布江山靜，教化高同日月明。", "九郡竟歌兼煮海，四方皆得共和羹。", "東南自此全無事，只爲期年政已成。"]'),
('a0b33d72-8eda-4c1c-9a3f-3cb2466f31d6','講德陳情上淮南李僕射八首 四','許棠','唐','唐诗','tang','','[]','帝念淮堧疫疹頻，牢籠山海委名臣。',64,'全唐诗/poet.tang.33000.json','["帝念淮堧疫疹頻，牢籠山海委名臣。", "古來比德由無侶，當代同途豈有人。", "夜宴獨吟梁苑月，朝遊重見廣陵春。", "多年疲瘵全蘇息，須到謳謠日滿秦。"]'),
('40ae41d7-92e6-4144-8bcb-0698ac15ad0b','講德陳情上淮南李僕射八首 五','許棠','唐','唐诗','tang','','[]','三紀吟詩望一名，丹霄待得白頭成。',64,'全唐诗/poet.tang.33000.json','["三紀吟詩望一名，丹霄待得白頭成。", "已期到老還沾祿，無復偷閑却養生。", "當宴每垂聽樂淚，望雲長起憶山情。", "朱門舊是登龍客，初脫魚鱗膽尚驚。"]'),
('16f5a26f-e70f-4d09-90dc-77fca2345ecc','講德陳情上淮南李僕射八首 六','許棠','唐','唐诗','tang','','[]','東來淮海拜旌旟，不把公卿一字書。',64,'全唐诗/poet.tang.33000.json','["東來淮海拜旌旟，不把公卿一字書。", "曾侍晚齋吟對雪，又容華館食兼魚。", "孤微自省恩非次，際會誰知分有餘。", "唯耻舊橋題處在，榮歸無計似相如。"]'),
('5555e848-95bb-495a-9cac-006bdffcadc3','講德陳情上淮南李僕射八首 七','許棠','唐','唐诗','tang','','[]','平生南北逐蓬飄，待得名成鬢已彫。',64,'全唐诗/poet.tang.33000.json','["平生南北逐蓬飄，待得名成鬢已彫。", "寒浦一從拋釣艇，舊林無處認風飆。", "程途雖喜關河盡，時節猶驚骨肉遙。", "愁策羸蹄更歸去，亂山流水滿翻潮。"]'),
('eb68444e-2252-4083-b9bc-5276dce424e1','講德陳情上淮南李僕射八首 八','許棠','唐','唐诗','tang','','[]','丹霄空把桂枝歸，白首依前着布衣。',64,'全唐诗/poet.tang.33000.json','["丹霄空把桂枝歸，白首依前着布衣。", "當路公卿誰見待，故鄉親愛自疑非。", "東風乍喜還滄海，棲旅終愁出翠微。", "應念無媒居選限，二年須更守漁磯。"]'),
('ef3be07d-63fe-47e3-86be-7cb8e3d26c69','獻獨孤尚書','許棠','唐','唐诗','tang','','[]','虛拋南楚滯西秦，白首依前衣白身。',64,'全唐诗/poet.tang.33000.json','["虛拋南楚滯西秦，白首依前衣白身。", "退鷁已經三十載，登龍曾見一千人。", "魂離爲役詩篇苦，淚竭緣嗟骨相貧。", "今日鞠躬高斾下，欲傾肝膽杳無因。"]'),
('141ab2c2-5d74-453a-aba3-94a1f1b6c23d','將過單于','許棠','唐','唐诗','tang','','[]','荒磧連天堡戍稀，日憂蕃寇却忘機。',64,'全唐诗/poet.tang.33000.json','["荒磧連天堡戍稀，日憂蕃寇却忘機。", "江山不到處皆到，隴鴈已歸時未歸。", "行李亦須攜戰器，趨迎當便著戎衣。", "幷州去路殊迢遰，風雨何當達近畿。"]'),
('30bf66c7-df85-4c06-bdca-66fb75e56028','貞女祠','許棠','唐','唐诗','tang','','[]','何穴藏貞骨，荒祠見舊顏。',48,'全唐诗/poet.tang.33000.json','["何穴藏貞骨，荒祠見舊顏。", "精靈應自在，雲雨不相關。", "落石泉多咽，無風樹盡閑。", "唯疑千古後，爲瑞向人間。"]'),
('dfe90a3a-14c7-45f9-aaa6-2532610d3e37','宿華山','許棠','唐','唐诗','tang','','[]','異境良難測，非仙豈合遊。',48,'全唐诗/poet.tang.33000.json','["異境良難測，非仙豈合遊。", "星辰方滿岳，風雨忽移舟。", "噴月泉垂壁，棲松鶴在樓。", "因知休養處，不必在嵩丘。"]'),
('3c1e25e7-2ecb-4804-bb6e-338990f3106d','送張員外西川從事','許棠','唐','唐诗','tang','','[]','爲郎不入朝，自是赴嘉招。',48,'全唐诗/poet.tang.33000.json','["爲郎不入朝，自是赴嘉招。", "豸角初離首，金章已在腰。", "劒橫陰綠野，棧響近丹霄。", "迎驛應相續，懸愁去路遙。"]'),
('da9e3a7d-76f6-450f-8fa0-b23a2588282a','題慈恩寺元遂上人院','許棠','唐','唐诗','tang','','[]','竹檻匝回廊，城中似外方。',48,'全唐诗/poet.tang.33000.json','["竹檻匝回廊，城中似外方。", "月雲開作片，枝鳥立成行。", "徑接河源潤，庭容塔影涼。", "天台頻去說，誰占最高房。"]'),
('86b1d624-848d-4497-b9eb-4f8090b01e9d','送杜倉曹往滄洲覲叔常侍','許棠','唐','唐诗','tang','','[]','浮陽橫巨浸，南巷擁旌旃。',48,'全唐诗/poet.tang.33000.json','["浮陽橫巨浸，南巷擁旌旃。", "別帶秦城雨，行聞魏國蟬。", "磧鴻來每後，朝日見常先。", "東鄙雲霞廣，高林間水天。"]'),
('b7b92379-60e2-4202-abe1-1f60edaa379c','雕陰道中作','許棠','唐','唐诗','tang','','[]','五月綏州北，途程少鬱蒸。',48,'全唐诗/poet.tang.33000.json','["五月綏州北，途程少鬱蒸。", "馬依羶草聚，人抱濁河澄。", "蹟固長城壘，冤深太子陵。", "往來經此地，悲苦有誰能。"]'),
('67f46f04-5812-4986-8569-0cf288a67869','留別從弟郴','許棠','唐','唐诗','tang','','[]','同承太嶽胤，俱值太平時。',48,'全唐诗/poet.tang.33000.json','["同承太嶽胤，俱值太平時。", "丹陛懷趨計，滄洲負去期。", "久貧成蹭蹬，多病惜支離。", "宗分兼交分，吾知汝亦知。"]'),
('688e565c-a8c4-4e76-bfaf-2774e7a15531','尋山','許棠','唐','唐诗','tang','','[]','躡履復支筇，深山草木中。',48,'全唐诗/poet.tang.33000.json','["躡履復支筇，深山草木中。", "隔溪遙避虎，當塢忽聞鐘。", "落葉多相似，幽禽半不同。", "羣猱呼却散，如此異林翁。"]'),
('8e5f10c9-8d99-47a5-9e5e-627953a61201','送徐侍御充南詔判官','許棠','唐','唐诗','tang','','["\u957f\u6c5f"]','西去安夷落，乘軺從節行。',96,'全唐诗/poet.tang.33000.json','["西去安夷落，乘軺從節行。", "彤庭傳聖旨，異城化戎情。", "瘴路窮巴徼，蠻川過嶠城。", "地偏風自雜，天漏月稀明。", "危棧連空動，長江到底清。", "笑宜防狒狒，言好聽猩猩。", "撫論如敦行，歸情自合盟。", "迴期佩印綬，何更見新正。"]'),
('e26c79d6-e596-4074-a733-738ca69bd464','送省玄上人歸江東','許棠','唐','唐诗','tang','','[]','釋律周儒禮，嚴持用戒身。',48,'全唐诗/poet.tang.33000.json','["釋律周儒禮，嚴持用戒身。", "安禪思剡石，留偈別都人。", "雨合吳江黑，潮移海路新。", "缾盂自此去，應不更還秦。"]'),
('7c721d80-41c2-4095-863e-16d5bcd1687c','送劉校書遊東魯','許棠','唐','唐诗','tang','','[]','內閣勞讎校，東邦忽縱遊。',48,'全唐诗/poet.tang.33000.json','["內閣勞讎校，東邦忽縱遊。", "才編精二雅，分合遇諸侯。", "暗海龜蒙雨，連空趙魏秋。", "如經麟見處，駐馬瞰荒丘。"]'),
('01a227a6-77bf-4939-a217-9bf9ec7f41ec','送金吾侍御奉使日東','許棠','唐','唐诗','tang','','[]','還鄉兼作使，到日倍榮親。',48,'全唐诗/poet.tang.33000.json','["還鄉兼作使，到日倍榮親。", "向化雖多國，如公有幾人。", "孤山無返照，積水合蒼旻。", "膝下知難住，金章已繫身。"]'),
('ca39a67e-23b4-446e-8416-4384f3e7c027','題甘露寺','許棠','唐','唐诗','tang','','[]','丹檻拂丹霄，人寰下瞰遙。',122,'全唐诗/poet.tang.33000.json','["丹檻拂丹霄，人寰下瞰遙。", "何年增造化，萬古出塵囂。", "地勢盤三楚，江聲換幾朝。", "滿欄皆異藥，到頂盡飛橋。", "澤廣方雲夢，山孤數沃焦。", "中[宵]霞始散，經臘木稀凋。", "鐸動天風度，窗明海氣消。", "帶鼙分迥堞，當日辨翻潮。", "鳥去沉葭菼，帆來映泬㵳。", "浮生自多事，無計免迴鑣。"]'),
('af4226f9-84bb-4c36-bf9f-f168379c4a07','冬夜懷真里友人會宿','許棠','唐','唐诗','tang','','[]','靜語與高吟，搜神又爽心。',48,'全唐诗/poet.tang.33000.json','["靜語與高吟，搜神又爽心。", "各來依帝里，相對似山陰。", "漏永星河沒，堂寒月彩深。", "從容不易到，莫惜曙鐘侵。"]'),
('b80e109a-8bda-445d-b83f-b5fc8236edf8','陪友人夏夜對月','許棠','唐','唐诗','tang','','[]','後伏中宵月，高秋滿魄齊。',48,'全唐诗/poet.tang.33000.json','["後伏中宵月，高秋滿魄齊。", "輪移仙掌外，影下玉繩西。", "蟬雀飛多悞，星螢出自迷。", "煩蒸驚頓絕，吟翫畏聞雞。"]'),
('74d850b7-e5fa-4bc9-9291-cca36a0af3c8','送從弟籌任告成尉','許棠','唐','唐诗','tang','','[]','海上從戎罷，嵩陽佐縣初。',48,'全唐诗/poet.tang.33000.json','["海上從戎罷，嵩陽佐縣初。", "故人皆羨去，吾祖舊曾居。", "地古多生藥，溪靈不聚魚。", "唯應尋隱者，閑寺講仙書。"]'),
('5eaceacf-41ce-4ed0-9683-352578db792b','秋日陪陸校書遊玉泉','許棠','唐','唐诗','tang','','[]','共愛泉源異，頻來不覺勞。',48,'全唐诗/poet.tang.33000.json','["共愛泉源異，頻來不覺勞。", "散光垂草細，繁響出風高。", "沫滯潭花片，沙遺浴鳥毛。", "塵間喧與悶，須向此中逃。"]'),
('fe1b49fd-0e0a-4f8a-86b0-3436e286fac7','送防州鄔員外','許棠','唐','唐诗','tang','','[]','千溪與萬嶂，繚繞復崢嶸。',48,'全唐诗/poet.tang.33000.json','["千溪與萬嶂，繚繞復崢嶸。", "太守勞車馬，何從駐斾旌。", "椒香近滿郭，漆貨遠通京。", "唯滌雙塵耳，東南聽政聲。"]'),
('df80663c-eb58-410d-b2f5-0f7188bde5ee','過穆陵關','許棠','唐','唐诗','tang','','[]','荒關無守吏，亦耻白衣過。',48,'全唐诗/poet.tang.33000.json','["荒關無守吏，亦耻白衣過。", "地廣人耕絕，天寒鴈下多。", "東西方自感，雨雪更相和。", "日暮聊攄思，搖鞭一放歌。"]'),
('b91b959f-e79d-4b87-b91e-c96b1c352183','江上遇友人','許棠','唐','唐诗','tang','','[]','闕下分離日，杏園花半開。',48,'全唐诗/poet.tang.33000.json','["闕下分離日，杏園花半開。", "江邊相值夜，榆塞鴈初來。", "坐久河沉斗，吟長月浸杯。", "鱸魚非不戀，共有客程催。"]'),
('14e6f1dc-f2be-4a99-90bc-cbdd55dc7b5e','憶宛陵舊居','許棠','唐','唐诗','tang','','[]','舊憶陵陽北，林園近板橋。',48,'全唐诗/poet.tang.33000.json','["舊憶陵陽北，林園近板橋。", "江晴帆影滿，野迥鶴聲遙。", "鳥徑通山市，汀扉上海潮。", "秦城歸去夢，夜夜到漁樵。"]'),
('7ab529ff-af54-4265-b1a6-560d2fbfc749','題聞琴館','許棠','唐','唐诗','tang','','[]','城非宓賤邑，館亦號聞琴。',48,'全唐诗/poet.tang.33000.json','["城非宓賤邑，館亦號聞琴。", "乃是前賢意，常留化俗心。", "代公存綠綺，誰更寄清音。", "此迹應無改，寥寥畢古今。"]'),
('923eca15-6f96-4c09-829f-642286c17dd6','寄江上弟妹','許棠','唐','唐诗','tang','','[]','無成歸未得，不是不謀歸。',48,'全唐诗/poet.tang.33000.json','["無成歸未得，不是不謀歸。", "垂老登雲路，猶勝守釣磯。", "大荒身去數，窮海信來稀。", "孤立皆難進，非關命獨違。"]'),
('1cfd5abd-1077-4f6a-a88e-aab15d17b448','題李昌符豐樂幽居','許棠','唐','唐诗','tang','','[]','詩家依闕下，野景似山中。',48,'全唐诗/poet.tang.33000.json','["詩家依闕下，野景似山中。", "蘭菊俱含露，杉梧爲奏風。", "破門韋曲對，淺岸御溝通。", "莫歎連年屈，君須遇至公。"]'),
('ef3977d7-0456-4269-aa94-313158c14c11','青山晚望','許棠','唐','唐诗','tang','','[]','昔人懷感處，此地倍魂消。',48,'全唐诗/poet.tang.33000.json','["昔人懷感處，此地倍魂消。", "四海經搖落，三吳正寂寥。", "風移殘燒遠，帆帶夕陽遙。", "欲繼前賢跡，誰能似隱招。"]'),
('ab5d50cd-88b8-4977-9935-1f405c00dc58','宣城送進士鄭徽赴舉','許棠','唐','唐诗','tang','','[]','長安去是歸，上馬肯沾衣。',48,'全唐诗/poet.tang.33000.json','["長安去是歸，上馬肯沾衣。", "水國車通少，秦人楚薦稀。", "鴻方離北鄙，葉下已西畿。", "好整丹霄步，知音在紫微。"]'),
('85aea06b-20d9-4d9a-8394-798cd69b3c7f','言懷','許棠','唐','唐诗','tang','','[]','萬事不關心，終朝但苦吟。',48,'全唐诗/poet.tang.33000.json','["萬事不關心，終朝但苦吟。", "久貧慙負債，漸老愛山深。", "日月銷天外，帆檣棄海陰。", "榮枯應已定，無復繫浮沉。"]'),
('eaf4bcae-a0b5-403c-bab1-feca26fd8a5d','汴河十二韻','許棠','唐','唐诗','tang','','[]','昔年開汴水，元應別有由。',144,'全唐诗/poet.tang.33000.json','["昔年開汴水，元應別有由。", "或兼通楚塞，寧獨爲揚州。", "直斷平蕪色，橫分積石流。", "所思千里便，豈計萬方憂。", "首甚資功濟，終難弭宴遊。", "空懷龍舸下，不見錦帆收。", "浪倒長汀柳，風欹遠岸樓。", "奔逾懷許竭，澄徹泗濱休。", "路要多行客，魚稀少釣舟。", "日開天際晚，鴈合磧西秋。", "一派注滄海，幾人生白頭。", "常期身事畢，於此泳東浮。"]'),
('176d8f52-e01b-4d31-9aed-993aa81c1d0c','旅中送人歸九華','許棠','唐','唐诗','tang','','[]','分與仙山背，多年負翠微。',48,'全唐诗/poet.tang.33000.json','["分與仙山背，多年負翠微。", "無因隨鹿去，只是送人歸。", "頂木晴摩日，根嵐曉潤衣。", "會於猨鳥外，相對掩高扉。"]'),
('74c7e56b-5129-4da4-9c8b-b911a3e6f21b','送友人歸江南','許棠','唐','唐诗','tang','','[]','皇州五更鼓，月落西南維。',36,'全唐诗/poet.tang.33000.json','["皇州五更鼓，月落西南維。", "此時有行客，別我孤舟歸。", "上國身無主，下第誠可悲。"]'),
('c84560c0-6d4d-4875-9e36-ca08dad0abc8','洞庭湖','許棠','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u6292\u60c5", "\u4f24\u6625", "\u5199\u666f", "\u5730\u65b9", "\u5b64\u5bc2"]','空江浩蕩景蕭然，盡日菰蒲泊釣船。',64,'全唐诗/poet.tang.33000.json','["空江浩蕩景蕭然，盡日菰蒲泊釣船。", "青草浪高三月渡，綠楊花撲一溪煙。", "情多莫舉傷春目，愁極兼無買酒錢。", "猶有漁人數家住，不成村落夕陽邊。"]'),
('22f57b2b-b013-43bc-a5c1-349b66b282b5','句','許棠','唐','唐诗','tang','','[]','曉嶂猨開戶，寒湫鹿舐冰。',36,'全唐诗/poet.tang.33000.json','["曉嶂猨開戶，寒湫鹿舐冰。", "當空吟待月，到晚坐看山。", "一年三領郡，領郡管仙山。"]'),
('361e35b8-dcc9-42ea-99ad-f07e9ef14918','放歌行','邵謁','唐','唐诗','tang','','[]','龜爲秉靈亡，魚爲弄珠死。',36,'全唐诗/poet.tang.33000.json','["龜爲秉靈亡，魚爲弄珠死。", "心中自有賊，莫怨任公子。", "屈原若不賢，焉得沈湘水。"]'),
('0614785f-46f6-4ba9-9e14-0c25326f6f06','長安寒食','邵謁','唐','唐诗','tang','','["\u5bd2\u98df\u8282", "\u90ca\u6e38", "\u8bbd\u523a"]','春日照九衢，春風媚羅綺。',60,'全唐诗/poet.tang.33000.json','["春日照九衢，春風媚羅綺。", "萬騎出都門，擁在香塵裏。", "莫辭弔枯骨，千載長如此。", "安知今日身，不是昔時鬼。", "但看平地遊，亦見摧輈死。"]'),
('996d8689-9292-4d6b-bba5-f675cd0be3c7','貞女墓','邵謁','唐','唐诗','tang','','[]','生持節操心，死作堅貞鬼。',24,'全唐诗/poet.tang.33000.json','["生持節操心，死作堅貞鬼。", "至今墳上春，草木無花卉。"]'),
('6fa01339-4c77-4c49-828d-b859885ac1c4','自歎','邵謁','唐','唐诗','tang','','[]','春蠶未成繭，已賀箱籠實。',84,'全唐诗/poet.tang.33000.json','["春蠶未成繭，已賀箱籠實。", "蟢子徒有絲，終年不成匹。", "每念古人言，有得則有失。", "我命獨如何，憔悴長如一。", "白日九衢中，幽獨暗如漆。", "流泉有枯時，窮賤無盡日。", "惆悵復惆悵，幾迴新月出。"]'),
('9cdd7471-9eee-46b8-a481-c6d1234ca163','送徐羣宰望江','邵謁','唐','唐诗','tang','','[]','古人力文學，所務安疲甿。',180,'全唐诗/poet.tang.33000.json','["古人力文學，所務安疲甿。", "今人力文學，所務惟公卿。", "大賢重邦本，屈跡官武城。", "勸民勤機杼，自然國用幷。", "但見富貴者，知食不知耕。", "忽爾秋不熟，儲廩焉得盈。", "貢藝既精苦，用心必公平。", "吾道不遺賢，霄漢期芳馨。", "一夫若有德，千古稱其英。", "陶潛雖理邑，崔烈徒台衡。", "濁者必惡清，瞽者必惡明。", "孤松自有色，豈奪衆草榮。", "爲刀若不利，焉得宰牛名。", "爲絲若不直，焉得琴上聲。", "好去立高節，重來振羽翎。"]'),
('b263ca8e-028e-41e3-93e5-435eaafef2d2','秋夕','邵謁','唐','唐诗','tang','','[]','萬里憑夢歸，骨肉皆在眼。',60,'全唐诗/poet.tang.33000.json','["萬里憑夢歸，骨肉皆在眼。", "覺來益惆悵，不信長安遠。", "人人但爲農，我獨常逢旱。", "惡命如漏巵，滴滴添不滿。", "天末雁來時，一呌一腸斷。"]'),
('3864e8c1-a9da-4f18-bc2d-3a0ad463e0df','覽孟東野集','邵謁','唐','唐诗','tang','','[]','蚌死留夜光，劍折留鋒鋩。',60,'全唐诗/poet.tang.33000.json','["蚌死留夜光，劍折留鋒鋩。", "哲人歸大夜，千古傳珪璋。", "珪璋徧四海，人倫多變改。", "題花花已無，翫月月猶在。", "不知天地間，白日幾時昧。"]'),
('1654d196-c27a-46d9-a5d1-78253ba3eaa5','送友人江行','邵謁','唐','唐诗','tang','','[]','送君若浪水，疊疊愁思起。',24,'全唐诗/poet.tang.33000.json','["送君若浪水，疊疊愁思起。", "夢魂如月明，相送秋江裏。"]'),
('208bbede-53a4-444d-8417-4fc0f2d0af3f','下第有感','邵謁','唐','唐诗','tang','','[]','古人有遺言，天地如掌闊。',84,'全唐诗/poet.tang.33000.json','["古人有遺言，天地如掌闊。", "我行三十載，青雲路未達。", "嘗聞讀書者，所貴免征伐。", "誰知失意時，痛於刃傷骨。", "身如石上草，根蔕淺難活。", "人人皆愛春，我獨愁花發。", "如何歸故山，相攜採薇蕨。"]'),
('2d452827-47fe-4b4d-bd2a-69a69dff558c','論政','邵謁','唐','唐诗','tang','','[]','賢哉三握髪，爲有天下憂。',96,'全唐诗/poet.tang.33000.json','["賢哉三握髪，爲有天下憂。", "孫弘不開閣，丙吉寧問牛。", "內政由股肱，外政由諸侯。", "股肱政若行，諸侯政自修。", "一物不得所，蟻穴滿山丘。", "莫言萬木死，不因一葉秋。", "朱雲若不直，漢帝終自由。", "子嬰一失國，渭水東悠悠。"]'),
('62dcae30-df84-4dae-aa84-f8ac164d8404','戰城南','邵謁','唐','唐诗','tang','','[]','武皇重征伐，戰士輕生死。',48,'全唐诗/poet.tang.33000.json','["武皇重征伐，戰士輕生死。", "朝爭刃上功，暮作泉下鬼。", "悲風弔枯骨，明日照荒壘。", "千載留長聲，嗚咽城南水。"]'),
('1309961c-a099-4ff1-9e5f-53d6544cda43','贈鄭殷處士','邵謁','唐','唐诗','tang','','[]','善琴不得聽，嘉玉不得名。',72,'全唐诗/poet.tang.33000.json','["善琴不得聽，嘉玉不得名。", "知音既已死，良匠亦未生。", "退居一河湄，山中物景清。", "魚沈池水碧，鶴去松枝輕。", "長材靡入用，大廈失巨楹。", "顏子不得祿，誰謂天道平。"]'),
('1c0d23a5-cdc0-4faa-ac96-c6ef571db628','古樂府','邵謁','唐','唐诗','tang','','[]','對酒彈古琴，弦中發新音。',72,'全唐诗/poet.tang.33000.json','["對酒彈古琴，弦中發新音。", "新音不可辨，十指幽怨深。", "妾顏不自保，四時如車輪。", "不知今夜月，曾照幾時人。", "露滴芙蓉香，香銷心亦死。", "良時無可留，殘紅謝池水。"]'),
('72c13484-b61b-4d20-9b88-83cd27a5cc14','經安容先生舊居','邵謁','唐','唐诗','tang','','[]','羽化留遺蹤，千載蹤難沒。',60,'全唐诗/poet.tang.33000.json','["羽化留遺蹤，千載蹤難沒。", "一泉巖下水，幾度換明月。", "松老不改柯，龍久皆變骨。", "雲雨有歸時，雞犬無還日。", "至今青山中，寂寞桃花發。"]'),
('f562fdd3-4d2e-44eb-a8d0-ebf21fd1883d','望行人','邵謁','唐','唐诗','tang','','[]','登樓恐不高，及高君已遠。',60,'全唐诗/poet.tang.33000.json','["登樓恐不高，及高君已遠。", "雲行郎即行，雲歸郎不返。", "嗟爲樓上人，望望不相近。", "若作轍中泥，不放郎車轉。", "白日下西山，望盡妾腸斷。"]'),
('a1f17b09-e1e7-4a18-a2b0-6b6da05aef17','歲豐','邵謁','唐','唐诗','tang','','[]','皇天降豐年，本憂貧士食。',60,'全唐诗/poet.tang.33000.json','["皇天降豐年，本憂貧士食。", "貧士無良疇，安能得稼穡。", "工傭輸富家，日落長歎息。", "爲供豪者糧，役盡匹夫力。", "天地莫施恩，施恩強者得。"]'),
('b6feae66-234a-4cb5-a705-53134ae9764f','金谷園懷古','邵謁','唐','唐诗','tang','','[]','在富莫驕奢，驕奢多自亡。',108,'全唐诗/poet.tang.33000.json','["在富莫驕奢，驕奢多自亡。", "爲女莫騁容，騁容多自傷。", "如何金谷園，鬱鬱椒蘭房。", "昨夜綺羅列，今日池館荒。", "竹死不變節，花落有餘香。", "美人抱義死，千載名猶彰。", "嬌歌無遺音，明月留清光。", "浮雲易改色，衰草難重芳。", "不學韓侯婦，銜冤報宋王。"]'),
('acc9b7b3-f1e1-4b60-9410-9fbab9071398','春日有感','邵謁','唐','唐诗','tang','','[]','我心如蘗苦，他見如薺甘。',48,'全唐诗/poet.tang.33000.json','["我心如蘗苦，他見如薺甘。", "火未到身者，痛楚難共諳。", "但言貧者拙，不言富者貧。", "誰知苦寒女，力盡爲桑蠶。"]'),
('d04192c6-beac-455d-b26d-55eae5bfd9fc','學仙詞','邵謁','唐','唐诗','tang','','[]','上仙傳祕訣，澹薄與無營。',60,'全唐诗/poet.tang.33000.json','["上仙傳祕訣，澹薄與無營。", "鍊藥□□□，變姓不變形。", "三尸既無累，百慮自不生。", "是知寸心中，有路通上清。", "祖龍好仙術，燒却黃金精。"]'),
('a0bf402e-877e-4b88-99c3-a27068584f49','妓女','邵謁','唐','唐诗','tang','','[]','天若許人登，青山高不止。',96,'全唐诗/poet.tang.33000.json','["天若許人登，青山高不止。", "地若許人窮，黃泉深無水。", "量諸造化情，物成皆有以。", "如何上青冥，視之平若砥。", "日下騁琅玕，空中無羅綺。", "但見勢騰凌，將爲長如此。", "炫燿一時間，逡巡九泉裏。", "一種爲埃塵，不學墮樓死。"]'),
('6bee3b72-de25-49a1-8395-a96eac7d2e09','寒女行','邵謁','唐','唐诗','tang','','[]','寒女命自薄，生來多賤微。',108,'全唐诗/poet.tang.33000.json','["寒女命自薄，生來多賤微。", "家貧人不聘，一身無所歸。", "養蠶多苦心，繭熟他人絲。", "織素徒苦力，素成他人衣。", "青樓富家女，纔生便有主。", "終日著羅綺，何曾識機杼。", "清夜聞歌聲，聽之淚如雨。", "他人如何歡，我意又何苦。", "所以問皇天，皇天竟無語。"]'),
('7f18e429-e1b7-4513-aac6-cd8d43696e0d','覽鏡','邵謁','唐','唐诗','tang','','[]','一照一迴悲，再照顏色衰。',48,'全唐诗/poet.tang.33000.json','["一照一迴悲，再照顏色衰。", "日月自流水，不知身老時。", "昨日照紅顏，今朝照白絲。", "白絲與紅顏，相去咫尺間。"]'),
('070e07e3-99f1-45ce-936a-474bf1daebac','輕薄行','邵謁','唐','唐诗','tang','','[]','薄薄身上衣，輕輕浮雲質。',36,'全唐诗/poet.tang.33000.json','["薄薄身上衣，輕輕浮雲質。", "長安一花開，九陌馬蹄疾。", "誰言公子車，不是天上力。"]'),
('9853ae44-9a48-4d73-94ca-451094647d5d','苦別離','邵謁','唐','唐诗','tang','','[]','十五爲君婚，二十入君門。',84,'全唐诗/poet.tang.33000.json','["十五爲君婚，二十入君門。", "自從入戶後，見君長出門。", "朝看相送人，暮看相送人。", "若遣折楊柳，此地樹無根。", "願爲陌上土，得作馬蹄塵。", "願爲曲木枝，得作雙車輪。", "安得太行山，移來君馬前。"]'),
('fed75571-bbbb-4857-bac0-4dd26a09ca66','覽張騫傳','邵謁','唐','唐诗','tang','','[]','採藥不得根，尋河不得源。',60,'全唐诗/poet.tang.33000.json','["採藥不得根，尋河不得源。", "此時虛白首，徒感武皇恩。", "桑田未聞改，日月曾幾昏。", "仙骨若求得，壟頭無新墳。", "不見杜陵草，至今空自繁。"]'),
('6bdf16fb-53cc-4a88-96f5-7cf1d475e3d2','白頭吟','邵謁','唐','唐诗','tang','','[]','漢家天宇闊，日月不暫閑。',36,'全唐诗/poet.tang.33000.json','["漢家天宇闊，日月不暫閑。", "常將古今骨，裨作北邙山。", "山高勢已極，猶自凋朱顏。"]'),
('f027da9c-fdcc-4ca3-a6e3-70448b408a97','瞽者歎','邵謁','唐','唐诗','tang','','[]','我心豈不平，我目自不明。',24,'全唐诗/poet.tang.33000.json','["我心豈不平，我目自不明。", "徒云備雙足，天下何由行。"]'),
('802d7972-70ff-4ee3-a7db-9683813c4f27','送從弟長安下第南歸覲親','邵謁','唐','唐诗','tang','','[]','白日不得照，戴天如戴盆。',180,'全唐诗/poet.tang.33000.json','["白日不得照，戴天如戴盆。", "青雲未見路，丹車勞出門。", "採薇秦山鎮，養親湘水源。", "心中豈不切，其如行路難。", "爲文清益峻，爲心直且安。", "芝蘭未入用，馨香志獨存。", "他門種桃李，猶能蔭子孫。", "我家有棠陰，枝葉竟不繁。", "心醉豈因酒，愁多徒見萱。", "征徒忽告歸，執袂殷勤論。", "在鳥終爲鳳，爲魚須化鯤。", "富貴豈長守，貧賤寧有根。", "丈夫志不大，何以佐乾坤。", "晝短疾於箭，早來獻天言。", "莫戀蒼梧畔，野煙橫破村。"]'),
('7b9d3e35-0981-4763-8522-d496d55c5602','少年行','邵謁','唐','唐诗','tang','','[]','丈夫十八九，膽氣欺韓彭。',64,'全唐诗/poet.tang.33000.json','["丈夫十八九，膽氣欺韓彭。", "報讎不用劍，輔國不用兵。", "以目爲水鑑，以心作權衡。", "願君似堯舜，能使天下平。", "何必走馬誇弓矢，然後致得人心爭。"]'),
('cc683d88-62eb-4c1f-90db-40259387809b','漢宮井','邵謁','唐','唐诗','tang','','[]','轆轤聲絕離宮靜，班姬幾度照金井。',32,'全唐诗/poet.tang.33000.json','["轆轤聲絕離宮靜，班姬幾度照金井。", "梧桐老去殘花開，猶似當時美人影。"]'),
('1b62ad48-49d0-452a-a177-0cd725f293b0','顯茂樓','邵謁','唐','唐诗','tang','','[]','秦山渭水尚悠悠，如何草樹迷宮闕。',32,'全唐诗/poet.tang.33000.json','["秦山渭水尚悠悠，如何草樹迷宮闕。", "繁華朱翠盡東流，唯有望樓對明月。"]'),
('d424da5f-29b5-49ca-9e00-289b629d6c20','紫閣峯','邵謁','唐','唐诗','tang','','[]','壯國山河倚空碧，迥拔煙霞侵太白。',32,'全唐诗/poet.tang.33000.json','["壯國山河倚空碧，迥拔煙霞侵太白。", "綠崖下視千萬尋，青天只據百餘尺。"]'),
('2ffa20a5-ecb8-4df9-8fa0-f51f304f518a','送李員外頻之建州','林寬','唐','唐诗','tang','','[]','句踐江頭月，客星臺畔松。',48,'全唐诗/poet.tang.33000.json','["句踐江頭月，客星臺畔松。", "爲郎久不見，出守暫相逢。", "鳥泊牽灘索，花空押號鐘。", "遠人思化切，休上武夷峰。"]'),
('d7dc2bf9-c4d3-4a9c-a07c-c2e91e4afcb1','送許棠先輩歸宣州','林寬','唐','唐诗','tang','','[]','髪枯窮律韻，字字合塤篪。',48,'全唐诗/poet.tang.33000.json','["髪枯窮律韻，字字合塤篪。", "日月所到處，姓名無不知。", "鶯啼謝守壘，苔老謫仙碑。", "詩道喪來久，東歸爲弔之。"]'),
('3d8af169-8b32-469c-8760-12e25f14b914','窮冬太學','林寬','唐','唐诗','tang','','["\u5e90\u5c71"]','投跡依槐館，荒亭草合時。',48,'全唐诗/poet.tang.33000.json','["投跡依槐館，荒亭草合時。", "雪深鳶嘯急，薪濕鼎吟遲。", "默坐同誰話，非僧不我知。", "匡廬瀑布畔，何日副心期。"]'),
('5b0ab99c-6b1d-44dd-8614-11e6450e9efa','陪鄭諴郎中假日省中寓直','林寬','唐','唐诗','tang','','[]','憲廳名最重，假日許從容。',48,'全唐诗/poet.tang.33000.json','["憲廳名最重，假日許從容。", "牀滿諸司印，庭高五粒松。", "井尋芸吏汲，茶拆岳僧封。", "鳥度簾旌暮，猶吟隔苑鐘。"]'),
('a956c5ba-b15f-44f0-b0d2-8f03a37a0f3c','送謝石先輩歸宣州','林寬','唐','唐诗','tang','','[]','名隨春色遠，湖外已先知。',48,'全唐诗/poet.tang.33000.json','["名隨春色遠，湖外已先知。", "花盡方辭醉，鶯殘是放時。", "天寒千尺嶽，頷白半聯詩。", "笋蕨猶堪採，榮歸及養期。"]'),
('9116a4f5-6a50-4ade-a8ff-547f408fec90','下第寄歐陽瓚','林寬','唐','唐诗','tang','','[]','詩人道僻命多奇，更值干戈亂起時。',32,'全唐诗/poet.tang.33000.json','["詩人道僻命多奇，更值干戈亂起時。", "莫作江寧王少府，一生吟苦竟誰知。"]'),
('b2f518a6-d254-42c3-a574-53ae65c90785','寄何紹餘','林寬','唐','唐诗','tang','','[]','雁過君猶未入城，清賢門下舊知名。',64,'全唐诗/poet.tang.33000.json','["雁過君猶未入城，清賢門下舊知名。", "風波凍馬遙逢見，革橐飢僮尚挈行。", "住在閑坊無轍跡，別來何寺有泉聲。", "芙蓉苑北曲江岸，期看終南新雪晴。"]'),
('718a0c14-5339-4204-b988-5771a83d7296','送人宰浦城','林寬','唐','唐诗','tang','','[]','東南猶阻寇，梨嶺更誰登。',48,'全唐诗/poet.tang.33000.json','["東南猶阻寇，梨嶺更誰登。", "作宰應無俸，歸船必有僧。", "灘平眠獺石，燒斷飲猨藤。", "歲盡校殊最，方當見異能。"]'),
('ade34684-60aa-4bb2-9499-09beebead399','省試臘後望春宮','林寬','唐','唐诗','tang','','[]','皇都初度臘，鳳輦出深宮。',72,'全唐诗/poet.tang.33000.json','["皇都初度臘，鳳輦出深宮。", "高凭樓臺上，遙瞻灞滻中。", "仗凝霜彩白，袍映日華紅。", "柳眼方開凍，鶯聲漸轉風。", "御溝穿斷靄，驪岫照斜空。", "時見宸游興，因觀稼穡功。"]'),
('4bbe085c-055c-403c-a4d5-926e6e2fe7ad','寄省中知己','林寬','唐','唐诗','tang','','[]','門掩清曹晚，靜將烏府鄰。',48,'全唐诗/poet.tang.33000.json','["門掩清曹晚，靜將烏府鄰。", "花開封印早，雪下典衣頻。", "怪木風吹閣，廢巢時落薪。", "每憐吾道苦，長說向同人。"]'),
('3c4c6c56-7bf2-4f58-930e-64824f8e4363','朱坡','林寬','唐','唐诗','tang','','[]','朱坡坡上望，不似在秦京。',48,'全唐诗/poet.tang.33000.json','["朱坡坡上望，不似在秦京。", "漸覺溪山秀，更高魚鳥情。", "夜吟禪子室，曉爨獵人鐺。", "恃此偷佳賞，九衢蜩未鳴。"]'),
('c7ce3cca-3da3-43a0-8b15-01d0051cdb1a','酬陳樵見寄','林寬','唐','唐诗','tang','','[]','失意閑眠起更遲，又將羈薄謝深知。',64,'全唐诗/poet.tang.33000.json','["失意閑眠起更遲，又將羈薄謝深知。", "囊書旋入酒家盡，紗帽長依僧壁垂。", "待月句新遭鬼哭，尋山貌古被猨窺。", "元和才子多如此，除却清吟何所爲。"]'),
('e2ea2b0d-4345-449a-8b12-bbe26150d113','華清宮','林寬','唐','唐诗','tang','','[]','殿角鐘殘立宿鴉，朝元歸駕望無涯。',32,'全唐诗/poet.tang.33000.json','["殿角鐘殘立宿鴉，朝元歸駕望無涯。", "香泉空浸宮前草，未到春時爭發花。"]'),
('e4093339-f20d-4607-a48c-7789623d4899','終南山','林寬','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','標奇聳峻壯長安，影入千門萬戶寒。',32,'全唐诗/poet.tang.33000.json','["標奇聳峻壯長安，影入千門萬戶寒。", "徒自倚天生氣色，塵中誰爲舉頭看。"]'),
('103dad37-ff58-4d15-be02-5a944406f7a8','歌風臺','林寬','唐','唐诗','tang','','[]','蒿棘空存百尺基，酒酣曾唱大風詞。',32,'全唐诗/poet.tang.33000.json','["蒿棘空存百尺基，酒酣曾唱大風詞。", "莫言馬上得天下，自古英雄盡解詩。"]'),
('7c79ec9c-409e-41fc-aca7-da6086bed142','送人歸日東','林寬','唐','唐诗','tang','','[]','滄溟西畔望，一望一心摧。',48,'全唐诗/poet.tang.33000.json','["滄溟西畔望，一望一心摧。", "地即同正朔，天教阻往來。", "波翻夜作電，鯨吼晝爲雷。", "門外人葠徑，到時花幾開。"]'),
('39a111c0-a531-456b-85b7-1779f65ba90d','寓興','林寬','唐','唐诗','tang','','[]','西母一杯酒，空言浩劫春。',48,'全唐诗/poet.tang.33000.json','["西母一杯酒，空言浩劫春。", "英雄歸厚土，日月照閑人。", "衰草珠璣塚，冷灰龍鳳身。", "茂陵驪岫晚，過者暗傷神。"]'),
('611d75ff-fcb9-4d4e-8826-939d3329ef67','少年行','林寬','唐','唐诗','tang','','[]','柳煙侵御道，門映夾城開。',48,'全唐诗/poet.tang.33000.json','["柳煙侵御道，門映夾城開。", "白日莫空過，青春不再來。", "報讎衝雪去，乘醉臂鷹迴。", "看取歌鐘地，殘陽滿壞臺。"]'),
('f217cf4f-841a-4ba9-8201-dc2500548215','塞上還荅友人','林寬','唐','唐诗','tang','','[]','無端遊絕塞，歸鬢已蒼然。',48,'全唐诗/poet.tang.33000.json','["無端遊絕塞，歸鬢已蒼然。", "戎羯圍中過，風沙馬上眠。", "草衰頻過燒，耳冷不聞蟬。", "從此甘貧坐，休言更到邊。"]'),
('dcaccdaa-a09c-44da-9f57-00753b021e3a','哭棲白供奉','林寬','唐','唐诗','tang','','[]','侍輦才難得，三朝有上人。',48,'全唐诗/poet.tang.33000.json','["侍輦才難得，三朝有上人。", "琢詩方到骨，至死不離貧。", "風帳孤螢入，霜堦積葉頻。", "夕陽門半掩，過此亦無因。"]'),
('ccaefadf-cda0-432d-9a38-3ba3e44e4cca','送昇道靖恭相公分司','林寬','唐','唐诗','tang','','[]','東風時不遇，果見致君難。',48,'全唐诗/poet.tang.33000.json','["東風時不遇，果見致君難。", "海岳影猶動，鵾鵬勢未安。", "星沈關鎖冷，雞唱驛燈殘。", "誰似二賓客，門閑嵩洛寒。"]'),
('79a21f00-d533-4410-8d23-ac48b5db9486','關下早行','林寬','唐','唐诗','tang','','["\u9ec4\u6cb3"]','軋軋推危轍，聽雞獨早行。',48,'全唐诗/poet.tang.33000.json','["軋軋推危轍，聽雞獨早行。", "風吹宿靄散，月照華山明。", "白首東西客，黃河晝夜清。", "相逢皆有事，唯我是閑情。"]'),
('eec1af9f-2d78-4e9a-ae5d-9f2013c4974b','曲江','林寬','唐','唐诗','tang','','[]','曲江初碧草初青，萬轂千蹄匝岸行。',64,'全唐诗/poet.tang.33000.json','["曲江初碧草初青，萬轂千蹄匝岸行。", "傾國妖姬雲鬢重，薄徒公子雪衫輕。", "瓊鐫狒𤝞遶觥舞，金蹙辟邪拏撥鳴。", "柳絮杏花留不得，隨風處處逐歌聲。"]'),
('c9c1da97-44d4-4e6b-9d8f-dcda611214ce','長安遣懷','林寬','唐','唐诗','tang','','[]','醉下高樓醒復登，任從浮薄笑才能。',32,'全唐诗/poet.tang.33000.json','["醉下高樓醒復登，任從浮薄笑才能。", "青龍寺裏三門上，立爲南山不爲僧。"]'),
('61f222e8-59bf-4229-b44e-125b9b779a3b','送僧遊太白峰','林寬','唐','唐诗','tang','','[]','雲深遊太白，莫惜遍探奇。',48,'全唐诗/poet.tang.33000.json','["雲深遊太白，莫惜遍探奇。", "頂上多靈跡，塵中少客知。", "懸崖倚凍瀑，飛狖過孤枝。", "出定更何事，相逢必有詩。"]'),
('8d4a5faf-b503-4732-aff6-90a18c476277','哭造微禪師','林寬','唐','唐诗','tang','','[]','神遷不火葬，新塔露疎檉。',48,'全唐诗/poet.tang.33000.json','["神遷不火葬，新塔露疎檉。", "是物皆磨滅，唯師出死生。", "虛堂散釣叟，怪木哭山精。", "林下路長在，無因更此行。"]'),
('f4da1855-f3cb-4bc9-a2e7-a451c6eb91a4','獻同年孔郎中','林寬','唐','唐诗','tang','','[]','炊瓊爇桂帝關居，賣盡寒衣典盡書。',64,'全唐诗/poet.tang.33000.json','["炊瓊爇桂帝關居，賣盡寒衣典盡書。", "驅馬每尋霜影裏，到門常在鼓聲初。", "蟾枝交彩清蘭署，鸞珮排光映玉除。", "一顧深恩身未殺，爭期皎日負吹噓。"]'),
('865e96b8-d12f-4bb6-805f-f025d0cc6b34','聞雁','林寬','唐','唐诗','tang','','[]','接影橫空背雪飛，聲聲寒出玉關遲。',32,'全唐诗/poet.tang.33000.json','["接影橫空背雪飛，聲聲寒出玉關遲。", "上陽宮裏三千夢，月冷風清聞過時。"]'),
('ec595bea-428b-49fb-b0e4-cd28acf698ba','送惠補闕','林寬','唐','唐诗','tang','','[]','詔下搜巖野，高人入竹林。',48,'全唐诗/poet.tang.33000.json','["詔下搜巖野，高人入竹林。", "長因抗疏日，便作去官心。", "清俸供僧盡，滄洲寄跡深。", "東門有歸路，徒自棄華簪。"]'),
('23b95b8f-fb3f-4da6-970a-2899304c6646','和友人賊後','林寬','唐','唐诗','tang','','[]','帶號乞兵急，英雄陷賊圍。',48,'全唐诗/poet.tang.33000.json','["帶號乞兵急，英雄陷賊圍。", "江山猶未靜，魚鳥欲何歸。", "城露桑榆盡，時平老幼稀。", "書從戰後得，讀徹血盈衣。"]'),
('0771bdd1-a9cc-4dd6-b587-f7bbb40e8386','長安即事','林寬','唐','唐诗','tang','','[]','暝鼓纔終復曉雞，九門何計出沈迷。',64,'全唐诗/poet.tang.33000.json','["暝鼓纔終復曉雞，九門何計出沈迷。", "樵童亂打金吾鼓，豪馬爭奔丞相隄。", "翡翠鬟欹釵上燕，麒麟衫束海中犀。", "須知不是詩人事，空憶泉聲菊畔畦。"]'),
('5aea74ae-c174-4462-9bcc-5c764449c5b4','和周繇校書先輩省中寓直','林寬','唐','唐诗','tang','','[]','古木重門掩，幽深秖欠溪。',120,'全唐诗/poet.tang.33000.json','["古木重門掩，幽深秖欠溪。", "此中真吏隱，何必更巖棲。", "名姓鐫幢記，經書逐庫題。", "字隨飛蠹缺，堦與落星齊。", "伴直僧談靜，侵霜蛩韻低。", "粘塵賀草沒，剝粉薛禽迷。", "衰蘚牆千堵，微陽菊半畦。", "鼓殘鴉去北，漏在月沈西。", "每憶終南雪，幾登雲閣梯。", "時因搜句次，那惜一招攜。"]'),
('438b2878-c2d7-4309-99a0-cae394614d2c','苦雨','林寬','唐','唐诗','tang','','[]','霪霖翳日月，窮巷變溝坑。',122,'全唐诗/poet.tang.33000.json','["霪霖翳日月，窮巷變溝坑。", "驟灑纖枝折，奔傾壞堵平。", "蒙[簦]來客絕，躍甃噪蛙獰。", "敗屐陰苔積，摧簷濕菌生。", "斜飛穿裂瓦，迸落打空鐺。", "葉底遲歸蝶，林中滯出鶯。", "潤侵書缝黑，冷浸鬢絲明。", "牖暗參差影，堦寒斷續聲。", "尺薪功比桂，寸粒價高瓊。", "遙想管弦裏，無因識此情。"]'),
('b9186af7-c419-431a-8bcb-612b7cc65031','翰林作','劉鄴','唐','唐诗','tang','','[]','曾是江波垂釣人，自憐深厭九衢塵。',64,'全唐诗/poet.tang.33000.json','["曾是江波垂釣人，自憐深厭九衢塵。", "浮生漸老年隨水，往事曾聞淚滿巾。", "已覺遠天秋色動，不堪閑夜雨聲頻。", "多慚不是相如筆，虛直金鑾接侍臣。"]'),
('cb4af199-f2aa-4f3d-a575-3b7171814288','待漏院吟','劉鄴','唐','唐诗','tang','','[]','玉堂簾外獨遲遲，明月初沈勘契時。',32,'全唐诗/poet.tang.33000.json','["玉堂簾外獨遲遲，明月初沈勘契時。", "閑聽景陽鐘盡後，兩鶯飛上萬年枝。"]'),
('7e1a33ed-9e0d-488d-8927-313878fe9d9d','慧山寺肄業送懷坦上人','李騭','唐','唐诗','tang','','[]','流水何山分，浮雲空中遇。',132,'全唐诗/poet.tang.33000.json','["流水何山分，浮雲空中遇。", "我生無根株，聚散亦難固。", "憶昨鬬龍春，巖棲侶高步。", "清懷去羈束，幽境無滓污。", "日落九峰明，煙生萬華暮。", "茲歡未云隔，前笑倏已故。", "四時難信留，百草換霜露。", "離襟一成解，悵抱將何諭。", "驚泉有餘哀，永日誰與度。", "緬思孤帆影，再往重江路。", "去去忽悽悲，因風暫回顧。"]'),
('04ac9515-a376-42d8-b41a-f1283e7a1bb0','讀惠山若冰師集因題故院三首 一','李騭','唐','唐诗','tang','','[]','五天何處望，心念起皆知。',48,'全唐诗/poet.tang.33000.json','["五天何處望，心念起皆知。", "化塔留今日，泉鳴自昔時。", "古苔生石靜，秋草滿山悲。", "莫道聲容遠，長歌白雪詞。"]'),
('b6c837b4-c856-4d17-a015-abab1d78c9c4','讀惠山若冰師集因題故院三首 二','李騭','唐','唐诗','tang','','[]','高懷逢異境，佳句想吟頻。',48,'全唐诗/poet.tang.33000.json','["高懷逢異境，佳句想吟頻。", "月冷松溪夜，煙濃草寺春。", "浮雲將世遠，清聽與名新。", "不見開巖日，空爲拜影人。"]'),
('2be60f00-61f2-435d-948c-6584f9ca0899','讀惠山若冰師集因題故院三首 三','李騭','唐','唐诗','tang','','[]','景物搜求歇，山雲放縱飛。',48,'全唐诗/poet.tang.33000.json','["景物搜求歇，山雲放縱飛。", "樹寒煙鶴去，池靜水龍歸。", "暗榻塵飄滿，陰簷月到稀。", "何年燈焰盡，風動影堂扉。"]'),
('06503ff8-f8e3-4d08-b206-245215944b05','自惠山至吳下寄酬南徐從事','李騭','唐','唐诗','tang','','[]','不接芳晨游，獨此長洲苑。',72,'全唐诗/poet.tang.33000.json','["不接芳晨游，獨此長洲苑。", "風顏一成阻，翰墨勞空返。", "悠悠汀渚長，杳杳蘋花晚。", "如何西府歡，尚念東吳遠。", "瑤音動清韻，蘭思芬盈畹。", "猶及九峰春，歸吟白雲巘。"]'),
('bc450c2f-58f4-4773-a6c1-f80faddd3b2c','中秋夜戲酬顧道流','孫蜀','唐','唐诗','tang','','[]','不那此身偏愛月，等閑看月即更深。',32,'全唐诗/poet.tang.33000.json','["不那此身偏愛月，等閑看月即更深。", "仙翁每被嫦娥使，一度逢圓一度吟。"]'),
('78dfa3e8-2ba4-41e6-9e71-e25c3b71460d','詠燕上主司鄭愚','歐陽澥','唐','唐诗','tang','','[]','翩翩雙燕畫堂開，送古迎今幾萬回。',32,'全唐诗/poet.tang.33000.json','["翩翩雙燕畫堂開，送古迎今幾萬回。", "長向春秋社前後，爲誰歸去爲誰來。"]'),
('1f892662-79f9-444f-9f1c-8e862828e49d','句','歐陽澥','唐','唐诗','tang','','[]','黃菊離家十四年，離家已是夢松年。',28,'全唐诗/poet.tang.33000.json','["黃菊離家十四年，離家已是夢松年。", "落日望鄉處，何人知客情。"]'),
('b44ded41-fdeb-4051-a798-7da94316110f','自詠豆花','陳黯','唐','唐诗','tang','','[]','玳瑁應難比，斑犀定不加。',24,'全唐诗/poet.tang.33000.json','["玳瑁應難比，斑犀定不加。", "天嫌未端正，滿面與妝花。"]'),
('8416388e-8934-4d9f-b5c3-d2f1b7e8b6ac','雪詩','張孜','唐','唐诗','tang','','["\u751f\u6d3b", "\u5199\u96ea", "\u96ea"]','長安大雪天，鳥雀難相覓。',72,'全唐诗/poet.tang.33000.json','["長安大雪天，鳥雀難相覓。", "其中豪貴家，搗椒泥四壁。", "到處爇紅爐，周迴下羅冪。", "暖手調金絲，蘸甲斟瓊液。", "醉唱玉塵飛，困融香汗滴。", "豈知飢寒人，手脚生皴劈。"]'),
('494ab0dc-0e87-4fae-a585-bde3c845d165','句','張孜','唐','唐诗','tang','','["\u9ec4\u6cb3"]','著牙賣朱紫，斷錢賒舉選。',56,'全唐诗/poet.tang.33000.json','["著牙賣朱紫，斷錢賒舉選。", "華山秀作英雄骨，黃河瀉出縱橫才。", "夢破青霄春，煙霞無去塵。", "若誇郭璞五色筆，江淹却是尋常人。"]'),
('1a401af4-52df-4688-a397-e95c778272d1','贈妓僊哥','鄭仁表','唐','唐诗','tang','','[]','嚴吹如何下太清，玉肌無疹六銖輕。',32,'全唐诗/poet.tang.33000.json','["嚴吹如何下太清，玉肌無疹六銖輕。", "自知不是流霞酌，願聽雲和瑟一聲。"]'),
('97914716-3075-4de2-b608-8a304f3b7367','贈妓命洛真','鄭仁表','唐','唐诗','tang','','[]','巧製新章拍拍新，金罍巡舉助精神。',32,'全唐诗/poet.tang.33000.json','["巧製新章拍拍新，金罍巡舉助精神。", "時時欲得橫波眄，又怕回籌錯指人。"]'),
('386ed35c-92f8-4adb-bbf7-1e864f2e9ac4','句','鄭仁表','唐','唐诗','tang','','[]','文章世上爭開路，閥閱山東拄破天。',16,'全唐诗/poet.tang.33000.json','["文章世上爭開路，閥閱山東拄破天。"]'),
('4ba529c1-39a6-4eb7-8906-6c0068d417dd','杜甫同谷茅茨','趙鴻','唐','唐诗','tang','','[]','工部棲遲後，鄰家大半無。',48,'全唐诗/poet.tang.33000.json','["工部棲遲後，鄰家大半無。", "青羌迷道路，白社寄杯盂。", "大雅何人繼，全生此地孤。", "孤雲飛鳥什，空勒舊山隅。"]'),
('bb9937fb-3212-4c9c-b56c-7b6dc3a4c2e3','栗亭','趙鴻','唐','唐诗','tang','','[]','杜甫栗亭詩，詩人多在口。',24,'全唐诗/poet.tang.33000.json','["杜甫栗亭詩，詩人多在口。", "悠悠二甲子，題紀今何有。"]'),
('6f46697d-ad3e-4929-8465-a99e611b5538','泥功山','趙鴻','唐','唐诗','tang','','[]','立石泥功狀，天然詭怪形。',24,'全唐诗/poet.tang.33000.json','["立石泥功狀，天然詭怪形。", "未嘗私禍福，終不費丹青。"]'),
('11a87491-eaca-4717-a459-e4a1ace84f35','昆明池織女石','童翰卿','唐','唐诗','tang','','[]','一片昆明石，千秋織女名。',72,'全唐诗/poet.tang.33000.json','["一片昆明石，千秋織女名。", "見人虛脈脈，臨水更盈盈。", "苔作輕衣色，波爲促杼聲。", "岸雲連鬢濕，沙月對眉生。", "有臉蓮同笑，無心鳥不驚。", "還如朝鏡裏，形影兩分明。"]'),
('15cf52d4-354c-40a0-98fd-bc5597aba439','絕句','童翰卿','唐','唐诗','tang','','[]','大朴逐物盡，哀我天地功。',24,'全唐诗/poet.tang.33000.json','["大朴逐物盡，哀我天地功。", "爭得榮辱心，灑然歸西風。"]'),
('a248d6d9-a8c1-4dd3-9a07-f50a107c3239','補周禮九夏系文   一','皮日休','唐','唐诗','tang','','[]','爣爣皎日，歘麗於天。',20,'全唐诗/poet.tang.33000.json','["爣爣皎日，歘麗於天。", "厥明御舒，如王出焉。"]'),
('60722288-d085-4aee-814a-e741f9c22772','補周禮九夏系文   二','皮日休','唐','唐诗','tang','','[]','爣爣皎日，歘入於地。',20,'全唐诗/poet.tang.33000.json','["爣爣皎日，歘入於地。", "厥晦厥貞，如王入焉。"]'),
('3c1c2256-2fe9-49b3-8e11-c583b7d252b0','補周禮九夏系文   三','皮日休','唐','唐诗','tang','','[]','出有龍旂，入有珩佩。',20,'全唐诗/poet.tang.33000.json','["出有龍旂，入有珩佩。", "勿驅勿馳，惟慎惟戒。"]'),
('44ed3248-5872-4541-b94d-877aa3da2af5','補周禮九夏系文   四','皮日休','唐','唐诗','tang','','[]','出有嘉謀，入有內則。',20,'全唐诗/poet.tang.33000.json','["出有嘉謀，入有內則。", "繄彼臣庶，欽王之式。"]'),
('e3e97062-1a57-424a-982f-4f0bb94f926f','補周禮九夏系文   一','皮日休','唐','唐诗','tang','','[]','愔愔清廟，儀儀象服。',20,'全唐诗/poet.tang.33000.json','["愔愔清廟，儀儀象服。", "我尸出矣，迎神之穀。"]'),
('dedc2b1f-306e-40db-a328-d53d3f72b958','補周禮九夏系文   二','皮日休','唐','唐诗','tang','','[]','杳杳陰竹，坎坎路鼓。',20,'全唐诗/poet.tang.33000.json','["杳杳陰竹，坎坎路鼓。", "我尸入矣，得神之祜。"]'),
('be53a076-db9e-4ff1-997b-74a10b2a571f','補周禮九夏系文   一','皮日休','唐','唐诗','tang','','[]','有鬱其鬯，有儼其彝。',20,'全唐诗/poet.tang.33000.json','["有鬱其鬯，有儼其彝。", "九變未作，全乘來之。"]'),
('c8477211-b077-420f-9d1b-6a798c184fc0','補周禮九夏系文   二','皮日休','唐','唐诗','tang','','[]','既醑既酢，爰朄爰舞。',20,'全唐诗/poet.tang.33000.json','["既醑既酢，爰朄爰舞。", "象物既降，全乘之去。"]'),
('1e8563f2-8e19-4c68-904a-faec1189d8f3','補周禮九夏系文   一','皮日休','唐','唐诗','tang','','[]','麟之儀儀，不縶不維。',20,'全唐诗/poet.tang.33000.json','["麟之儀儀，不縶不維。", "樂德而至，如賓之嬉。"]'),
('4bb6f647-2913-47c8-a4ca-c1b4655d67d1','補周禮九夏系文   二','皮日休','唐','唐诗','tang','','[]','鳳之愉愉，不篝不笯。',20,'全唐诗/poet.tang.33000.json','["鳳之愉愉，不篝不笯。", "樂德而至，如賓之娛。"]'),
('4aa65a5d-2f65-4250-a131-b133c9c8d5b9','補周禮九夏系文   三','皮日休','唐','唐诗','tang','','[]','自筐及筥，我有牢醑。',20,'全唐诗/poet.tang.33000.json','["自筐及筥，我有牢醑。", "自筐及篚，我有貨幣。"]'),
('f648de04-10ab-4307-a708-87f098c74c1c','補周禮九夏系文   四','皮日休','唐','唐诗','tang','','[]','我牢不愆，我貨不匱。',20,'全唐诗/poet.tang.33000.json','["我牢不愆，我貨不匱。", "碩碩其才，有樂而止。"]'),
('e9a98326-3dc3-4d4b-af7b-a95d56738c47','補周禮九夏系文   一','皮日休','唐','唐诗','tang','','[]','王有虎臣，錫之鈇鉞。',20,'全唐诗/poet.tang.33000.json','["王有虎臣，錫之鈇鉞。", "征彼不憓，一撲而滅。"]'),
('50bbf336-5400-428e-b57f-5693b9ee82be','補周禮九夏系文   二','皮日休','唐','唐诗','tang','','[]','王有虎臣，錫之圭瓚。',20,'全唐诗/poet.tang.33000.json','["王有虎臣，錫之圭瓚。", "征彼不享，一烘而泮。"]'),
('f3509bec-0b32-40c2-aaac-48c16d1450cc','補周禮九夏系文   三','皮日休','唐','唐诗','tang','','[]','王有掌訝，遉爾疆理。',20,'全唐诗/poet.tang.33000.json','["王有掌訝，遉爾疆理。", "王有掌客，饋爾饔餼。"]'),
('c421e0cd-a6d8-44e5-bdc7-41a384859b1c','補周禮九夏系文   四','皮日休','唐','唐诗','tang','','[]','何以樂之，金石九奏。',20,'全唐诗/poet.tang.33000.json','["何以樂之，金石九奏。", "何以錫之，龍旂九旒。"]'),
('6259214e-c9ab-4baa-9a47-d45f210e2d25','補周禮九夏系文','皮日休','唐','唐诗','tang','','[]','𤫩𤫩衡笄，翬衣褕翟。',20,'全唐诗/poet.tang.33000.json','["𤫩𤫩衡笄，翬衣褕翟。", "自內而祭，爲君之則。"]'),
('7801ddbb-644b-4e24-9ded-878b0e852a03','補周禮九夏系文   一','皮日休','唐','唐诗','tang','','[]','洪源誰孕，疏爲江河。',20,'全唐诗/poet.tang.33000.json','["洪源誰孕，疏爲江河。", "大塊孰埏，播爲山阿。"]'),
('744878b3-298d-484e-8097-510f474e8f37','補周禮九夏系文   二','皮日休','唐','唐诗','tang','','[]','厥流浩漾，厥勢嵯峨。',20,'全唐诗/poet.tang.33000.json','["厥流浩漾，厥勢嵯峨。", "今君之酌，慰我實多。"]'),
('e45283a9-7eb5-419d-9871-021a7af0ce46','補周禮九夏系文   一','皮日休','唐','唐诗','tang','','[]','禮酒既酌，嘉賓既厚，牘爲之奏。',15,'全唐诗/poet.tang.33000.json','["禮酒既酌，嘉賓既厚，牘爲之奏。"]'),
('5b747dbd-3e50-4a74-b33d-e9dd178f1476','補周禮九夏系文   二','皮日休','唐','唐诗','tang','','[]','禮酒既竭，嘉賓既悅，應爲之節。',15,'全唐诗/poet.tang.33000.json','["禮酒既竭，嘉賓既悅，應爲之節。"]'),
('13c8d9e2-a103-4ea7-84ee-f73d12767990','補周禮九夏系文   三','皮日休','唐','唐诗','tang','','[]','禮酒既罄，嘉賓既醒，雅爲之行。',15,'全唐诗/poet.tang.33000.json','["禮酒既罄，嘉賓既醒，雅爲之行。"]'),
('f84e1f53-b20d-443d-ad69-df756f979bf5','補周禮九夏系文   一','皮日休','唐','唐诗','tang','','[]','桓桓其珪，衮衮其衣。',20,'全唐诗/poet.tang.33000.json','["桓桓其珪，衮衮其衣。", "出作二伯，天子是毗。"]'),
('49ad8da7-f784-4635-886a-5711ea38fa9f','補周禮九夏系文   二','皮日休','唐','唐诗','tang','','[]','桓桓其珪，衮衮其服。',20,'全唐诗/poet.tang.33000.json','["桓桓其珪，衮衮其服。", "入作三孤，國人是福。"]'),
('109074c4-087c-4406-a668-484196330f74','三羞詩三首','皮日休','唐','唐诗','tang','','[]','吾聞古君子，介介勵其節。',240,'全唐诗/poet.tang.33000.json','["吾聞古君子，介介勵其節。", "入門疑儲宮，撫己思鈇鉞。", "志者若不退，佞者何由達。", "君臣一殽膳，家國共殘殺。", "此道見於今，永思心若裂。", "王臣方謇謇，佐我無玷缺。", "如何以謀計，中道生芽蘗。", "憲司遵故典，分道播南越。", "蒼惶出班行，家室不容別。", "玄鬢行爲霜，清淚立成血。", "乘遽劇飛鳥，就傳過風發。", "嗟吾何爲者，叨在造士列。", "獻文不上第，歸于淮之汭。", "蹇蹄可再犇，退羽可後歇。", "利則侶軒裳，塞則友松月。", "而於方寸內，未有是愁結。", "未爲祿食仕，俯不媿粱糲。", "未爲冠冕人，死不慙忠烈。", "如何有是心，不能叩丹闕。", "赫赫負君歸，南山采芝蕨。"]'),
('f81b414f-2c26-4b9b-bb35-fa468d319ddc','三羞詩三首','皮日休','唐','唐诗','tang','','[]','南荒不擇吏，致我交阯覆。',204,'全唐诗/poet.tang.33000.json','["南荒不擇吏，致我交阯覆。", "緜聯三四年，流爲中夏辱。", "懦者鬬即退，武者兵則黷。", "軍庸滿天下，戰將多金玉。", "刮則齊民癕，分爲猛士祿。", "雄健許昌師，忠武冠其族。", "去爲萬騎風，住作一川肉。", "昨朝殘卒回，千門萬戶哭。", "哀聲動閭里，怨氣成山谷。", "誰能聽晝鼙，不忍看金鏃。", "吾有制勝術，不奈賤碌碌。", "貯之胸臆間，慙見許師屬。", "自嗟胡爲者，得躡前修躅。", "家不出軍租，身不識部曲。", "亦衣許師衣，亦食許師粟。", "方知古人道，蔭我已爲足。", "念此向誰羞，悠悠潁川綠。"]'),
('a52e1527-2850-4b7a-8e17-4b895ee1dd98','三羞詩三首','皮日休','唐','唐诗','tang','','[]','天子丙戌年，淮右民多飢。',264,'全唐诗/poet.tang.33000.json','["天子丙戌年，淮右民多飢。", "就中潁之汭，轉徙何纍纍。", "夫婦相顧亡，棄却抱中兒。", "兄弟各自散，出門如大癡。", "一金易蘆蔔，一縑換鳧茈。", "荒村墓鳥樹，空屋野花籬。", "兒童齧草根，倚桑空羸羸。", "斑白死路傍，枕土皆離離。", "方知聖人教，於民良在斯。", "厲能去人愛，荒能奪人慈。", "如何司牧者，有術皆在茲。", "粵吾何爲人，數畝清溪湄。", "一寫落第文，一家歡復嬉。", "朝食有麥饘，晨起有布衣。", "一身既飽暖，一家無怨咨。", "家雖有畎畝，手不秉鎡基。", "歲雖有札瘥，庖不廢晨炊。", "何道以致是，我有明公知。", "食之以侯食，衣之以侯衣。", "歸時卹金帛，使我奉庭闈。", "撫己媿潁民，奚不進德爲。", "因茲感知己，盡日空涕洟。"]'),
('d98a6211-a1b2-4955-98fa-f94f052f7949','七愛詩 房杜二相國','皮日休','唐','唐诗','tang','','[]','吾愛房與杜，貧賤共聯步。',120,'全唐诗/poet.tang.33000.json','["吾愛房與杜，貧賤共聯步。", "脫身拋亂世，策杖歸真主。", "縱橫握中算，左右天下務。", "骯髒無敵才，磊落不世遇。", "美矣名公卿，魁然真宰輔。", "黃閣三十年，清風一萬古。", "巨業照國史，大勳鎮王府。", "遂使後世民，至今受陶鑄。", "粵吾少有志，敢躡前賢路。", "苟得同其時，願爲執鞭豎。"]'),
('91f87f2a-adab-40f2-93ec-15cccca71f4a','七愛詩 李太尉','皮日休','唐','唐诗','tang','','[]','吾愛李太尉，崛起定中原。',156,'全唐诗/poet.tang.33000.json','["吾愛李太尉，崛起定中原。", "驍雄十萬兵，四面圍國門。", "一戰取王畿，一叱散妖氛。", "乘輿既反正，兇豎爭亡魂。", "巍巍柱天功，蕩蕩蓋世勳。", "仁於曹孟德，勇過霍將軍。", "丹券入帑藏，青史傳子孫。", "所謂大丈夫，動合驚乾坤。", "所謂聖天子，難得忠貞臣。", "下以契魚水，上以合風雲。", "百世必一亂，千年方一人。", "吾雖翰墨子，氣概敢不羣。", "願以太平頌，題向甘泉春。"]'),
('c86ea9f2-365a-47d5-9fc5-156790cb510b','七愛詩 盧徵君','皮日休','唐','唐诗','tang','','[]','吾愛盧徵君，高臥嵩山裏。',216,'全唐诗/poet.tang.33000.json','["吾愛盧徵君，高臥嵩山裏。", "百辟未一顧，三徵方暫起。", "坦腹對宰相，岸幘揖天子。", "建禮門前吟，金鑾殿裏醉。", "天下皆餔糟，真君獨潔己。", "天下皆樂聞，徵君獨洗耳。", "天下皆懷羞，徵君獨多恥。", "銀黃不妨懸，赤紱不妨被。", "而於心抱中，獨作羲皇地。", "籃輿一云返，泥詔褒不已。", "再看緱山雲，重酌嵩陽水。", "放曠書裏終，逍遙醉中死。", "吾謂伊與周，不若徵君貴。", "吾謂巢與許，不若徵君義。", "高名無階級，逸迹絕涯涘。", "萬世唐書中，逸名不可比。", "粵吾慕真隱，強以骨肉累。", "如教不爲名，敢有徵君志。"]'),
('2d8add5f-4b86-4ea2-a579-5b94918c316c','七愛詩 元魯山','皮日休','唐','唐诗','tang','','[]','吾愛元紫芝，清介如伯夷。',168,'全唐诗/poet.tang.33000.json','["吾愛元紫芝，清介如伯夷。", "輦母遠之官，宰邑無玷疵。", "三年魯山民，豐稔不暫饑。", "三年魯山吏，清慎各自持。", "只飲魯山泉，只采魯山薇。", "一室冰檗苦，四遠聲光飛。", "退歸舊隱來，斗酒入茅茨。", "雞黍匪家畜，琴尊常自怡。", "盡日一菜食，窮年一布衣。", "清似匣中鏡，直如琴上絲。", "世無用賢人，青山生白髭。", "既臥黔婁衾，空立陳寔碑。", "吾無魯山道，空有魯山辭。", "所恨不相識，援毫空涕垂。"]'),
('57f60753-f228-4620-8be8-fa2701b3b58d','七愛詩 李翰林','皮日休','唐','唐诗','tang','','[]','吾愛李太白，身是酒星魄。',180,'全唐诗/poet.tang.33000.json','["吾愛李太白，身是酒星魄。", "口吐天上文，迹作人間客。", "磥砢千丈林，澄澈萬尋碧。", "醉中草樂府，十幅筆一息。", "召見承明廬，天子親賜食。", "醉曾吐御牀，傲幾觸天澤。", "權臣妬逸才，心如斗筲窄。", "失恩出內署，海岳甘自適。", "刺謁戴接㒿，赴宴著縠屐。", "諸侯百步迎，明君九天憶。", "竟遭腐脅疾，醉魄歸八極。", "大鵬不可籠，大椿不可植。", "蓬壺不可見，姑射不可識。", "五岳爲辭鋒，四溟作胸臆。", "惜哉千萬年，此俊不可得。"]'),
('3b96252b-751b-410c-85d5-57561fc51174','七愛詩 白太傅','皮日休','唐','唐诗','tang','','[]','吾愛白樂天，逸才生自然。',168,'全唐诗/poet.tang.33000.json','["吾愛白樂天，逸才生自然。", "誰謂辭翰器，乃是經綸賢。", "歘從浮豔詩，作得典誥篇。", "立身百行足，爲文六藝全。", "清望逸內署，直聲驚諫垣。", "所刺必有思，所臨必可傳。", "忘形任詩酒，寄傲徧林泉。", "所望標文柄，所希持化權。", "何期遇訾毀，中道多左遷。", "天下皆汲汲，樂天獨怡然。", "天下皆悶悶，樂天獨舍旃。", "高吟辭兩掖，清嘯罷三川。", "處世似孤鶴，遺榮同脫蟬。", "仕若不得志，可爲龜鏡焉。"]'),
('4500bdbe-1f32-481c-b434-049872d5877c','正樂府十篇 卒妻怨','皮日休','唐','唐诗','tang','','[]','河湟戍卒去，一半多不迴。',132,'全唐诗/poet.tang.33000.json','["河湟戍卒去，一半多不迴。", "家有半菽食，身爲一囊灰。", "官吏按其籍，伍中斥其妻。", "處處魯人髽，家家杞婦哀。", "少者任所歸，老者無所攜。", "況當札瘥年，米粒如瓊瑰。", "纍纍作餓殍，見之心若摧。", "其夫死鋒刃，其室委塵埃。", "其命即用矣，其賞安在哉。", "豈無黔敖恩，救此窮餓骸。", "誰知白屋士，念此飜欸欸。"]'),
('dcbc2e12-4880-44b8-930f-bb75ce4bd579','正樂府十篇 橡媼歎','皮日休','唐','唐诗','tang','','["\u63ed\u9732", "\u5199\u4eba", "\u540c\u60c5", "\u5199\u4eba\u8bd7"]','秋深橡子熟，散落榛蕪岡。',156,'全唐诗/poet.tang.33000.json','["秋深橡子熟，散落榛蕪岡。", "傴傴黃髪媼，拾之踐晨霜。", "移時始盈掬，盡日方滿筐。", "幾曝復幾蒸，用作三冬糧。", "山前有熟稻，紫穗襲人香。", "細獲又精舂，粒粒如玉璫。", "持之納於官，私室無倉箱。", "如何一石餘，只作五斗量。", "狡吏不畏刑，貪官不避贓。", "農時作私債，農畢歸官倉。", "自冬及於春，橡實誑飢腸。", "吾聞田成子，詐仁猶自王。", "吁嗟逢橡媼，不覺淚霑裳。"]'),
('1b8fd13a-79aa-40a6-b7c3-8e8c89ee5af0','正樂府十篇 貪官怨','皮日休','唐','唐诗','tang','','[]','國家省闥吏，賞之皆與位。',156,'全唐诗/poet.tang.33000.json','["國家省闥吏，賞之皆與位。", "素來不知書，豈能精吏理。", "大者或宰邑，小者皆尉史。", "愚者皆混沌，毒者如雄虺。", "傷哉堯舜民，肉袒受鞭箠。", "吾聞古聖王，天下無遺士。", "朝庭及下邑，治者皆仁義。", "國家選賢良，定制兼拘忌。", "所以用此徒，令之充祿仕。", "何不廣取人，何不廣歷試？", "下位既賢哉，上位何如矣。", "胥徒賞以財，俊造悉爲吏。", "天下若不平，吾當甘棄市。"]'),
('2693b5ba-1e9a-4d8b-a415-dfc484c9efa9','正樂府十篇 農父謠','皮日休','唐','唐诗','tang','','["\u9ec4\u6cb3"]','農父冤辛苦，向我述其情。',96,'全唐诗/poet.tang.33000.json','["農父冤辛苦，向我述其情。", "難將一人農，可備十人征。", "如何江淮粟，輓漕輸咸京。", "黃河水如電，一半沈與傾。", "均輸利其事，職司安敢評。", "三川豈不農，三輔豈不耕。", "奚不車其粟，用以供天兵。", "美哉農父言，何計達王程。"]'),
('6fb18d12-4851-4903-9317-d6a28b2f754d','正樂府十篇 路臣恨','皮日休','唐','唐诗','tang','','[]','路臣何方來，去馬真如龍。',120,'全唐诗/poet.tang.33000.json','["路臣何方來，去馬真如龍。", "行驕不動塵，滿轡金瓏璁。", "有人自天來，將避荆棘叢。", "獰呼不覺止，推下蒼黃中。", "十夫掣鞭策，御之如驚鴻。", "日行六七郵，瞥若鷹無蹤。", "路臣慎勿愬，愬則刑爾躬。", "軍期方似雨，天命正如風。", "七雄戰爭時，賓旅猶自通。", "如何太平世，動步却途窮。"]'),
('21fdefcf-2c46-461e-9729-1fe9dbd8bdd1','正樂府十篇 賤貢士','皮日休','唐','唐诗','tang','','[]','南越貢珠璣，西蜀進羅綺。',96,'全唐诗/poet.tang.33000.json','["南越貢珠璣，西蜀進羅綺。", "到京未晨旦，一一見天子。", "如何賢與俊，爲貢賤如此。", "所知不可求，敢望前席事。", "吾聞古聖人，射宮親選士。", "不肖盡屏跡，賢能皆得位。", "所以謂得人，所以稱多士。", "歎息幾編書，時哉又何異。"]'),
('6923eb3b-f245-42e5-bf3e-30a2a6a28872','正樂府十篇 頌夷臣','皮日休','唐','唐诗','tang','','[]','夷師本學外，仍善唐文字。',60,'全唐诗/poet.tang.33000.json','["夷師本學外，仍善唐文字。", "吾人本尚捨，何況夷臣事。", "所以不學者，反爲夷臣戲。", "所以尸祿人，反爲夷臣忌。", "吁嗟華風衰，何嘗不由是。"]'),
('d2b48c16-6454-41b1-9cb5-497b757a3181','正樂府十篇 惜義鳥','皮日休','唐','唐诗','tang','','[]','商顏多義鳥，義鳥實可嗟。',108,'全唐诗/poet.tang.33000.json','["商顏多義鳥，義鳥實可嗟。", "危巢末纍纍，隱在栲木花。", "他巢若有雛，乳之如一家。", "他巢若遭捕，投之同一羅。", "商人每秋貢，所貴復如何。", "飽以稻粱滋，飾以組繡華。", "惜哉仁義禽，委戲於宮娥。", "吾聞鳳之貴，仁義亦足夸。", "所以不遭捕，蓋緣生不多。"]'),
('c82f1f95-e9cf-4401-bfe7-461efa41a4fb','正樂府十篇 誚虛器','皮日休','唐','唐诗','tang','','[]','襄陽作髹器，中有庫露真。',84,'全唐诗/poet.tang.33000.json','["襄陽作髹器，中有庫露真。", "持以遺北虜，紿云生有神。", "每歲走其使，所費如雲屯。", "吾聞古聖王，修德來遠人。", "未聞作巧詐，用欺禽獸君。", "吾道尚如此，戎心安足云。", "如何漢宣帝，却得呼韓臣。"]'),
('9900796d-e39c-412a-8ace-1b7a1e4f51b4','正樂府十篇 哀隴民','皮日休','唐','唐诗','tang','','[]','隴山千萬仞，鸚鵡巢其巔。',132,'全唐诗/poet.tang.33000.json','["隴山千萬仞，鸚鵡巢其巔。", "窮危又極嶮，其山猶不全。", "蚩蚩隴之民，懸度如登天。", "空中覘其巢，墮者爭紛然。", "百禽不得一，十人九死焉。", "隴川有戍卒，戍卒亦不閑。", "將命提雕籠，直到金臺前。", "彼毛不自珍，彼舌不自言。", "胡爲輕人命，奉此玩好端。", "吾聞古聖王，珍獸皆舍旃。", "今此隴民屬，每歲啼漣漣。"]'),
('7f87dade-1eb1-42c0-bfa1-a1f557799e6d','奉獻致政裴祕監','皮日休','唐','唐诗','tang','','[]','何胤本徵士，高情動天地。',216,'全唐诗/poet.tang.33000.json','["何胤本徵士，高情動天地。", "既無閥閱門，常嫌冠冕累。", "宰邑著嘉政，爲郡留高致。", "移官在書府，方樂鴛池貴。", "玉季牧江西，泣之不忍離。", "捨杖隨之去，天下欽高義。", "烏帽白絺裘，籃輿竹如意。", "黃菊陶潛酒，青山謝公妓。", "月檻詠詩情，花溪釣魚戲。", "鍾陵既方舟，魏闕將結駟。", "甘求白首閑，不爲蒼生起。", "優詔加大監，所以符公議。", "既爲逍遙公，又作鴟夷子。", "安車懸不出，駟馬閑無事。", "微雨漢陂舟，殘日終南騎。", "富貴盡凌雲，何人能至此。", "猜禍皆及身，何復至如是。", "賢哉此丈夫，百世一人矣。"]'),
('2b363fb7-eaef-4220-8170-f55dc512fa36','秋夜有懷','皮日休','唐','唐诗','tang','','[]','夢裏憂身泣，覺來衣尚濕。',72,'全唐诗/poet.tang.33000.json','["夢裏憂身泣，覺來衣尚濕。", "骨肉煎我心，不是謀生急。", "如何欲佐主，功名未成立。", "處世既孤特，傳家無承襲。", "明朝走梁楚，步步出門澀。", "如何一寸心，千愁萬愁入。"]'),
('57bcca38-d5fe-4816-85dd-d35b7f9b1917','喜鵲','皮日休','唐','唐诗','tang','','[]','棄羶在庭際，雙鵲來搖尾。',36,'全唐诗/poet.tang.33000.json','["棄羶在庭際，雙鵲來搖尾。", "欲啄怕人驚，喜語晴光裏。", "何況佞倖人，微禽解如此。"]'),
('232245f7-1235-49da-8f02-c1a362ba59e1','蚊子','皮日休','唐','唐诗','tang','','[]','隱隱聚若雷，噆膚不知足。',48,'全唐诗/poet.tang.33000.json','["隱隱聚若雷，噆膚不知足。", "皇天若不平，微物教食肉。", "貧士無絳紗，忍苦臥茅屋。", "何事覓膏腴，腹無太倉粟。"]'),
('ab0c8cae-1140-46b4-8a97-f879184aff12','鹿門夏日','皮日休','唐','唐诗','tang','','[]','滿院松桂陰，日午却不知。',72,'全唐诗/poet.tang.33000.json','["滿院松桂陰，日午却不知。", "山人睡一覺，庭鵲立未移。", "出檐趁雲去，忘戴白接㒿。", "書眼若薄霧，酒腸如漏巵。", "身外所勞者，飲食須自持。", "何如便絕粒，直使身無爲。"]'),
('6f703e5c-9992-4f67-ac48-65b185208c47','偶書','皮日休','唐','唐诗','tang','','[]','女媧掉繩索，絙泥成下人。',48,'全唐诗/poet.tang.33000.json','["女媧掉繩索，絙泥成下人。", "至今頑愚者，生如土偶身。", "雲物養吾道，天爵高我貧。", "大笑猗氏輩，爲富皆不仁。"]'),
('4aaa87fa-561c-4f53-93b3-0e6c05b4fdee','讀書','皮日休','唐','唐诗','tang','','["\u8bfb\u4e66", "\u5fc3\u60c5"]','家資是何物，積帙列梁梠。',48,'全唐诗/poet.tang.33000.json','["家資是何物，積帙列梁梠。", "高齋曉開卷，獨共聖人語。", "英賢雖異世，自古心相許。", "案頭見蠹魚，猶勝凡儔侶。"]'),
('076484f6-5fd4-413d-9f33-9d045753d729','貧居秋日','皮日休','唐','唐诗','tang','','[]','亭午頭未冠，端坐獨愁予。',48,'全唐诗/poet.tang.33000.json','["亭午頭未冠，端坐獨愁予。", "貧家煙爨稀，竈底陰蟲語。", "門小媿車馬，廩空慙雀鼠。", "盡室未寒衣，機聲羨鄰女。"]'),
('577499d9-da7f-464d-ab0d-b23cad0bb023','魯望讀襄陽耆舊傳見贈五百言過褒庸材靡有稱是然襄陽曩事歷歷在目夫耆舊傳所未載者漢陽王則宗社元勳孟浩然則文章大匠予次而贊之因而寄荅亦詩人無言不詶之義也次韻','皮日休','唐','唐诗','tang','','[]','漢水碧於天，南荆廓然秀。',288,'全唐诗/poet.tang.33000.json','["漢水碧於天，南荆廓然秀。", "廬羅遵古俗，鄢郢迷昔囿。", "幽奇無得狀，巉絕不能究。", "興替忽矣新，山川悄然舊。", "斑斑生造士，一一應玄宿。", "巴庸乃嶮岨，屈景實豪右。", "是非既自分，涇渭不相就。", "粵自靈均來，清才若天漱。", "偉哉洞上隱，卓爾隆中耨。", "始將麋鹿狎，遂與麒麟鬬。", "萬乘不可謁，千鍾固非茂。", "爰從景升死，境上多兵候。", "檀溪試戈船，峴嶺屯貝胄。", "寂莫數百年，質唯包礫琇。", "上玄賞唐德，生賢命之授。", "是爲漢陽王，帝曰俞爾奏。", "巨德聳神鬼，宏才轢前後。", "勢端唯金莖，質古乃玉豆。", "行葉蔭大椿，詞源吐洪溜。", "六成清廟音，一柱明堂構。", "在昔房陵遷，圓穹正中漏。", "繄王揭然出，上下拓宇宙。", "俯視三事者，騃騃若童幼。", "低摧護中興，若鳳視其鷇。"]'),
('4005be1d-41b2-4deb-816a-e557523330b9','魯望昨以五百言見貽過有褒美內揣庸陋彌增媿悚因成一千言上述吾唐文物之盛次敘相得之歡亦迭和之微旨也','皮日休','唐','唐诗','tang','','[]','三辰至精氣，生自蒼頡前。',288,'全唐诗/poet.tang.33000.json','["三辰至精氣，生自蒼頡前。", "粵從有文字，精氣銖於緜。", "所以楊墨後，文詞縱橫顛。", "元狩富材術，建安儼英賢。", "厥祀四百餘，作者如排穿。", "五馬渡江日，羣魚食蒲年。", "大風蕩天地，萬陣黃鬚羶。", "縱有命世才，不如一空弮。", "後至陳隋世，得之拘且緛。", "太浮如瀲灩，太細如蚳蝝。", "太亂如靡靡，太輕如芊芊。", "流之爲䣱醟，變之爲游畋。", "百足雖云衆，不救殺馬蚿。", "君臣作降虜，北走如㺦猭。", "所以文字妖，致其國朝遷。", "吾唐革其弊，取士將科縣。", "文星下爲人，洪秀密於緶。", "大開紫宸扉，來者皆詳延。", "日晏朝不罷，龍姿歡𨌈𨌈。", "於焉周道反，由是秦法悛。", "射洪陳子昂，其聲亦喧闐。", "惜哉不得時，將奮猶拘攣。", "玉壘李太白，銅堤孟浩然。", "李寬包堪輿，孟澹擬漪漣。"]'),
('b4db4777-c2bf-4eb9-b82f-823e39a6d517','吳中苦雨因書一百韻寄魯望','皮日休','唐','唐诗','tang','','[]','全吳臨巨溟，百里到滬瀆。',288,'全唐诗/poet.tang.33000.json','["全吳臨巨溟，百里到滬瀆。", "海物競駢羅，水怪爭滲漉。", "狂蜃吐其氣，千尋勃然蹙。", "一刷半天墨，架爲欹危屋。", "怒鯨瞪相向，吹浪山轂轂。", "倏忽腥杳冥，須臾坼崖谷。", "帝命有嚴程，慈物有潛伏。", "噓之爲玄雲，彌亙千萬幅。", "直拔倚天劒，又建橫海纛。", "化之爲暴雨，潨潨射平陸。", "如將月窟寫，似把天河撲。", "著樹勝戟支，中人過箭鏃。", "龍光倏閃照，虯角搊琤觸。", "此時一千里，平下天台瀑。", "雷公恣其志，䃸磹裂電目。", "蹋破霹靂車，折却三四輻。", "雨工避罪者，必在蚊睫宿。", "狂發鏗訇音，不得懈怠僇。", "頃刻勢稍止，尚自傾蔌蔌。", "不敢履洿處，恐蹋爛地軸。", "自爾凡十日，茫然晦林麓。", "只是遇滂沱，少曾逢霢霂。", "伊余之廨宇，古製拙卜築。", "頹檐倒菌黃，破砌頑莎綠。"]'),
('0d61ff8f-f4cb-48be-8200-cff2e88690ab','初夏即事寄魯望','皮日休','唐','唐诗','tang','','[]','夏景恬且曠，遠人疾初平。',276,'全唐诗/poet.tang.33000.json','["夏景恬且曠，遠人疾初平。", "黃鳥語方熟，紫桐陰正清。", "廨宇有幽處，私游無定程。", "歸來閉雙關，亦忘枯與榮。", "土室作深谷，蘚垣爲干城。", "𢼮杉突杝架，迸筍支檐楹。", "片石共坐穩，病鶴同喜晴。", "癭木四五器，筇杖一兩莖。", "泉爲葛天味，松作羲皇聲。", "或看名畫徹，或吟閑詩成。", "忽枕素琴睡，時把仙書行。", "自然寡儔侶，莫說更紛爭。", "具區包地髓，震澤含天英。", "粵從三讓來，俊造紛然生。", "顧予客茲地，薄我皆爲傖。", "唯有陸夫子，盡力提客卿。", "各負出俗才，俱懷超世情。", "駐我一棧車，啜君數藜羹。", "敲門若我訪，倒屣欣逢迎。", "胡餅蒸甚熟，貊盤舉尤輕。", "茗脆不禁炙，酒肥或難傾。", "掃除就藤下，移榻尋虛明。", "唯共陸夫子，醉與天壤幷。"]'),
('e05735ce-598a-44ee-9a0b-0c060db02f62','二遊詩 徐詩','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','東莞爲著姓，奕代皆雋喆。',288,'全唐诗/poet.tang.33000.json','["東莞爲著姓，奕代皆雋喆。", "強學取科第，名聲盡孤揭。", "自爲方州來，清操稱凜冽。", "唯寫墳籍多，必云清俸絕。", "宣毫利若風，剡紙光於月。", "札吏指欲胼，萬通排未闋。", "樓船若夏屋，欲載如垤㙞。", "轉徙入吳都，縱橫礙門闑。", "縹囊輕似霧，緗帙殷於血。", "以此爲基構，將斯用貽厥。", "重於通侯印，貴却全師節。", "我愛參卿道，承家能介潔。", "潮田五萬步，草屋十餘楶。", "微宦不能去，歸來坐如刖。", "保茲萬卷書，守慎如羈紲。", "念我曾苦心，相逢無間別。", "引之看祕寶，任得窮披閱。", "軸閑翠鈿剝，籤古紅牙折。", "帙解帶芸香，卷開和桂屑。", "枕兼石鋒刃，榻共松瘡癤。", "一臥寂無諠，數編看盡徹。", "或攜歸廨宇，或把穿林樾。", "挈過太湖風，抱宿支硎雪。", "如斯未星紀，悉得分毫末。"]'),
('b9aaba6f-783b-4ca5-af11-b09bc9f40d2b','二遊詩 任詩','皮日休','唐','唐诗','tang','','[]','任君恣高放，斯道能寡合。',292,'全唐诗/poet.tang.33000.json','["任君恣高放，斯道能寡合。", "一宅閑林泉，終身遠囂雜。", "嘗聞佐浩穰，散性多儑𠉤。", "歘爾解其綬，遺之如棄靸。", "歸來鄉黨內，却與親朋洽。", "開溪未讓丁，列第方稱甲。", "入門約百步，古木聲霎霎。", "廣檻小山欹，斜廊怪石夾。", "白蓮倚闌楯，翠鳥緣簾押。", "地勢似五瀉，巖形若三峽。", "猿眠但膃肭，鳧食時啑唼。", "撥荇下文竿，結藤縈桂檝。", "門留醫樹客，壁倚栽花鍤。", "度歲止褐衣，經旬唯白㡊。", "多君方閉戶，顧我能倒屧。", "請題在茅棟，留坐於石榻。", "魂從清景遛，衣任煙霞裛。", "階墀龜任上，枕席鷗方狎。", "沼[似]頗黎[鏡]，當中見魚眨。", "杯杓悉杉瘤，盤筵盡荷葉。", "閑斟不置罰，閑弈無爭劫。", "閑日不整冠，閑風不用箑。", "以斯爲思慮，吾道寧疲薾。", "衮衣競璀璨，鼓吹爭鞺鞳。"]'),
('0dc6dc1d-ddd6-4e02-95dd-5f7a4ebb925c','追和虎丘寺清遠道士詩','皮日休','唐','唐诗','tang','','[]','成道自衰周，避世窮炎漢。',144,'全唐诗/poet.tang.33000.json','["成道自衰周，避世窮炎漢。", "荆杞雖云梗，煙霞尚容竄。", "茲岑信靈異，吾懷愜流玩。", "石澀古鐵鉎，嵐重輕埃漫。", "松膏膩幽徑，蘋沫著孤岸。", "諸蘿幄幕暗，衆鳥陶匏亂。", "巖罅地中心，海光天一半。", "玄猨行列歸，白雲次第散。", "蟾蜍生夕景，沆瀣餘清旦。", "風日采幽什，墨客學靈翰。", "嗟予慕斯文，一詠復三歎。", "顯晦雖不同，茲吟粗堪贊。"]'),
('4ff2829e-24c7-409e-8013-c09f0c25cb1e','追和幽獨君詩次韻 一','皮日休','唐','唐诗','tang','','[]','念爾風雅魄，幽咽猶能文。',24,'全唐诗/poet.tang.33000.json','["念爾風雅魄，幽咽猶能文。", "空令傷魂鳥，啼破山邊墳。"]'),
('5204c7b6-d771-4e57-b808-8ba53f8edf96','追和幽獨君詩次韻 二','皮日休','唐','唐诗','tang','','[]','恨劇但埋土，聲幽難放哀。',72,'全唐诗/poet.tang.33000.json','["恨劇但埋土，聲幽難放哀。", "墳古春自晚，愁緒空崔嵬。", "白楊老無花，枯根侵夜臺。", "天高有時裂，川去何時迴？", "雙睫不能濡，六藏無可摧。", "不聞搴蓬事，何必深悲哉。"]'),
('aefc220d-ad6e-4f1b-95c7-b5f02b848cf9','奉和魯望讀陰符經見寄','皮日休','唐','唐诗','tang','','[]','三百八十言，出自伊[祁]氏。',290,'全唐诗/poet.tang.33000.json','["三百八十言，出自伊[祁]氏。", "上以生神仙，次云立仁義。", "玄機一以發，五賊紛然起。", "結爲日月精，融作天地髓。", "不測似陰陽，難名若鬼神。", "得之升高天，失之沈厚地。", "具茨雲木老，大塊煙霞委。", "自顓頊以降，賊爲聖人軌。", "堯乃一庶人，得之賊帝摯。", "摯見其德尊，脫身授其位。", "舜唯一鰥民，冗冗作什器。", "得之賊帝堯，白丁作天子。", "禹本刑人後，以功繼其嗣。", "得之賊帝舜，用以平洚水。", "自禹及文武，天機𢟉然弛。", "姬公樹其綱，賊之爲聖智。", "聲詩川競大，禮樂山爭峙。", "爰從幽厲餘，宸極若孩穉。", "九伯真犬彘，諸侯實虎兕。", "五星合其耀，白日下闕里。", "由是聖人生，於焉當亂紀。", "黃帝之五賊，拾之若青紫。", "高揮春秋筆，不可刊一字。", "賊子虐甚斨，姦臣痛於箠。"]'),
('670c5810-3b22-45ed-a321-a519e6d751fe','初夏遊楞伽精舍','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','越舼輕似萍，漾漾出煙郭。',291,'全唐诗/poet.tang.33000.json','["越舼輕似萍，漾漾出煙郭。", "人聲漸疎曠，天氣忽寥廓。", "伊予愜斯志，有似劀{疒}瘼。", "遇勝即夷猶，逢幽且淹泊。", "俄然櫂深處，虛無倚巖崿。", "霜毫一道人，引我登龍閣。", "當中見壽象，欲禮光紛箔。", "珠幡時相鏗，恐是諸天樂。", "樹杪見觚稜，林端逢赭堊。", "千尋井猶在，萬祀靈不涸。", "下通蛟人道，水色黮而惡。", "欲照六藏驚，將窺百骸愕。", "朅去山南嶺，其險如邛笮。", "悠然放吾興，欲把青天摸。", "紫藤垂罽珥，紅荔懸纓絡。", "蘚厚滑似漦，峰尖利如鍔。", "斯須到絕頂，似愈漸離㸌。", "一片太湖光，只驚天漢落。", "梅風脫綸帽，乳水透芒屩。", "嵐姿與波彩，不動渾相著。", "既不暇供應，將何以酬酢。", "却來穿竹徑，似入青油幕。", "穴恐水君開，龕如鬼工鑿。", "窮幽入茲院，前楯臨巨壑。"]'),
('2b7fbe91-076e-4157-9c92-ed58052c3f11','公齋四詠 小松','皮日休','唐','唐诗','tang','','[]','婆娑只三尺，移來白雲徑。',108,'全唐诗/poet.tang.33000.json','["婆娑只三尺，移來白雲徑。", "亭亭向空意，已解凌遼敻。", "葉健似虯鬚，枝脆如鶴脛。", "清音猶未成，紺彩空不定。", "陰圓小芝蓋，鱗澀修荷柄。", "先愁被鷃搶，預恐遭蝸病。", "結根幸得地，且免離離映。", "磥砢不難遇，在保晚成性。", "一日造明堂，爲君當畢命。"]'),
('69632692-4e6d-48f8-91b7-652706e57d81','公齋四詠 小桂','皮日休','唐','唐诗','tang','','[]','一子落天上，生此青璧枝。',96,'全唐诗/poet.tang.33000.json','["一子落天上，生此青璧枝。", "歘從山之幽，斸斷雲根移。", "勁挺隱珪質，盤珊緹油姿。", "葉彩碧髓融，花狀白毫蕤。", "稜層立翠節，偃蹇樛青螭。", "影澹雪霽後，香汎風和時。", "吾祖在月竁，孤貞能見怡。", "願老君子地，不敢辭喧卑。"]'),
('2c0d6fe8-c591-4099-bd8e-a9a196170245','公齋四詠 新竹','皮日休','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','笠澤多異竹，移之植後楹。',108,'全唐诗/poet.tang.33000.json','["笠澤多異竹，移之植後楹。", "一架三百本，綠沈森冥冥。", "圓緊珊瑚節，釤利翡翠翎。", "儼若青帝仗，矗如紫姑屏。", "槭槭微風度，漠漠輕靄生。", "如神語鈞天，似樂奏洞庭。", "一玩九藏冷，再聞百骸醒。", "有根可以執，有𥳇可以馨。", "願稟君子操，不敢先凋零。"]'),
('a5ccbcba-402e-456d-99ad-9b3cdd21e57d','公齋四詠 鶴屏','皮日休','唐','唐诗','tang','','[]','三幅吹空縠，孰寫仙禽狀。',96,'全唐诗/poet.tang.33000.json','["三幅吹空縠，孰寫仙禽狀。", "䯔耳側以聽，赤精曠如望。", "引吭看雲勢，翹足臨池樣。", "頗似近蓐席，還如入方丈。", "盡日空不鳴，窮年但相向。", "未許子晉乘，難教道林放。", "貌既合羽儀，骨亦符法相。", "願升君子堂，不必思崑閬。"]'),
('70a337e6-827c-48b5-90fd-7018dc94d40c','奉酬崔璐進士見寄次韻','皮日休','唐','唐诗','tang','','[]','伊余幼且賤，所稟自以殊。',132,'全唐诗/poet.tang.33000.json','["伊余幼且賤，所稟自以殊。", "弱歲謬知道，有心匡皇符。", "意超海上鷹，運跼轅下駒。", "縱性作古文，所謂皆自如。", "但恐才格劣，敢誇詞彩敷。", "句句考事實，篇篇窮玄虛。", "誰能變羊質，競不獲驪珠。", "粵有造化手，曾開天地鑪。", "文章鄴下秀，氣貌淹中儒。", "展我此志業，期君持中樞。", "蒼生眼穿望，勿作磻谿謨。"]'),
('d80da79e-f25c-4c88-9d4b-cfa156716170','太湖詩 初入太湖','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','聞有太湖名，十年未曾識。',216,'全唐诗/poet.tang.33000.json','["聞有太湖名，十年未曾識。", "今朝得遊汎，大笑稱平昔。", "一舍行胥塘，盡日到震澤。", "三萬六千頃，千頃頗黎色。", "連空澹無纇，照野平絕隟。", "好放青翰舟，堪弄白玉笛。", "疎岑七十二，𡾼𡾼露矛戟。", "悠然嘯傲去，天上搖畫艗。", "西風乍獵獵，驚波罨涵碧。", "倏忽雷陣吼，須臾玉崖坼。", "樹動爲蜃尾，山浮似鼇脊。", "落照射鴻溶，清輝蕩拋𢶉。", "雲輕似可染，霞爛如堪摘。", "漸暝無處泊，挽帆從所適。", "枕下聞澎湃，肌上生瘮𤶬。", "討異足邅迴，尋幽多阻隔。", "願風與良便，吹入神仙宅。", "甘將一蘊書，永事嵩山伯。"]'),
('b6526a1c-8a89-4e43-8fee-6216d8b438b7','太湖詩 曉次神景宮','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','夜半幽夢中，扁舟似鳧躍。',288,'全唐诗/poet.tang.33000.json','["夜半幽夢中，扁舟似鳧躍。", "曉來到何許，俄倚包山脚。", "三百六十丈，攢空利如削。", "遐瞻但徙倚，欲上先矍鑠。", "濃露濕莎裳，淺泉漸草屩。", "行行未一里，節境轉寂寞。", "靜徑侵泬寥，仙扉傍巖崿。", "松聲正清絕，海日方照灼。", "歘臨幽虛天，萬想皆擺落。", "壇靈有芝菌，殿聖無鳥雀。", "瓊幃自迴旋，錦旌空粲錯。", "鼎氣爲龍虎，香煙混丹雘。", "凝看出次雲，默聽語時鶴。", "綠書不可注，雲笈應無鑰。", "晴來鳥思喜，崦裏花光弱。", "天籟如擊琴，泉聲似摐鐸。", "清齋洞前院，敢負玄科約。", "空中悉羽章，地上皆靈藥。", "金醴可酣暢，玉豉堪咀嚼。", "存心服燕胎，叩齒讀龍蹻。", "福地七十二，茲焉永堪託。", "在獸乏虎貙，於蟲不毒蠚。", "嘗聞擇骨錄，仙誌非可作。", "綠腸既朱髓，青肝復紫絡。"]'),
('14eca7bb-1703-48a5-ad74-8e7f7b2dd114','太湖詩 入林屋洞','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','齋心已三日，筋骨如煙輕。',296,'全唐诗/poet.tang.33000.json','["齋心已三日，筋骨如煙輕。", "腰下佩金獸，手中持火鈴。", "幽塘四百里，中有日月精。", "連亙三十六，各各爲玉京。", "自非心至誠，必被神物烹。", "顧余慕大道，不能惜微生。", "遂招放曠侶，同作幽憂行。", "其門纔函丈，初若盤薄硎。", "洞氣黑昳𥄴，苔髮紅鬇鬡。", "試足值坎窞，低頭避崢嶸。", "攀緣不知倦，怪異焉敢驚。", "匍匐一百步，稍稍策可橫。", "忽然白蝙蝠，來撲松炬明。", "人語散澒洞，石響高玲玎。", "脚底龍蛇氣，頭上波濤聲。", "有時若服匿，偪仄如見繃。", "俄爾造平澹，豁然逢光晶。", "金堂似鐫出，玉座如琢成。", "前有方丈沼，凝碧融人[睛]。", "雲漿湛不動，璚露涵而馨。", "漱之恐減算，酌之必延齡。", "愁爲三官責，不敢攜一{賏/缶|瓦}。", "昔云夏后氏，於此藏真經。", "刻之以紫琳，祕之以丹瓊。"]'),
('b292bd8c-131c-4b63-b09e-d82bbe23a65a','太湖詩 雨中遊包山精舍','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','松門亙五里，彩碧高下絢。',204,'全唐诗/poet.tang.33000.json','["松門亙五里，彩碧高下絢。", "幽人共躋攀，勝事頗清便。", "翣翣林上雨，隱隱湖中電。", "薜帶輕束腰，荷笠低遮面。", "濕屨黏煙霧，穿衣落霜霰。", "笑次度巖壑，困中遇臺殿。", "老僧三四人，梵字十數卷。", "施稀無夏屋，境僻乏朝膳。", "散髪抵泉流，支頤數雲片。", "坐石忽忘起，捫蘿不知倦。", "異蝶時似錦，幽禽或如鈿。", "篥簩還戛刃，栟櫚自搖扇。", "俗態既斗藪，野情空眷戀。", "道人摘芝菌，爲予備午饌。", "渴興石榴羹，飢愜胡麻飯。", "如何事于役，茲遊急於傳。", "却將塵土衣，一任瀑絲濺。"]'),
('9252b016-2f84-4b09-97e8-2f2c348f595b','太湖詩 遊毛公壇','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','却上南山路，松行儼如廡。',288,'全唐诗/poet.tang.33000.json','["却上南山路，松行儼如廡。", "松根礙幽徑，孱顏不能斧。", "擺履跨亂雲，傾巾蹲怪樹。", "三休且半日，始到毛公塢。", "兩水合一澗，潨崖却爲浦。", "相敵百千戟，共攂十萬鼓。", "噴散日月精，射破神仙府。", "唯愁絕地脈，又恐折天柱。", "一窺耳目眩，耳聽雲髪豎。", "次到鍊丹井，井幹翳宿莽。", "下有蘂剛丹，勺之百疾愈。", "凝於白獺髓，湛似桐馬乳。", "黃露醒齒牙，碧黏甘胏腑。", "檜異松復怪，枯疎互撐拄。", "乾蛟一百丈，髐然半天舞。", "下有毛公壇，壇方不盈畝。", "當時雲龍篆，一片苔蘚古。", "時時仙禽來，忽忽祥煙聚。", "我愛周息元，忽起應明主。", "三諫却歸來，迴頭唾圭組。", "伊余何不幸，斯人不復覩。", "如何大開口，與世爭枯腐。", "將山待夸娥，以肉投䝟貐。", "歘坐侵桂陰，不知已與午。"]'),
('808bbc9f-0a70-49ce-ae59-adbf8e4e7c99','太湖詩 三宿神景宮','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','古觀岑且寂，幽人情自怡。',192,'全唐诗/poet.tang.33000.json','["古觀岑且寂，幽人情自怡。", "一來包天下，三宿湖之湄。", "況此深夏夕，不逢清月姿。", "玉泉浣衣後，金殿添香時。", "客省高且敞，客牀蟠復奇。", "石枕冷入腦，筍席寒侵肌。", "氣清寐不著，起坐臨階墀。", "松陰忽微照，獨見螢火芝。", "素鶴警微露，白蓮明暗池。", "窗櫺帶乳蘚，壁縫含雲蕤。", "聞磬走魍魎，見燭奔羈雌。", "沆瀣欲滴瀝，芭蕉未離披。", "五更山蟬響，醒發如吹篪。", "杉風忽然起，飄破步虛詞。", "道客巾屨樣，上清朝禮儀。", "明發作此事，豈復甘趨馳。"]'),
('adc39c77-49ee-41cb-a07a-3ce8e30b1e50','太湖詩 以毛公泉一缾獻上諫議因寄','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','劉根昔成道，茲塢四百年。',242,'全唐诗/poet.tang.33000.json','["劉根昔成道，茲塢四百年。", "毿毿被其體，號爲綠毛仙。", "因思清[泠]汲，鑿彼岝𡿃巔。", "五色既鍊矣，一勺方鏗然。", "既用文武火，俄窮雌雄篇。", "赤鹽撲紅霧，白華飛素煙。", "服之生羽翼，倏爾沖玄天。", "真隱尚有迹，厥祀將近千。", "我來討靈勝，到此期終焉。", "滴苦破竇淨，蘚深餘甃圓。", "澄如玉髓潔，汎如金精鮮。", "顏色半帶乳，氣味全和鉛。", "飲之融痞蹇，濯之伸拘攣。", "有時玩者觸，倏忽風雷顛。", "素綆絲不短，越罌腹甚便。", "汲時月液動，擔處玉漿旋。", "敢獻大司諫，置之鈴閣前。", "清如介潔性，滌比埽蕩權。", "炙背野人興，亦思侯伯憐。", "也知飲冰苦，願受一缾泉。"]'),
('e68860ea-63fe-4389-887d-39dddd20d5a6','太湖詩 縹緲峰','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','頭戴華陽帽，手拄大夏筇。',288,'全唐诗/poet.tang.33000.json','["頭戴華陽帽，手拄大夏筇。", "清晨陪道侶，來上縹緲峰。", "帶露齅藥蔓，和雲尋鹿蹤。", "時驚𪕍𪕌鼠，飛上千丈松。", "翠壁內有室，叩之虛䃔䃧。", "古穴下徹海，視之寒鴻濛。", "遇歇有佳思，緣危無倦容。", "須臾到絕頂，似鳥穿樊籠。", "恐足蹈海日，疑身凌天風。", "衆岫點巨浸，四方接圓穹。", "似將青螺髻，撒在明月中。", "片白作越分，孤嵐爲吳宮。", "一陣靉靆氣，隱隱生湖東。", "激雷與波起，狂電將日紅。", "礊礊雨點大，金髇轟下空。", "暴光隔雲閃，髣髴亙天龍。", "連拳百丈尾，下拔湖之洪。", "捽爲一雪山，欲與昭回通。", "移時却𢷈下，細碎衡與嵩。", "神物諒不測，絕境尤難窮。", "杖策下返照，漸聞仙觀鐘。", "煙波濆肌骨，雲壑闐心胸。", "竟死愛未足，當生且歡逢。", "不然把天爵，自拜太湖公。"]'),
('0f14dbfb-b79f-4412-96cc-1830b490191c','太湖詩 桃花塢','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','夤緣度南嶺，盡日穿林樾。',144,'全唐诗/poet.tang.33000.json','["夤緣度南嶺，盡日穿林樾。", "窮深到茲塢，逸興轉超忽。", "塢名雖然在，不見桃花發。", "恐是武陵溪，自閉仙日月。", "倚峰小精舍，當嶺殘耕垡。", "將洞任迴環，把雲恣披拂。", "閑禽啼叫窱，險狖眠硉矹。", "微風吹重嵐，碧埃輕勃勃。", "清陰減鶴睡，秀色治人渴。", "敲竹鬬錚摐，弄泉爭咽嗢。", "空齋蒸柏葉，野飯調石髪。", "空羨塢中人，終身無履韤。"]'),
('84cecfb3-ecc3-46a3-8f38-54c694839241','太湖詩 明月灣','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','曉景澹無際，孤舟恣迴環。',156,'全唐诗/poet.tang.33000.json','["曉景澹無際，孤舟恣迴環。", "試問最幽處，號爲明月灣。", "半巖翡翠巢，望見不可攀。", "柳弱下絲網，藤深垂花鬘。", "松癭忽似狖，石文或如虥。", "釣壇兩三處，苔老腥斒斑。", "沙雨幾處霽，水禽相向閑。", "野人波濤上，白屋幽深間。", "曉培橘栽去，暮作魚梁還。", "清泉出石砌，好樹臨柴關。", "對此老且死，不知憂與患。", "好境無處住，好處無境刪。", "赧然不自適，脈脈當湖山。"]'),
('7bc5a351-0865-4e34-be2a-ba8575dba221','太湖詩 練瀆','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','吳王厭得國，所玩終不足。',204,'全唐诗/poet.tang.33000.json','["吳王厭得國，所玩終不足。", "一上姑蘇臺，猶自嫌局促。", "艅艎六宮鬧，艨衝後軍肅。", "一陣水麝風，空中蕩平淥。", "鳥困避錦帆，龍跧防鐵軸。", "流蘇惹煙浪，羽葆飄巖谷。", "靈境太蹂踐，因茲塞林屋。", "空闊嫌太湖，崎嶇開練瀆。", "三尋齾石齒，數里穿山腹。", "底靜似金膏，礫碎如丹粟。", "波殿鄭妲醉，蟾閣西施宿。", "幾轉含煙舟，一唱來雲曲。", "不知闌楯上，夜有越人鏃。", "君王掩面死，嬪御不敢哭。", "豔魄逐波濤，荒宮養麋鹿。", "國破溝亦淺，代變草空綠。", "白鳥都不知，朝眠還暮浴。"]'),
('67770afe-cef8-4758-aa46-bb4f73dfa2e0','太湖詩 投龍潭','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','龜山下最深，惡氣何洋溢。',156,'全唐诗/poet.tang.33000.json','["龜山下最深，惡氣何洋溢。", "涎水瀑龍巢，腥風卷蛟室。", "曉來林岑靜，獰色如怒日。", "氣涌撲炱煤，波澄埽純漆。", "下有水君府，貝闕光比櫛。", "左右列介臣，縱橫守鱗卒。", "月中珠母見，煙際楓人出。", "生犀不敢燒，水怪恐摧捽。", "時有慕道者，作彼投龍術。", "端巖持碧簡，齋戒揮紫筆。", "兼以金蜿蜒，投之光焌律。", "琴高坐赤鯉，何許縱仙逸。", "我願與之遊，茲焉託靈質。"]'),
('8732befc-eae5-4d91-bb65-215588938875','太湖詩 孤園寺','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','艇子小且兀，緣湖蕩白芷。',216,'全唐诗/poet.tang.33000.json','["艇子小且兀，緣湖蕩白芷。", "縈紆泊一碕，宛到孤園寺。", "蘿島凝清陰，松門湛虛翠。", "寒泉飛碧螭，古木鬬蒼兕。", "鐘梵在水魄，樓臺入雲肆。", "巖邊足鳴𧔢，樹杪多飛鸓。", "香莎滿院落，風汎金靃靡。", "靜鶴啄柏蠹，閑猱弄榅䗁。", "小殿熏陸香，古經貝多紙。", "老僧方瞑坐，見客還強起。", "指茲正險絕，何以來到此。", "先言洞壑數，次話真如理。", "磬韻醒閑心，茶香凝皓齒。", "巾之劫貝布，饌以栴檀餌。", "數刻得清淨，終身欲依止。", "可憐陶侍讀，身列丹臺位。", "雅號曰勝力，亦聞師佛氏。", "今日到孤園，何妨稱弟子。"]'),
('d57904e1-45cd-4723-af05-0b5604cd41ba','太湖詩 上真觀','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','徑盤在山肋，繚繞窮雲端。',288,'全唐诗/poet.tang.33000.json','["徑盤在山肋，繚繞窮雲端。", "摘菌杖頭紫，緣崖屐齒刓。", "半日到上真，洞宮知造難。", "雙戶啓真景，齋心方可觀。", "天鈞鳴響亮，天祿行蹣跚。", "琪樹夾一徑，萬條青琅玕。", "兩松峙庭際，怪狀吁可歎。", "大螾騰共結，修蛇飛相盤。", "皮膚坼甲胄，枝節擒貙犴。", "罅處似天裂，朽中如井眢。", "襹褷風聲㾌，跁跒地力痑。", "根上露鉗釱，空中狂波瀾。", "合時若莽蒼，闢處如轘轅。", "儼對無霸陣，靜問嚴陵灘。", "靈飛一以護，山都焉敢干。", "兩廊潔寂歷，中殿高巑岏。", "靜架九色節，閑懸十絕幡。", "微風時一吹，百寶清闌珊。", "昔有葉道士，位當升靈官。", "欲箋紫微志，唯食虹影丹。", "既逐隱龍去，道風由此殘。", "猶聞絳目草，往往生空壇。", "羽客兩三人，石上譚泥丸。", "謂我或龍胄，粲然與之歡。"]'),
('0279b891-b2ed-416d-b992-6a29b0199b0f','太湖詩 銷夏灣','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','太湖有曲處，其門爲兩崖。',180,'全唐诗/poet.tang.33000.json','["太湖有曲處，其門爲兩崖。", "當中數十頃，別如一天池。", "號爲銷夏灣，此名無所私。", "赤日莫斜照，清風多遙吹。", "沙嶼埽粉墨，松竹調塤篪。", "山果紅靺鞨，水苔青髬髵。", "木陰厚若瓦，嚴磴滑如飴。", "我來此遊息，夏景方赫曦。", "一坐盤石上，肅肅寒生肌。", "小艖或可汎，短策或可支。", "行驚翠羽起，坐見白蓮披。", "斂袖弄輕浪，解巾敵涼颸。", "但有水雲見，更餘沙禽知。", "京洛往來客，暍死緣奔馳。", "此中便可老，焉用名利爲。"]'),
('60857d60-dcbd-45e9-936d-322ca0252c60','太湖詩 包山祠','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','白雲最深處，像設盈巖堂。',168,'全唐诗/poet.tang.33000.json','["白雲最深處，像設盈巖堂。", "村祭足茗粣，水奠多桃槳。", "䇹䉦突古砌，薜荔繃頹牆。", "爐灰寂不然，風送杉桂香。", "積雨晦州里，流波漂稻粱。", "恭惟大司諫，憫此如發狂。", "命予傳明禱，祗事實不遑。", "一奠若肸蠁，再祝如激揚。", "出廟未半日，隔雲逢澹光。", "𡾼𡾼雨點少，漸收羽林槍。", "忽然山家犬，起吠白日傍。", "公心與神志，相向如玄黃。", "我願作一疏，奏之於穹蒼。", "留神千萬祀，永福吳封疆。"]'),
('0c2b8b8a-d4fe-4016-9534-d2cc502db923','太湖詩 聖姑廟','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','洛神有靈逸，古廟臨空渚。',108,'全唐诗/poet.tang.33000.json','["洛神有靈逸，古廟臨空渚。", "暴雨駁丹青，荒蘿繞梁梠。", "野風旋芝蓋，飢烏銜椒糈。", "寂寂落楓花，時時鬬鼯鼠。", "常云三五夕，盡會妍神侶。", "月下留紫姑，霜中召青女。", "俄然響環珮，倏爾鳴機杼。", "樂至有聞時，香來無定處。", "目瞪如有待，魂斷空無語。"]'),
('862c83e5-2a5b-49a1-922a-6f428f121bfe','太湖詩 太湖石','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','茲山有石岸，抵浪如受屠。',204,'全唐诗/poet.tang.33000.json','["茲山有石岸，抵浪如受屠。", "雪陣千萬戰，蘚巖高下刳。", "乃是天詭怪，信非人功夫。", "白丁一云取，難甚網珊瑚。", "厥狀復若何，鬼工不可圖。", "或拳若虺蜴，或蹲如虎貙。", "連絡若鉤鏁，重疊如萼跗。", "或若巨人骼，或如太帝符。", "胮肛篔簹筍，格磔琅玕株。", "斷處露海眼，移來和沙鬚。", "求之煩耄倪，載之勞舳艫。", "通侯一以眄，貴却驪龍珠。", "厚賜以賝賮，遠去窮京都。", "五侯土山下，要爾添嵒齬。", "賞玩若稱意，爵祿行斯須。", "苟有王佐士，崛起於太湖。", "試問欲西笑，得如茲石無。"]'),
('083ae792-72f4-4c2a-9452-cd34520eafd5','太湖詩 崦裏','皮日休','唐','唐诗','tang','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','崦裏何幽奇，膏腴二十頃。',120,'全唐诗/poet.tang.33000.json','["崦裏何幽奇，膏腴二十頃。", "風吹稻花香，直過龜山頂。", "青苗細膩臥，白羽悠溶靜。", "塍畔起鸊鵜，田中通舴艋。", "幾家傍潭洞，孤戍當林嶺。", "罷釣時煑菱，停繰或焙茗。", "峭然八十翁，生計於此永。", "苦力供征賦，怡顏過朝暝。", "洞庭取異事，包山極幽景。", "念爾飽得知，亦是遺民幸。"]'),
('e25964eb-bede-47fb-8e0b-86b43abd2c8b','太湖詩 石板','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','翠石數百步，如板漂不流。',132,'全唐诗/poet.tang.33000.json','["翠石數百步，如板漂不流。", "空疑水妃意，浮出青玉洲。", "中若瑩龍劒，外唯疊蛇矛。", "狂波忽然死，浩氣清且浮。", "似將翠黛色，抹破太湖秋。", "安得三五夕，攜酒櫂扁舟。", "召取月夫人，嘯歌於上頭。", "又恐霄景闊，虛皇拜仙侯。", "欲建九錫碑，當立十二樓。", "瓊文忽然下，石板誰能留。", "此事少知者，唯應波上鷗。"]'),
('ac491c06-6a76-4924-b368-b4a6d74e0f5c','奉和魯望漁具十五詠 網','皮日休','唐','唐诗','tang','','[]','晚挂溪上網，暎空如霧縠。',48,'全唐诗/poet.tang.33000.json','["晚挂溪上網，暎空如霧縠。", "閑來發其機，旋旋沈平綠。", "下處若煙雨，牽時似崖谷。", "必若遇鯤鮞，從教通一目。"]'),
('924460aa-5dba-4976-b36f-6ee7f3af2e7d','奉和魯望漁具十五詠 罩','皮日休','唐','唐诗','tang','','[]','芒鞋下葑中，步步沈輕罩。',48,'全唐诗/poet.tang.33000.json','["芒鞋下葑中，步步沈輕罩。", "既爲菱浪颭，亦爲蓮泥膠。", "人立獨無聲，魚煩似相抄。", "滿手搦霜鱗，思歸舉輕櫂。"]'),
('0923f820-c11f-40af-a5b7-650efba21ce7','奉和魯望漁具十五詠 𦊔','皮日休','唐','唐诗','tang','','[]','煙雨晚來好，東塘下𦊔去。',48,'全唐诗/poet.tang.33000.json','["煙雨晚來好，東塘下𦊔去。", "網小正星𣞷，舟輕欲騰翥。", "誰知荇深後，恰值魚多處。", "浦口更有人，停橈一延竚。"]'),
('0d6f81e5-ca0c-49a6-acd4-9f75697068f1','奉和魯望漁具十五詠 釣筒','皮日休','唐','唐诗','tang','','[]','籠籦截數尺，標置能幽絕。',48,'全唐诗/poet.tang.33000.json','["籠籦截數尺，標置能幽絕。", "從浮笠澤煙，任臥桐江月。", "絲隨碧波漫，餌逐清灘發。", "好是趁筒時，秋聲正清越。"]'),
('8219492a-63cc-40c5-88a8-de401bfd8b95','奉和魯望漁具十五詠 釣車','皮日休','唐','唐诗','tang','','[]','得樂湖海志，不厭華輈小。',48,'全唐诗/poet.tang.33000.json','["得樂湖海志，不厭華輈小。", "月中拋一聲，驚起灘上鳥。", "心將潭底測，手把波文褭。", "何處覓奔車，平波今渺渺。"]'),
('bd77ec17-84d4-453e-a248-fb8221d41492','奉和魯望漁具十五詠 漁梁','皮日休','唐','唐诗','tang','','[]','波際插翠筠，離離似清籞。',48,'全唐诗/poet.tang.33000.json','["波際插翠筠，離離似清籞。", "遊鱗到溪口，入此無逃所。", "斜臨楊柳津，靜下鸕鷀侶。", "編此欲何之，終焉富春渚。"]'),
('d7aeaee8-5e06-4c0e-8113-8329de82a04e','奉和魯望漁具十五詠 叉魚','皮日休','唐','唐诗','tang','','[]','列炬春溪口，平潭如不流。',48,'全唐诗/poet.tang.33000.json','["列炬春溪口，平潭如不流。", "照見遊泳魚，一一如清晝。", "中目碎瓊碧，毀鱗殷組繡。", "樂此何太荒，居然媿川后。"]'),
('8fdadc69-3539-4766-a5c5-7f85a777b079','奉和魯望漁具十五詠 射魚','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','注矢寂不動，澄潭晴轉烘。',48,'全唐诗/poet.tang.33000.json','["注矢寂不動，澄潭晴轉烘。", "下窺見魚樂，怳若翔在空。", "驚羽決凝碧，傷鱗浮殷紅。", "堪將指杯術，授與太湖公。"]'),
('50338747-2cfb-4be3-b847-4f3e2795d4bd','奉和魯望漁具十五詠 鳴桹','皮日休','唐','唐诗','tang','','[]','盡日平湖上，鳴桹仍動槳。',48,'全唐诗/poet.tang.33000.json','["盡日平湖上，鳴桹仍動槳。", "丁丁入波心，澄澈和清響。", "鷺聽獨寂寞，魚驚昧來往。", "盡水無所逃，川中有鉤黨。"]'),
('5bd685a3-22c5-41ea-bf92-93211e08c742','奉和魯望漁具十五詠 滬','皮日休','唐','唐诗','tang','','[]','波中植甚固，磔磔如鰕鬚。',48,'全唐诗/poet.tang.33000.json','["波中植甚固，磔磔如鰕鬚。", "濤頭倏爾過，數頃跳鯆䱐。", "不是細羅密，自爲朝夕驅。", "空憐指魚命，遣出海邊租。"]'),
('5352e489-b5fe-4b75-8a63-f22b5e3d957f','奉和魯望漁具十五詠 {𥫗/穇}','皮日休','唐','唐诗','tang','','[]','伐彼槎蘗枝，放於冰雪浦。',48,'全唐诗/poet.tang.33000.json','["伐彼槎蘗枝，放於冰雪浦。", "遊魚趁暖處，忽爾來相聚。", "徒爲棲託心，不問庇庥主。", "一旦懸鼎鑊，禍機真自取。"]'),
('d5693f81-8e08-4c72-8da2-0fb07de451b2','奉和魯望漁具十五詠 種魚','皮日休','唐','唐诗','tang','','[]','移土湖岸邊，一半和魚子。',48,'全唐诗/poet.tang.33000.json','["移土湖岸邊，一半和魚子。", "池中得春雨，點點活如蟻。", "一月便翠鱗，終年必頳尾。", "借問兩綬人，誰知種魚利。"]'),
('ca421c15-0402-445f-ae90-b5524996663f','奉和魯望漁具十五詠 藥魚','皮日休','唐','唐诗','tang','','[]','吾無竭澤心，何用藥魚藥。',48,'全唐诗/poet.tang.33000.json','["吾無竭澤心，何用藥魚藥。", "見說放溪上，點點波光惡。", "食時競夷猶，死者爭紛泊。", "何必重傷魚，毒涇猶可作。"]'),
('f36c5e06-fdc7-4660-960f-f85f24a5d97b','奉和魯望漁具十五詠 舴艋','皮日休','唐','唐诗','tang','','[]','闊處只三尺，翛然足吾事。',48,'全唐诗/poet.tang.33000.json','["闊處只三尺，翛然足吾事。", "低篷挂釣車，枯蚌盛魚餌。", "只好攜橈坐，唯堪蓋蓑睡。", "若遣遂平生，艅艎不如是。"]'),
('bd7c7c19-61f6-479e-bb53-3224a1b473e0','奉和魯望漁具十五詠 笭箵','皮日休','唐','唐诗','tang','','[]','朝空笭箵去，暮實笭箵歸。',48,'全唐诗/poet.tang.33000.json','["朝空笭箵去，暮實笭箵歸。", "歸來倒卻魚，挂在幽窗扉。", "但聞鰕蜆氣，欲生蘋藻衣。", "十年佩此處，煙雨苦霏霏。"]'),
('07236cfa-77ae-46ff-9008-8bccf39e8cfd','添魚具詩 魚菴','皮日休','唐','唐诗','tang','','[]','菴中只方丈，恰稱幽人住。',48,'全唐诗/poet.tang.33000.json','["菴中只方丈，恰稱幽人住。", "枕上悉漁經，門前空釣具。", "束竿時倚壁，曬網還侵戶。", "上浻有楊顒，須留往來路。"]'),
('97522408-7b61-4fb6-a4d3-2c5c4fef4bb7','添魚具詩 釣磯','皮日休','唐','唐诗','tang','','[]','盤灘一片石，置我山居足。',50,'全唐诗/poet.tang.33000.json','["盤灘一片石，置我山居足。", "窪處著筣笓，竅中維[𦨧]䑿。", "多逢沙鳥污，愛彼潭雲觸。", "狂奴臥此多，所以蹋帝腹。"]'),
('4bc482b1-4b6f-4c9a-a661-042e99f97444','添魚具詩 蓑衣','皮日休','唐','唐诗','tang','','[]','一領蓑正新，著來沙塢中。',48,'全唐诗/poet.tang.33000.json','["一領蓑正新，著來沙塢中。", "隔溪遙望見，疑是綠毛翁。", "襟色裛䐑靄，袖香䙰褷風。", "前頭不施衮，何以爲三公。"]'),
('c7f93aa0-6043-4c79-ac62-f2d7ac2db615','添魚具詩 篛笠','皮日休','唐','唐诗','tang','','[]','圓似寫月魂，輕如織煙翠。',48,'全唐诗/poet.tang.33000.json','["圓似寫月魂，輕如織煙翠。", "涔涔向上雨，不亂窺魚思。", "攜來沙日微，挂處江風起。", "縱帶二梁冠，終身不忘爾。"]'),
('49c93a65-c66f-4f31-9f58-94ffdcbd0642','添魚具詩 背篷','皮日休','唐','唐诗','tang','','[]','儂家背篷樣，似箇大龜甲。',48,'全唐诗/poet.tang.33000.json','["儂家背篷樣，似箇大龜甲。", "雨中跼蹐時，一向聽霎霎。", "甘從魚不見，亦任鷗相狎。", "深擁竟無言，空成睡齁䶎。"]'),
('317643c0-649e-4e9e-8dea-ea2c05b6b53d','奉和魯望樵人十詠 樵谿','皮日休','唐','唐诗','tang','','[]','何時有此谿，應便生幽木。',48,'全唐诗/poet.tang.33000.json','["何時有此谿，應便生幽木。", "橡實養山禽，藤花蒙澗鹿。", "不止產蒸薪，願當歌棫樸。", "君知天意無，以此安吾族。"]'),
('551e2d03-94a5-4966-990f-47d8a4da474d','奉和魯望樵人十詠 樵家','皮日休','唐','唐诗','tang','','[]','空山最深處，太古兩三家。',48,'全唐诗/poet.tang.33000.json','["空山最深處，太古兩三家。", "雲蘿共夙世，猨鳥同生涯。", "衣服濯春泉，盤餐烹野花。", "居茲老復老，不解歎年華。"]'),
('3119c886-e65e-4d5a-9ee1-916135428063','奉和魯望樵人十詠 樵叟','皮日休','唐','唐诗','tang','','[]','不曾照青鏡，豈解傷華髪。',48,'全唐诗/poet.tang.33000.json','["不曾照青鏡，豈解傷華髪。", "至老未息肩，至今無病骨。", "家風是林嶺，世祿爲薇蕨。", "所以兩大夫，天年自爲伐。"]'),
('6c528323-f4f5-426c-8bb4-b0f3866af9f4','奉和魯望樵人十詠 樵子','皮日休','唐','唐诗','tang','','[]','相約晚樵去，跳踉上山路。',48,'全唐诗/poet.tang.33000.json','["相約晚樵去，跳踉上山路。", "將花餌鹿麛，以果投猨父。", "束薪白雲濕，負擔春日暮。", "何不壽童烏，果爲玄所誤。"]'),
('f9c94d26-6b15-4aed-9875-04c17cd5277c','奉和魯望樵人十詠 樵徑','皮日休','唐','唐诗','tang','','[]','蒙蘢中一徑，繞在千峰裏。',48,'全唐诗/poet.tang.33000.json','["蒙蘢中一徑，繞在千峰裏。", "歇處遇松根，危中值石齒。", "花穿枲衣落，雲拂芒鞋起。", "自古行此途，不聞顛與墜。"]'),
('733668b7-7ddb-4b28-ba14-12377e0a1e91','奉和魯望樵人十詠 樵斧','皮日休','唐','唐诗','tang','','[]','腰間插大柯，直入深谿裏。',48,'全唐诗/poet.tang.33000.json','["腰間插大柯，直入深谿裏。", "空林伐一聲，幽鳥相呼起。", "倒樹去李父，傾巢啼木魅。", "不知仗鉞者，除害誰如此。"]'),
('6f2ddf3c-aeb4-472a-aee5-16646073492c','奉和魯望樵人十詠 樵擔','皮日休','唐','唐诗','tang','','[]','不敢量樵重，唯知益薪束。',48,'全唐诗/poet.tang.33000.json','["不敢量樵重，唯知益薪束。", "軋軋下山時，彎彎向身曲。", "清泉洗得潔，翠靄侵來綠。", "看取荷戈人，誰能似吾屬。"]'),
('59874232-4f7c-49fe-a539-f76a57d6337a','奉和魯望樵人十詠 樵風','皮日休','唐','唐诗','tang','','[]','野船渡樵客，來往平波中。',48,'全唐诗/poet.tang.33000.json','["野船渡樵客，來往平波中。", "縱橫清飆吹，旦暮歸期同。", "蘋光惹衣白，蓮影涵薪紅。", "吾當請封爾，直作鏡湖公。"]'),
('7b2bb4c1-f4a6-4de2-9678-ad73944df316','奉和魯望樵人十詠 樵火','皮日休','唐','唐诗','tang','','[]','山客地爐裏，然薪如陽輝。',48,'全唐诗/poet.tang.33000.json','["山客地爐裏，然薪如陽輝。", "松膏作𣺫瀡，杉子爲珠璣。", "響誤擊刺鬧，燄疑彗孛飛。", "傍邊煖白酒，不覺瀑冰垂。"]'),
('62723f3d-40a0-4599-8ba6-3bba6dbf8ad2','奉和魯望樵人十詠 樵歌','皮日休','唐','唐诗','tang','','[]','此曲太古音，由來無管奏。',48,'全唐诗/poet.tang.33000.json','["此曲太古音，由來無管奏。", "多云採樵樂，或說林泉候。", "一唱凝閑雲，再謠悲顧獸。", "若遇採詩人，誣辭收鄙陋。"]'),
('32520991-203d-43ca-b5dd-c4e4635d7f49','酒中十詠 酒星','皮日休','唐','唐诗','tang','','[]','誰遣酒旗耀，天文列其位。',48,'全唐诗/poet.tang.33000.json','["誰遣酒旗耀，天文列其位。", "彩微嘗似酣，芒弱偏如醉。", "唯憂犯帝座，只恐騎天駟。", "若遇卷舌星，讒君應墮地。"]'),
('b7e2e071-b2f5-41ef-9246-9842db2b879d','酒中十詠 酒泉','皮日休','唐','唐诗','tang','','[]','羲皇有玄酒，滋味何太薄。',48,'全唐诗/poet.tang.33000.json','["羲皇有玄酒，滋味何太薄。", "玉液是澆漓，金沙乃糟粕。", "春從野鳥沽，晝仍閑猨酌。", "我願葬茲泉，醉魂似鳧躍。"]'),
('4e9e2678-2618-4b8e-b5c6-87bab6c9a356','酒中十詠 酒篘','皮日休','唐','唐诗','tang','','[]','翠{𥫗/筏}初織來，或如古魚器。',52,'全唐诗/poet.tang.33000.json','["翠{𥫗/筏}初織來，或如古魚器。", "新從山下買，靜向甔中試。", "輕可網金醅，疎能容玉蟻。", "自此好成功，無貽我罍恥。"]'),
('a6fc5420-ad3b-4086-bc6b-f79bcc49253e','酒中十詠 酒牀','皮日休','唐','唐诗','tang','','[]','糟牀帶松節，酒膩肥如羜。',48,'全唐诗/poet.tang.33000.json','["糟牀帶松節，酒膩肥如羜。", "滴滴連有聲，空疑杜康語。", "開眉既壓後，染指偷嘗處。", "自此得公田，不過渾種黍。"]'),
('72e5501e-090e-4bed-a356-a302ce1edc3c','酒中十詠 酒壚','皮日休','唐','唐诗','tang','','[]','紅壚高幾尺，頗稱幽人意。',48,'全唐诗/poet.tang.33000.json','["紅壚高幾尺，頗稱幽人意。", "火作縹醪香，灰爲冬醷氣。", "有鎗盡龍頭，有主皆犢鼻。", "倘得作杜根，傭保何足媿。"]'),
('b577461c-313a-465c-996c-0dfe80636c70','酒中十詠 酒樓','皮日休','唐','唐诗','tang','','[]','鉤楯跨通衢，喧鬧當九市。',48,'全唐诗/poet.tang.33000.json','["鉤楯跨通衢，喧鬧當九市。", "金罍瀲灩後，玉斝紛綸起。", "舞蝶傍應酣，啼鶯聞亦醉。", "野客莫登臨，相讎多失意。"]'),
('7b2bcb6e-f0c9-468f-8b76-8f046f9a62e0','酒中十詠 酒旗','皮日休','唐','唐诗','tang','','[]','青幟闊數尺，懸於往來道。',48,'全唐诗/poet.tang.33000.json','["青幟闊數尺，懸於往來道。", "多爲風所颺，時見酒名號。", "拂拂野橋幽，翻翻江市好。", "雙眸復何事，終竟望君老。"]'),
('4a88ca38-b14b-47c3-ade0-23735290db46','酒中十詠 酒樽','皮日休','唐','唐诗','tang','','[]','犧樽一何古，我抱期幽客。',48,'全唐诗/poet.tang.33000.json','["犧樽一何古，我抱期幽客。", "少恐消醍醐，滿擬烘琥珀。", "猨窺曾撲瀉，鳥蹋經攲仄。", "度度醒來看，皆如死生隔。"]'),
('fc7f7667-995b-4968-9d3b-3ff30f07a508','酒中十詠 酒城','皮日休','唐','唐诗','tang','','[]','萬仞峻爲城，沈酣浸其俗。',48,'全唐诗/poet.tang.33000.json','["萬仞峻爲城，沈酣浸其俗。", "香侵井幹過，味染濠波淥。", "朝傾踰百榼，暮壓幾千斛。", "吾將隸此中，但爲閽者足。"]'),
('03a23c9a-4517-48b2-b75e-c4f8694719e6','酒中十詠 酒鄉','皮日休','唐','唐诗','tang','','[]','何人置此鄉，杳在天皇外。',48,'全唐诗/poet.tang.33000.json','["何人置此鄉，杳在天皇外。", "有事忘哀樂，有時忘顯晦。", "如尋罔象歸，似與希夷會。", "從此共君遊，無煩用冠帶。"]'),
('1853477b-9f34-463b-9b58-07f7d4391f74','奉和添酒中六詠 酒池','皮日休','唐','唐诗','tang','','[]','八齊競奔注，不知深幾丈。',50,'全唐诗/poet.tang.33000.json','["八齊競奔注，不知深幾丈。", "竹葉島紆徐，鳧花波蕩漾。", "醺應爛地軸，浸可柔天壤。", "以此獻吾君，願銘於[几]杖。"]'),
('f8905612-cdb1-4a87-aae0-d8b78b63d8f2','奉和添酒中六詠 酒龍','皮日休','唐','唐诗','tang','','[]','銅爲蚴蟉鱗，鑄作鱙𬵩角。',48,'全唐诗/poet.tang.33000.json','["銅爲蚴蟉鱗，鑄作鱙𬵩角。", "吐處百里雷，瀉時千丈壑。", "初疑潛苑囿，忽似拏寥廓。", "遂使銅雀臺，香消野花落。"]'),
('100b8969-f87d-4282-ada2-63ac4dd1a2fc','奉和添酒中六詠 酒甕','皮日休','唐','唐诗','tang','','[]','堅淨不苦窳，陶於醉封疆。',48,'全唐诗/poet.tang.33000.json','["堅淨不苦窳，陶於醉封疆。", "臨溪刷舊痕，隔屋聞新香。", "移來近麴室，倒處臨糟牀。", "所嗟無比鄰，余亦能偷嘗。"]'),
('b2517bc7-4894-471b-876b-290258033dd6','奉和添酒中六詠 酒船','皮日休','唐','唐诗','tang','','[]','剡桂復刳蘭，陶陶任行樂。',48,'全唐诗/poet.tang.33000.json','["剡桂復刳蘭，陶陶任行樂。", "但知涵泳好，不計風濤惡。", "嘗行麴封內，稍繫糟丘泊。", "東海如可傾，乘之就斟酌。"]'),
('ece2a87b-53be-450c-a653-09c733bb85fa','奉和添酒中六詠 酒鎗','皮日休','唐','唐诗','tang','','[]','象鼎格仍高，其中不烹餁。',48,'全唐诗/poet.tang.33000.json','["象鼎格仍高，其中不烹餁。", "唯將煮濁醪，用以資酣飲。", "偏宜旋樵火，稍近餘酲枕。", "若得伴琴書，吾將著閑品。"]'),
('73d1a9a4-23a1-427e-b414-23f78992c4e1','奉和添酒中六詠 酒杯','皮日休','唐','唐诗','tang','','[]','昔有嵇氏子，龍章而鳳姿。',48,'全唐诗/poet.tang.33000.json','["昔有嵇氏子，龍章而鳳姿。", "手揮五弦罷，聊復一樽持。", "但取性澹泊，不知味醇醨。", "茲器不復見，家家唯玉巵。"]'),
('6531a82b-78e5-4182-b59d-01cb0031652f','茶中雜詠 茶塢','皮日休','唐','唐诗','tang','','[]','閑尋堯氏山，遂入深深塢。',48,'全唐诗/poet.tang.33000.json','["閑尋堯氏山，遂入深深塢。", "種荈已成園，栽葭寧記畝。", "石窪泉似掬，巖罅雲如縷。", "好是夏初時，白花滿煙雨。"]'),
('a0bb2b2e-a58b-4ec4-9a06-a3bead15f31d','茶中雜詠 茶人','皮日休','唐','唐诗','tang','','[]','生於顧渚山，老在漫石塢。',48,'全唐诗/poet.tang.33000.json','["生於顧渚山，老在漫石塢。", "語氣爲茶荈，衣香是煙霧。", "庭從𣟤子遮，果任獳師虜。", "日晚相笑歸，腰間佩輕蔞。"]'),
('23a693bd-67ff-4859-878b-dccb248a932f','茶中雜詠 茶筍','皮日休','唐','唐诗','tang','','[]','褎然三五寸，生必依巖洞。',48,'全唐诗/poet.tang.33000.json','["褎然三五寸，生必依巖洞。", "寒恐結紅鉛，暖疑銷紫汞。", "圓如玉軸光，脆似瓊英凍。", "每爲遇之疎，南山挂幽夢。"]'),
('8aad6a19-a3f0-4b7b-96e4-ca60577a02a2','茶中雜詠 茶籯','皮日休','唐','唐诗','tang','','[]','筤篣曉攜去，驀箇山桑塢。',48,'全唐诗/poet.tang.33000.json','["筤篣曉攜去，驀箇山桑塢。", "開時送紫茗，負處沾清露。", "歇把傍雲泉，歸將挂煙樹。", "滿此是生涯，黃金何足數。"]'),
('a1abdf29-11c6-4c11-9f7a-7d4748cecbc1','茶中雜詠 茶舍','皮日休','唐','唐诗','tang','','[]','陽崖枕白屋，幾口嬉嬉活。',48,'全唐诗/poet.tang.33000.json','["陽崖枕白屋，幾口嬉嬉活。", "棚上汲紅泉，焙前蒸紫蕨。", "乃翁研茗後，中婦拍茶歇。", "相向掩柴扉，清香滿山月。"]'),
('34d40753-e7b5-40fb-92f5-4e3a14d3c97d','茶中雜詠 茶竈','皮日休','唐','唐诗','tang','','[]','南山茶事動，竈起巖根傍。',48,'全唐诗/poet.tang.33000.json','["南山茶事動，竈起巖根傍。", "水煮石髪氣，薪然杉脂香。", "青瓊蒸後凝，綠髓炊來光。", "如何重辛苦，一一輸膏粱。"]'),
('2a7fd54e-7707-499a-8084-a4d21c94bfad','茶中雜詠 茶焙','皮日休','唐','唐诗','tang','','[]','鑿彼碧巖下，恰應深二尺。',48,'全唐诗/poet.tang.33000.json','["鑿彼碧巖下，恰應深二尺。", "泥易帶雲根，燒難礙石脉。", "初能燥金餅，漸見乾瓊液。", "九里共杉林，相望在山側。"]'),
('7899d0fd-0839-4e00-a03f-c45376fad617','茶中雜詠 茶鼎','皮日休','唐','唐诗','tang','','[]','龍舒有良匠，鑄此佳樣成。',48,'全唐诗/poet.tang.33000.json','["龍舒有良匠，鑄此佳樣成。", "立作菌蠢勢，煎爲潺湲聲。", "草堂暮雲陰，松窗殘雪明。", "此時勺複茗，野語知逾清。"]'),
('fc40a1fe-6eae-45aa-b5fd-71025c3eef81','茶中雜詠 茶甌','皮日休','唐','唐诗','tang','','[]','邢客與越人，皆能造茲器。',48,'全唐诗/poet.tang.33000.json','["邢客與越人，皆能造茲器。", "圓似月魂墮，輕如雲魄起。", "棗花勢旋眼，蘋沫香沾齒。", "松下時一看，支公亦如此。"]'),
('86f8f8b4-40f4-4288-8f64-840ffb20fb09','茶中雜詠 煑茶','皮日休','唐','唐诗','tang','','[]','香泉一合乳，煎作連珠沸。',48,'全唐诗/poet.tang.33000.json','["香泉一合乳，煎作連珠沸。", "時看蟹目濺，乍見魚鱗起。", "聲疑松帶雨，餑恐生煙翠。", "尚把瀝中山，必無千日醉。"]'),
('f22f093a-6cc6-4af0-9445-fe3e1fdea6fa','石榴歌','皮日休','唐','唐诗','tang','','[]','蟬噪秋枝槐葉黃，石榴香老愁寒霜。',64,'全唐诗/poet.tang.33000.json','["蟬噪秋枝槐葉黃，石榴香老愁寒霜。", "流霞包染紫鸚粟，黃蠟紙裹紅瓠房。", "玉刻冰壺含露濕，斕斑似帶湘娥泣。", "蕭孃初嫁嗜甘酸，嚼破水精千萬粒。"]'),
('ea9b684e-9e1e-4d82-b0b0-8e76bd209d02','奉和魯望四明山九題 石窗','皮日休','唐','唐诗','tang','','[]','窗開自真宰，四達見蒼涯。',48,'全唐诗/poet.tang.33000.json','["窗開自真宰，四達見蒼涯。", "苔染渾成綺，雲漫便當紗。", "櫺中空吐月，扉際不扃霞。", "未會通何處，應憐玉女家。"]'),
('f9baba1b-a54b-4feb-a0a4-5eb9aea75d07','奉和魯望四明山九題 過雲','皮日休','唐','唐诗','tang','','[]','粉洞二十里，當中幽客行。',48,'全唐诗/poet.tang.33000.json','["粉洞二十里，當中幽客行。", "片時迷鹿迹，寸步隔人聲。", "以杖探虛翠，將襟惹薄明。", "經時未過得，恐是入層城。"]'),
('b74dbb59-cd92-4eda-b4e2-982602fbc12d','奉和魯望四明山九題 雲南','皮日休','唐','唐诗','tang','','[]','雲南背一川，無雁到峰前。',48,'全唐诗/poet.tang.33000.json','["雲南背一川，無雁到峰前。", "墟里生紅藥，人家發白泉。", "兒童皆似古，婚嫁盡如仙。", "共作真官戶，無由稅石田。"]'),
('cf864b37-32a6-458f-969e-d01bbfa0752a','奉和魯望四明山九題 雲北','皮日休','唐','唐诗','tang','','[]','雲北晝冥冥，空疑背壽星。',48,'全唐诗/poet.tang.33000.json','["雲北晝冥冥，空疑背壽星。", "犬能諳藥氣，人解寫芝形。", "野歇遇松蓋，醉書逢石屏。", "焚香住此地，應得入金庭。"]'),
('a849f6ab-75ff-4f19-b10c-a646a285687a','奉和魯望四明山九題 鹿亭','皮日休','唐','唐诗','tang','','[]','鹿羣多此住，因構白雲楣。',48,'全唐诗/poet.tang.33000.json','["鹿羣多此住，因構白雲楣。", "待侶傍花久，引麛穿竹遲。", "經時掊玉澗，盡日嗅金芝。", "爲在石窗下，成仙自不知。"]'),
('493bda0b-6e9e-4200-bc73-43bc5d431050','奉和魯望四明山九題 樊榭','皮日休','唐','唐诗','tang','','[]','主人成列仙，故榭獨依然。',48,'全唐诗/poet.tang.33000.json','["主人成列仙，故榭獨依然。", "石洞鬨人笑，松聲驚鹿眠。", "井香爲大藥，和語是靈篇。", "欲買重棲隱，雲峰不售錢。"]'),
('76daf61a-1ddd-437b-a6c9-acbfdfd1eeba','奉和魯望四明山九題 潺湲洞','皮日休','唐','唐诗','tang','','[]','陰宮何處淵，到此洞潺湲。',48,'全唐诗/poet.tang.33000.json','["陰宮何處淵，到此洞潺湲。", "敲碎一輪月，鎔銷半段天。", "響高吹谷動，勢急歕雲旋。", "料得深秋夜，臨流盡古仙。"]'),
('9c62b41a-b3a8-4258-b69d-9534a99d7312','奉和魯望四明山九題 青櫺子','皮日休','唐','唐诗','tang','','[]','山風熟異果，應是供真仙。',48,'全唐诗/poet.tang.33000.json','["山風熟異果，應是供真仙。", "味似雲腴美，形如玉腦圓。", "銜來多野鶴，落處半靈泉。", "必共玄都柰，花開不記年。"]'),
('096d9c8d-2e80-4c69-ac8e-7f2193a89d85','奉和魯望四明山九題 鞠侯','皮日休','唐','唐诗','tang','','[]','堪羨鞠侯國，碧巖千萬重。',48,'全唐诗/poet.tang.33000.json','["堪羨鞠侯國，碧巖千萬重。", "煙蘿爲印綬，雲壑是隄封。", "泉遣狙公護，果教𤟤子供。", "爾徒如不死，應得躡玄蹤。"]'),
('8cd8167d-1057-4fdb-a360-208c42c32851','五貺詩 五瀉舟','皮日休','唐','唐诗','tang','','[]','何事有青錢，因人買釣船。',48,'全唐诗/poet.tang.33000.json','["何事有青錢，因人買釣船。", "闊容兼餌坐，深許共蓑眠。", "短好隨朱鷺，輕堪倚白蓮。", "自知無用處，卻寄五湖仙。"]'),
('9d0188a8-2300-4858-8e15-fb0f67c325db','五貺詩 華頂杖','皮日休','唐','唐诗','tang','','[]','金庭仙樹枝，道客自攜持。',48,'全唐诗/poet.tang.33000.json','["金庭仙樹枝，道客自攜持。", "探洞求丹粟，挑雲覓白芝。", "量泉將濯足，闌鶴把支頤。", "以此將爲贈，惟君盡得知。"]'),
('d6faf0a2-4c5d-4edf-a9d3-85c1b44cb556','五貺詩 太湖硯','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','求於花石間，怪狀乃天然。',50,'全唐诗/poet.tang.33000.json','["求於花石間，怪狀乃天然。", "中瑩五寸劒，外[差]千疊蓮。", "月融還似洗，雲濕便堪研。", "寄與先生後，應添內外篇。"]'),
('aeff2163-9d33-409d-ab1a-5049201eb653','五貺詩 烏龍養和','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','壽木拳數尺，天生形狀幽。',48,'全唐诗/poet.tang.33000.json','["壽木拳數尺，天生形狀幽。", "把疑傷虺節，用恐破蛇瘤。", "置合月觀內，買須雲肆頭。", "料君攜去處，煙雨太湖舟。"]'),
('7d8bd31a-b6a1-44b8-9c1d-923131cee6b5','五貺詩 訶陵樽','皮日休','唐','唐诗','tang','','[]','一片鱟魚殼，其中生翠波。',48,'全唐诗/poet.tang.33000.json','["一片鱟魚殼，其中生翠波。", "買須能紫貝，用合對紅螺。", "盡瀉判狂藥，禁敲任浩歌。", "明朝與君後，爭那玉山何。"]'),
('13a06d77-8ea3-413d-b7e6-6fcb6d5a2215','早春病中書事寄魯望','皮日休','唐','唐诗','tang','','[]','眼暈見雲母，耳虛聞海濤。',48,'全唐诗/poet.tang.33000.json','["眼暈見雲母，耳虛聞海濤。", "惜春狂似蝶，養病躁於猱。", "案靜方書古，堂空藥氣高。", "可憐真宰意，偏解困吾曹。"]'),
('ab272c10-d5b9-47bc-80b5-1a42ff18e560','又寄次前韻','皮日休','唐','唐诗','tang','','[]','病根冬養得，春到一時生。',48,'全唐诗/poet.tang.33000.json','["病根冬養得，春到一時生。", "眼暗憐晨慘，心寒怯夜清。", "妻仍嫌酒癖，醫只禁詩情。", "應被高人笑，憂身不似名。"]'),
('0ad6f7dc-a532-4b55-ba40-af021f9e0789','秋晚留題魯望郊居二首 一','皮日休','唐','唐诗','tang','','[]','竹樹冷濩落，入門神已清。',48,'全唐诗/poet.tang.33000.json','["竹樹冷濩落，入門神已清。", "寒蛩傍枕響，秋菜上牆生。", "黃犬病仍吠，白驢飢不鳴。", "唯將一杯酒，盡日慰劉楨。"]'),
('330ead2f-24bf-4eda-a4b0-d0a5de6b020e','秋晚留題魯望郊居二首 二','皮日休','唐','唐诗','tang','','[]','冷臥空齋內，餘酲夕未消。',48,'全唐诗/poet.tang.33000.json','["冷臥空齋內，餘酲夕未消。", "秋花如有恨，寒蝶似無憀。", "簷上落鬬雀，籬根生晚潮。", "若輪羈旅事，猶自勝臯橋。"]'),
('5e86a5cf-40e6-42e9-b677-fee81e88805b','初冬章上人院','皮日休','唐','唐诗','tang','','[]','寒到無妨睡，僧吟不廢禪。',48,'全唐诗/poet.tang.33000.json','["寒到無妨睡，僧吟不廢禪。", "尚關經病鶴，猶濾欲枯泉。", "靜案貝多紙，閑爐波律煙。", "清譚兩三句，相向自翛然。"]'),
('6b0348bc-f356-4e00-8220-a210664a0a80','臨頓爲吳中偏勝之地陸魯望居之不出郛郭曠若郊墅余每相訪欵然惜去因成五言十首奉題屋壁 一','皮日休','唐','唐诗','tang','','[]','一方蕭灑地，之子獨深居。',48,'全唐诗/poet.tang.33000.json','["一方蕭灑地，之子獨深居。", "繞屋親栽竹，堆牀手寫書。", "高風翔砌鳥，暴雨失池魚。", "暗識歸山計，村邊買鹿車。"]'),
('14f03002-8549-4bcd-bce0-23899db1eb46','臨頓爲吳中偏勝之地陸魯望居之不出郛郭曠若郊墅余每相訪欵然惜去因成五言十首奉題屋壁 二','皮日休','唐','唐诗','tang','','[]','籬疎從綠槿，簷亂任黃茅。',48,'全唐诗/poet.tang.33000.json','["籬疎從綠槿，簷亂任黃茅。", "壓酒移谿石，煎茶拾野巢。", "靜窗懸雨笠，閑壁挂煙匏。", "支遁今無骨，誰爲世外交。"]'),
('e5b4f510-01b5-4dae-ab76-0e3f4aa64c86','臨頓爲吳中偏勝之地陸魯望居之不出郛郭曠若郊墅余每相訪欵然惜去因成五言十首奉題屋壁 三','皮日休','唐','唐诗','tang','','[]','繭稀初上簇，醅盡未乾牀。',48,'全唐诗/poet.tang.33000.json','["繭稀初上簇，醅盡未乾牀。", "盡日留蠶母，移時祭麴王。", "趁泉澆竹急，候雨種蓮忙。", "更葺園中景，應爲顧辟疆。"]'),
('59fff3b0-11ac-484a-ba34-fcade2cb0b7f','臨頓爲吳中偏勝之地陸魯望居之不出郛郭曠若郊墅余每相訪欵然惜去因成五言十首奉題屋壁 四','皮日休','唐','唐诗','tang','','[]','靜僻無人到，幽深每自知。',48,'全唐诗/poet.tang.33000.json','["靜僻無人到，幽深每自知。", "鶴來添口數，琴到益家資。", "壞塹生魚沫，頹簷落燕兒。", "空將綠蕉葉，來往寄閑詩。"]'),
('cbbdf41f-25c2-438d-8b12-7a7cf9679b11','臨頓爲吳中偏勝之地陸魯望居之不出郛郭曠若郊墅余每相訪欵然惜去因成五言十首奉題屋壁 五','皮日休','唐','唐诗','tang','','[]','夏過無擔石，日高開板扉。',48,'全唐诗/poet.tang.33000.json','["夏過無擔石，日高開板扉。", "僧雖與筒簟，人不典蕉衣。", "鶴靜共眠覺，鷺馴同釣歸。", "生公石上月，何夕約譚微。"]'),
('40ed71ce-a134-47d6-9061-3b2f285be913','臨頓爲吳中偏勝之地陸魯望居之不出郛郭曠若郊墅余每相訪欵然惜去因成五言十首奉題屋壁 六','皮日休','唐','唐诗','tang','','[]','經歲岸烏紗，讀書三十車。',48,'全唐诗/poet.tang.33000.json','["經歲岸烏紗，讀書三十車。", "水痕侵病竹，蛛網上衰花。", "詩任傳漁客，衣從遞酒家。", "知君秋晚事，白幘刈胡麻。"]'),
('d1706193-2de8-4892-a6e2-60456426b3d4','臨頓爲吳中偏勝之地陸魯望居之不出郛郭曠若郊墅余每相訪欵然惜去因成五言十首奉題屋壁 七','皮日休','唐','唐诗','tang','','[]','寂歷秋懷動，蕭條夏思殘。',48,'全唐诗/poet.tang.33000.json','["寂歷秋懷動，蕭條夏思殘。", "久貧空酒庫，多病束魚竿。", "玄想凝鶴扇，清齋拂鹿冠。", "夢魂無俗事，夜夜到金壇。"]'),
('4bbc271b-967f-4209-9121-5e5cfcb152d2','臨頓爲吳中偏勝之地陸魯望居之不出郛郭曠若郊墅余每相訪欵然惜去因成五言十首奉題屋壁 八','皮日休','唐','唐诗','tang','','[]','閉門無一事，安穩臥涼天。',48,'全唐诗/poet.tang.33000.json','["閉門無一事，安穩臥涼天。", "砌下翹飢鶴，庭陰落病蟬。", "倚杉閑把易，燒朮靜論玄。", "賴有包山客，時時寄紫泉。"]'),
('e6cb355b-e1ea-4697-864b-f822a72b02c0','臨頓爲吳中偏勝之地陸魯望居之不出郛郭曠若郊墅余每相訪欵然惜去因成五言十首奉題屋壁 九','皮日休','唐','唐诗','tang','','[]','病起扶靈壽，翛然強到門。',48,'全唐诗/poet.tang.33000.json','["病起扶靈壽，翛然強到門。", "與杉除敗葉，爲石整危根。", "薜蔓任遮壁，蓮莖臥枕盆。", "明朝有忙事，召客斵桐孫。"]'),
('c8b7d4c6-9128-4d29-9c93-3309eee6f97f','臨頓爲吳中偏勝之地陸魯望居之不出郛郭曠若郊墅余每相訪欵然惜去因成五言十首奉題屋壁 十','皮日休','唐','唐诗','tang','','[]','緩頰稱無利，低眉號不能。',48,'全唐诗/poet.tang.33000.json','["緩頰稱無利，低眉號不能。", "世情都太薄，俗意就中憎。", "雲態不知驟，鶴情非會徵。", "畫臣誰奉詔，來此寫姜肱。"]'),
('a23d64f0-cdf8-4b61-bec5-c37faa431bd5','遊棲霞寺','皮日休','唐','唐诗','tang','','[]','不見明居士，空山但寂寥。',48,'全唐诗/poet.tang.33000.json','["不見明居士，空山但寂寥。", "白蓮吟次缺，青靄坐來銷。", "泉冷無三伏，松枯有六朝。", "何時石上月，相對論逍遙。"]'),
('8044d094-982d-4eb1-8fbf-ef98567e4d9e','旅舍除夜','皮日休','唐','唐诗','tang','','[]','永夜誰能守，羈心不放眠。',48,'全唐诗/poet.tang.33000.json','["永夜誰能守，羈心不放眠。", "挑燈猶故歲，聽角已新年。", "出谷空嗟晚，銜杯尚媿先。", "晚來辭逆旅，雪涕野槐天。"]'),
('c96018f6-6fcc-482e-a2e4-7d9ec93db9a5','魯望示廣文先生吳門二章情格高散可醒俗態因追想山中風度次韻屬和存於詩編魯望之命也 一','皮日休','唐','唐诗','tang','','[]','我見先生道，休思鄭廣文。',48,'全唐诗/poet.tang.33000.json','["我見先生道，休思鄭廣文。", "鶴翻希作伴，鷗却覓爲羣。", "逸好冠清月，高宜著白雲。", "朝廷未無事，爭任醉醺醺。"]'),
('86e531fc-37aa-4172-b226-87b4662d8582','魯望示廣文先生吳門二章情格高散可醒俗態因追想山中風度次韻屬和存於詩編魯望之命也 二','皮日休','唐','唐诗','tang','','[]','能諳肉芝樣，解講隱書文。',48,'全唐诗/poet.tang.33000.json','["能諳肉芝樣，解講隱書文。", "終古神仙窟，窮年麋鹿羣。", "行廚煮白石，臥具拂青雲。", "應在雷平上，支頤復半醺。"]'),
('8b9f938e-0c23-4abd-8057-1f602dbc5a13','虎丘寺殿前有古杉一本形狀醜怪圖之不盡況百卉競媚若妬若媢娼唯此杉死抱奇節髐然闖然不知雨露之可生也風霜之可瘁也乃造化者方外之材乎遂賦三百言以見志','皮日休','唐','唐诗','tang','','[]','種日應逢晉，枯來必自隋。',288,'全唐诗/poet.tang.33000.json','["種日應逢晉，枯來必自隋。", "鰐狂將立處，螭鬬未開時。", "卓犖擲槍幹，叉牙束戟枝。", "初驚蟉篆活，復訝獝狂癡。", "勁質如堯瘦，貞容學舜黴。", "勢能擒土伯，醜可駭山祇。", "虎爪拏巖穩，虬身脫浪欹。", "槎頭禿似刷，枿觜利於錐。", "突兀方相脛，鱗皴夏氏胝。", "根應藏鬼血，柯欲漏龍漦。", "抝似神荼怒，呀如猰貐飢。", "朽癰難可吮，枯瘇不堪治。", "一炷玄雲拔，三尋黑矟奇。", "狼頭㪍窣豎，蠆尾掘攣垂。", "目燥那逢爟，心開豈中鈹。", "任苔爲疥癬，從蠹作瘡痍。", "品格齊遼鶴，年齡等寶龜。", "將懷縮地力，欲負拔山姿。", "未倒防風骨，初僵負貳屍。", "漆書明古本，鐵室抗全師。", "碨礧還無極，伶俜又莫持。", "堅應敵駿骨，文定寫甝皮。", "蟠屈愁凌剎，騰驤恐攫池。", "搶煙寒嶱𡾲，披蔦靜䙰褷。"]'),
('8d151fb9-d93b-4d0a-930b-f4915ef4a1fe','新秋言懷寄魯望三十韻','皮日休','唐','唐诗','tang','','[]','新秋入破宅，疎澹若平郊。',288,'全唐诗/poet.tang.33000.json','["新秋入破宅，疎澹若平郊。", "戶牖深如窟，詩書亂似巢。", "移牀驚蟋蟀，拂匣動蠨蛸。", "靜把泉華掬，閑拈乳管敲。", "檜身渾箇矮，石面得能䫜。", "小桂如拳葉，新松似手梢。", "鶴鳴轉清角，鶻下撲金𩩉。", "合藥還慵服，爲文亦嬾抄。", "煩心入夜醒，疾首帶涼抓。", "杉葉尖如鏃，藤絲靭似鞘。", "僨田含紫芋，低蔓隱青匏。", "老柏渾如疥，陰苔忽似膠。", "王餘落敗塹，胡孟入空庖。", "度日忘冠帶，經時憶酒肴。", "有心同木偶，無舌並金鐃。", "興欲添玄測，狂將換易爻。", "達人唯落落，俗士自譊譊。", "底力將排難，何顏用解嘲。", "欲銷毀後骨，空轉坐來胞。", "猶豫應難抱，狐疑不易包。", "等閑逢毒蠚，容易遇咆哮。", "時事方千蝎，公途正二崤。", "名微甘世棄，性拙任時拋。", "白日須投分，青雲合定交。"]'),
('b568851d-e84b-4356-bbdb-764fdc43e885','奉和魯望秋日遣懷次韻','皮日休','唐','唐诗','tang','','[]','高蹈爲時背，幽懷是事兼。',192,'全唐诗/poet.tang.33000.json','["高蹈爲時背，幽懷是事兼。", "神仙君可致，江海我能淹。", "共守庚申夜，同看乙巳占。", "藥囊除紫蠹，丹竈拂紅鹽。", "與物深無競，於生亦太廉。", "鴻災因足警，魚禍爲稀潛。", "筆硯秋光洗，衣巾夏蘚霑。", "酒甔香竹院，魚籠挂茅簷。", "琴忘因拋譜，詩存爲致籤。", "茶旗經雨展，石笋帶雲尖。", "鶴共心情慢，烏同面色黔。", "向陽裁白帢，終歲憶貂襜。", "取嶺爲山障，將泉作水簾。", "溪晴多晚鷺，池廢足秋蟾。", "破衲雖云補，閑齋未辦苫。", "共君還有役，竟夕得厭厭。"]'),
('ed4fc275-0b29-4d42-b047-258b308cf667','江南書情二十韻寄秘閣韋校書貽之商洛宋先輩垂文二同年','皮日休','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','四載加前字，今來未改銜。',242,'全唐诗/poet.tang.33000.json','["四載加前字，今來未改銜。", "君批鳳尾詔，我住虎頭巖。", "季氏唯謀逐，臧倉只擬讒。", "時訛輕五羖，俗淺重三緘。", "瘦去形如鶴，憂來態似獑。", "才非師趙壹，直欲效陳咸。", "孤竹寧收笛，黃琮未作瑊。", "作羊寧免狠，爲兔即須毚。", "枕戶槐從亞，侵堦草嬾芟。", "壅泉教咽咽，壘石放巉巉。", "掣釣隨心動，抽書任意杴。", "茶教弩父摘，酒遣僰童監。", "默坐看山困，清齋飲水嚴。", "蘚生天竺屐，煙外洞庭帆。", "病久新烏帽，閑多著白衫。", "藥苞陳[雨]匼，詩草蠹雲函。", "遣客呼林狖，辭人寄海𧍧。", "室唯搜古器，錢只買秋杉。", "寡合無深契，相期有至諴。", "他年如訪問，煙蔦暗髟髟。"]'),
('b1d0effe-f79c-42f7-a17d-6e6da5d9c8de','憶洞庭觀步十韻','皮日休','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','前時登觀步，暑雨正錚摐。',120,'全唐诗/poet.tang.33000.json','["前時登觀步，暑雨正錚摐。", "上戍看綿蕝，登村度石矼。", "崦花時有蔟，溪鳥不成雙。", "遠樹點黑矟，遙峰露碧幢。", "巖根瘦似殼，杉破腹如腔。", "䘨𧘈漁人服，筕篖野店窗。", "多攜白木鍤，愛買紫泉缸。", "仙犬聲音古，遺民意緒厖。", "何文堪緯地，底策可經邦。", "自此將妻子，歸山不姓龐。"]'),
('8d372fa7-aef1-4768-9c5a-b9c338be6043','諫議以罷郡將歸以六韻賜示因佇詶獻','皮日休','唐','唐诗','tang','','[]','欲下持衡詔，先容解印歸。',72,'全唐诗/poet.tang.33000.json','["欲下持衡詔，先容解印歸。", "露濃春後澤，霜薄霽來威。", "舊化堪治疾，餘恩可療飢。", "隔花攀去櫂，穿柳挽行衣。", "佐理能無取，酬知力甚微。", "空將千感淚，異日拜黃扉。"]'),
('71dd1555-ee74-4084-8227-4089bb48d6fb','過雲居院玄福上人舊居','皮日休','唐','唐诗','tang','','[]','重到雲居獨悄然，隔窗窺影尚疑禪。',64,'全唐诗/poet.tang.33000.json','["重到雲居獨悄然，隔窗窺影尚疑禪。", "不逢野老來聽法，猶見鄰僧爲引泉。", "龕上已生新石耳，壁間空帶舊茶煙。", "南宗弟子時時到，泣把山花奠几筵。"]'),
('0b5f0e61-f098-4ae6-b4fd-8da44bdcfb30','陪江西裴公遊襄州延慶寺','皮日休','唐','唐诗','tang','','[]','丹霄路上歇征輪，勝地偷閑一日身。',64,'全唐诗/poet.tang.33000.json','["丹霄路上歇征輪，勝地偷閑一日身。", "不署前驅驚野鳥，唯將後乘載詩人。", "巖邊候吏雲遮却，竹下朝衣露滴新。", "更向碧山深處問，不妨猶有草茅臣。"]'),
('0f206685-9c84-408a-a644-032564e5237b','西塞山泊漁家','皮日休','唐','唐诗','tang','','[]','白綸巾下髪如絲，靜倚楓根坐釣磯。',64,'全唐诗/poet.tang.33000.json','["白綸巾下髪如絲，靜倚楓根坐釣磯。", "中婦桑村挑葉去，小兒沙市買蓑歸。", "雨來蓴菜流船滑，春後鱸魚墜釣肥。", "西塞山前終日客，隔波相羨盡依依。"]'),
('f9994c65-a0d7-4b1d-8e4a-efda9ef25352','襄州春遊','皮日休','唐','唐诗','tang','','[]','信馬騰騰觸處行，春風相引與詩情。',64,'全唐诗/poet.tang.33000.json','["信馬騰騰觸處行，春風相引與詩情。", "等閑遇事成歌詠，取次衝筵隱姓名。", "映柳認人多錯誤，透花窺鳥最分明。", "岑牟單絞何曾著，莫道猖狂似禰衡。"]'),
('680be041-75fe-49af-afae-631454cd51fc','送從弟皮崇歸復州','皮日休','唐','唐诗','tang','','[]','羨爾優游正少年，竟陵煙月似吳天。',64,'全唐诗/poet.tang.33000.json','["羨爾優游正少年，竟陵煙月似吳天。", "車螯近岸無妨取，舴艋隨風不費牽。", "處處路傍千頃稻，家家門外一渠蓮。", "慇懃莫笑襄陽住，爲愛南溪縮項鳊。"]'),
('d975111e-b87f-427c-99a2-e2df00fb76c4','題潼關蘭若','皮日休','唐','唐诗','tang','','[]','潼津罷驚有招提，近百年無戰馬嘶。',64,'全唐诗/poet.tang.33000.json','["潼津罷驚有招提，近百年無戰馬嘶。", "壯士不言三尺劒，謀臣休道一丸泥。", "昔時馳道洪波上，今日宸居紫氣西。", "關吏不勞重借問，棄繻生擬入耶溪。"]'),
('19609e4c-196f-461d-8ded-09503531c42d','襄陽閑居與友生夜會','皮日休','唐','唐诗','tang','','[]','習隱悠悠世不知，林園幽事遞相期。',64,'全唐诗/poet.tang.33000.json','["習隱悠悠世不知，林園幽事遞相期。", "舊絲再上琴調晚，壞葉重燒酒煖遲。", "三徑引時寒步月，四鄰偷得夜吟詩。", "草玄寂淡無人愛，不遇劉歆更語誰。"]'),
('04ae3f10-73be-4221-ac3a-756afb2c6888','習池晨起','皮日休','唐','唐诗','tang','','[]','清曙蕭森載酒來，涼風相引繞亭臺。',64,'全唐诗/poet.tang.33000.json','["清曙蕭森載酒來，涼風相引繞亭臺。", "數聲翡翠背人去，一番芙蓉含日開。", "茭葉深深埋釣艇，魚兒漾漾逐流杯。", "竹屏風下登山屐，十宿高陽忘却迴。"]'),
('1b300278-a1cb-4487-8ab7-03febc9f1da0','秋晚自洞庭湖別業寄穆秀才','皮日休','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','破村寥落過重陽，獨自攖寧葺草房。',64,'全唐诗/poet.tang.33000.json','["破村寥落過重陽，獨自攖寧葺草房。", "風撦紅蕉仍換葉，雨淋黃菊不成香。", "野猨偷栗重窺戶，落雁疑人更繞塘。", "他日若修耆舊傳，爲予添取此書堂。"]'),
('7f3b6dcf-9df8-4497-b35d-b9f8cd786830','華山李鍊師所居','皮日休','唐','唐诗','tang','','[]','麻姑古貌上仙才，謫向蓮峰管玉臺。',64,'全唐诗/poet.tang.33000.json','["麻姑古貌上仙才，謫向蓮峰管玉臺。", "瑞氣染衣金液啓，香煙映面紫文開。", "孤雲盡日方離洞，雙鶴移時只有苔。", "深夜寂寥存想歇，月天時下草堂來。"]'),
('c8c0dcf1-0097-417d-91ae-e122fd20f27a','宏詞下第感恩獻兵部侍郎','皮日休','唐','唐诗','tang','','[]','分明仙籍列清虛，自是還丹九轉疎。',64,'全唐诗/poet.tang.33000.json','["分明仙籍列清虛，自是還丹九轉疎。", "畫虎已成翻類狗，登龍纔變即爲魚。", "空慙季布千金諾，但負劉弘一紙書。", "猶有報恩方寸在，不知通塞竟何如。"]'),
('bdd5fada-63af-4c22-a187-6d93c3ec4e99','襄州漢陽王故宅','皮日休','唐','唐诗','tang','','[]','碑字依稀廟已荒，猶聞耆舊憶賢王。',64,'全唐诗/poet.tang.33000.json','["碑字依稀廟已荒，猶聞耆舊憶賢王。", "園林一半爲他主，山水虛言是故鄉。", "戟戶野蒿生翠瓦，舞樓栖鴿汙雕梁。", "柱天功業緣何事，不得終身似霍光。"]'),
('e4ca0612-16bd-4cab-b47f-8d00bfa24902','傷盧獻秀才','皮日休','唐','唐诗','tang','','[]','愍征新價欲凌空，一首堪欺左太沖。',64,'全唐诗/poet.tang.33000.json','["愍征新價欲凌空，一首堪欺左太沖。", "只爲白衣聲過重，且非青漢路難通。", "貴侯待寫過門下，詞客偷名入卷中。", "手弄桂枝嫌不折，直教身歿負春風。"]'),
('b2c6a09a-9f2d-4d03-b728-22c54a21476b','南陽','皮日休','唐','唐诗','tang','','[]','昆陽王氣已蕭疎，依舊山河捧帝居。',64,'全唐诗/poet.tang.33000.json','["昆陽王氣已蕭疎，依舊山河捧帝居。", "廢路塌平殘瓦礫，破墳耕出爛圖書。", "綠莎滿縣年荒後，白鳥盈溪雨霽初。", "二百年來霸王業，可知今日是丘墟。"]'),
('46939335-ebc9-4075-8eea-85be03765bb0','秋晚訪李處士所居','皮日休','唐','唐诗','tang','','[]','門前襄水碧潺潺，靜釣歸來不掩關。',64,'全唐诗/poet.tang.33000.json','["門前襄水碧潺潺，靜釣歸來不掩關。", "書閣鼠穿廚簏破，竹園霜後桔橰閑。", "兒童不許驚幽鳥，藥草須教上假山。", "莫爲愛詩偏念我，訪君多得醉中還。"]'),
('96cfdc53-60b4-4f7e-9286-f89f665ba2f5','李處士郊居','皮日休','唐','唐诗','tang','','[]','石衣如髪小溪清，溪上柴門架樹成。',64,'全唐诗/poet.tang.33000.json','["石衣如髪小溪清，溪上柴門架樹成。", "園裏水流澆竹響，窗中人靜下棋聲。", "幾多狎鳥皆諳性，無限幽花未得名。", "滿引紅螺詩一首，劉楨失却病心情。"]'),
('875c43fa-0e4a-4017-9408-fe8d994f66ca','送令狐補闕歸朝','皮日休','唐','唐诗','tang','','[]','文如日月氣如虹，舉國重生正始風。',64,'全唐诗/poet.tang.33000.json','["文如日月氣如虹，舉國重生正始風。", "且願仲山居左掖，只憂徐邈入南宮。", "朝衣正在天香裏，諫草應焚禁漏中。", "爲說明年今日事，晉廷新拜黑頭公。"]'),
('50ff124a-5df0-4ebe-bca9-e7a0550b1480','洛中寒食二首 一','皮日休','唐','唐诗','tang','','[]','千門萬戶掩斜暉，繡幰金銜晚未歸。',64,'全唐诗/poet.tang.33000.json','["千門萬戶掩斜暉，繡幰金銜晚未歸。", "擊鞠王孫如錦地，鬬雞公子似花衣。", "嵩雲靜對行臺起，洛鳥閑穿上苑飛。", "唯有路傍無意者，獻書未納問淮肥。"]'),
('b6da20e4-bb4a-4c66-9b24-18e7fabed5d4','洛中寒食二首 二','皮日休','唐','唐诗','tang','','[]','遠近垂楊映鈿車，天津橋影壓神霞。',64,'全唐诗/poet.tang.33000.json','["遠近垂楊映鈿車，天津橋影壓神霞。", "弄春公子正迴首，趁節行人不到家。", "洛水萬年雲母竹，漢陵千載野棠花。", "欲知豪貴堪愁處，請看邙山晚照斜。"]'),
('4b181344-5ecc-48c3-92b1-6a84a529acba','登第後寒食杏園有宴因寄錄事宋垂文同年','皮日休','唐','唐诗','tang','','[]','雨洗清明萬象鮮，滿城車馬簇紅筵。',64,'全唐诗/poet.tang.33000.json','["雨洗清明萬象鮮，滿城車馬簇紅筵。", "恩榮雖得陪高會，科禁惟憂犯列仙。", "當醉不知開火日，正貧那似看花年。", "縱來恐被青娥笑，未納春風一宴錢。"]'),
('1366cf81-dec0-4216-8194-8a0dc5064dce','陳先輩故居','皮日休','唐','唐诗','tang','','[]','杉桂交陰一里餘，逢人渾似洞天居。',64,'全唐诗/poet.tang.33000.json','["杉桂交陰一里餘，逢人渾似洞天居。", "千株橘樹唯沽酒，十頃蓮塘不買魚。", "藜杖閑來侵徑竹，角巾端坐滿樓書。", "襄陽無限煙霞地，難覓幽奇似此殊。"]'),
('bb150d96-dd60-4020-b816-99d0375bfe5b','奉和魯望寒夜訪寂上人次韻','皮日休','唐','唐诗','tang','','[]','院寒青靄正沈沈，霜棧乾鳴入古林。',64,'全唐诗/poet.tang.33000.json','["院寒青靄正沈沈，霜棧乾鳴入古林。", "數葉貝書松火暗，一聲金磬檜煙深。", "陶潛見社無妨醉，殷浩譚經不廢吟。", "何事欲攀塵外契，除君皆有利名心。"]'),
('60202dc9-9217-4fa9-ab28-f8d0defd1394','江南道中懷茅山廣文南陽博士三首 一','皮日休','唐','唐诗','tang','','[]','寒嵐依約認華陽，遙想高人臥草堂。',64,'全唐诗/poet.tang.33000.json','["寒嵐依約認華陽，遙想高人臥草堂。", "半日始齋青䭀飯，移時空印白檀香。", "鶴雛入夜歸雲屋，乳管逢春落石牀。", "誰道夫君無伴侶，不離窗下見羲皇。"]'),
('53812167-6f76-48b8-9165-a61f373e3d70','江南道中懷茅山廣文南陽博士三首 二','皮日休','唐','唐诗','tang','','[]','住在華陽第八天，望君唯欲結良緣。',64,'全唐诗/poet.tang.33000.json','["住在華陽第八天，望君唯欲結良緣。", "堂扃洞裏千秋燕，廚蓋巖根數斗泉。", "壇上古松疑度世，觀中幽鳥恐成仙。", "不知何事迎新歲，烏納裘中一覺眠。"]'),
('cc681d08-5960-4d33-bdb0-118b3ddfc280','江南道中懷茅山廣文南陽博士三首 三','皮日休','唐','唐诗','tang','','[]','五色香煙惹內文，石飴初熟酒初醺。',64,'全唐诗/poet.tang.33000.json','["五色香煙惹內文，石飴初熟酒初醺。", "將開丹竈那防鶴，欲算棋圖却望雲。", "海氣平生當洞見，瀑冰初坼隔山聞。", "如何世外無交者，一臥金壇只有君。"]'),
('90ab5e4d-5c54-44c8-b589-2f19d71c08c1','奉和魯望早春雪中作吳體見寄','皮日休','唐','唐诗','tang','','[]','威仰噤死不敢語，瓊花雲魄清珊珊。',64,'全唐诗/poet.tang.33000.json','["威仰噤死不敢語，瓊花雲魄清珊珊。", "溪光冷射觸𪈺瑦，柳帶凍脆攢欄杆。", "竹根乍燒玉節快，酒面新潑金膏寒。", "全吳縹瓦十萬戶，惟君與我如袁安。"]'),
('9c6aa6de-31ca-4b17-b38a-3efd0fa2833c','吳中言情寄魯望','皮日休','唐','唐诗','tang','','[]','古來傖父愛吳鄉，一上胥臺不可忘。',64,'全唐诗/poet.tang.33000.json','["古來傖父愛吳鄉，一上胥臺不可忘。", "愛酒有情如手足，除詩無計似膏肓。", "宴時不輟琅書味，齋日難判玉鱠香。", "爲說松江堪老處，滿船煙月濕莎裳。"]'),
('183dee5a-d558-4256-ad81-23f1ebb59dad','行次野梅','皮日休','唐','唐诗','tang','','[]','蔦拂蘿捎一樹梅，玉妃無侶獨裴回。',64,'全唐诗/poet.tang.33000.json','["蔦拂蘿捎一樹梅，玉妃無侶獨裴回。", "好臨王母瑤池發，合傍蕭家粉水開。", "共月已爲迷眼伴，與春先作斷腸媒。", "不堪便向多情道，萬片霜華雨損來。"]'),
('420687a6-63b9-4670-ac35-365b28ac0dc1','揚州看辛夷花','皮日休','唐','唐诗','tang','','[]','臘前千朵亞芳叢，細膩偏勝素柰功。',64,'全唐诗/poet.tang.33000.json','["臘前千朵亞芳叢，細膩偏勝素柰功。", "螓首不言披曉雪，麝臍無主任春風。", "一枝拂地成瑤圃，數樹參庭是蘂宮。", "應爲當時天女服，至今猶未放全紅。"]'),
('2651d3a2-7917-4d23-8a24-553d45a6d254','暇日獨處寄魯望','皮日休','唐','唐诗','tang','','[]','幽慵不覺耗年光，犀柄金徽亂一牀。',64,'全唐诗/poet.tang.33000.json','["幽慵不覺耗年光，犀柄金徽亂一牀。", "野客共爲賒酒計，家人同作借書忙。", "園蔬預遣分僧料，廩粟先教算鶴糧。", "無限高情好風月，不妨猶得事吾王。"]'),
('1c1ae302-5908-4038-8f65-cc14cc0c6532','屣步訪魯望不遇','皮日休','唐','唐诗','tang','','[]','雪晴墟里竹欹斜，蠟屐徐吟到陸家。',64,'全唐诗/poet.tang.33000.json','["雪晴墟里竹欹斜，蠟屐徐吟到陸家。", "荒徑埽稀堆柏子，破扉開澀染苔花。", "壁閑定欲圖雙檜，廚靜空如飯一麻。", "擬受太玄今不遇，可憐遺恨似侯芭。"]'),
('fc777810-cebc-40f4-bdcc-fee4319d2727','開元寺客省早景即事','皮日休','唐','唐诗','tang','','[]','客省蕭條柿葉紅，樓臺如畫倚霜空。',64,'全唐诗/poet.tang.33000.json','["客省蕭條柿葉紅，樓臺如畫倚霜空。", "銅池數滴桂上雨，金鐸一聲松杪風。", "鶴靜時來珠像側，鴿馴多在寶幡中。", "如何塵外虛爲契，不得支公此會同。"]'),
('ba9db478-5fb2-4168-8ead-15f384b34d48','奉和魯望獨夜有懷吳體見寄','皮日休','唐','唐诗','tang','','[]','病鶴帶霧傍獨屋，破巢含雪傾孤梧。',64,'全唐诗/poet.tang.33000.json','["病鶴帶霧傍獨屋，破巢含雪傾孤梧。", "濯足將加漢光腹，抵掌欲捋梁武鬚。", "隱几清吟誰敢敵，枕琴高臥真堪圖。", "此時枉欠高散物，楠瘤作樽石作壚。"]'),
('9f7d19d2-f89e-43e8-a87a-8f646c94a1f1','病中有人惠海蟹轉寄魯望','皮日休','唐','唐诗','tang','','[]','紺甲青筐染菭衣，島夷初寄北人時。',63,'全唐诗/poet.tang.33000.json','["紺甲青筐染菭衣，島夷初寄北人時。", "離居定有石帆覺，失伴唯應海月知。", "族類分明連璅𤥐形容好箇似蟛蜞。", "病中無用霜螯處，寄與夫君左手持。"]'),
('4c4f23d7-d945-4da2-bc22-7e6782a653df','病中美景頗阻追遊因寄魯望','皮日休','唐','唐诗','tang','','[]','癭牀閑臥晝迢迢，唯把真如慰寂寥。',64,'全唐诗/poet.tang.33000.json','["癭牀閑臥晝迢迢，唯把真如慰寂寥。", "南國不須收薏苡，百年終竟是芭蕉。", "藥前美祿應難斷，枕上芳辰豈易銷。", "看取病來多少日，早梅零落玉華焦。"]'),
('4fa538bf-37c3-4fcf-935e-b5a4da970df8','魯望以花翁之什見招因次韻詶之','皮日休','唐','唐诗','tang','','[]','九十攜鋤傴僂翁，小園幽事盡能通。',64,'全唐诗/poet.tang.33000.json','["九十攜鋤傴僂翁，小園幽事盡能通。", "斸煙栽藥爲身計，負水澆花是世功。", "婚嫁定期杉葉紫，蓋藏應待桂枝紅。", "不知家道能多少，只在句芒一夜風。"]'),
('423c8127-6c8d-46cc-8adc-350b0edad543','病中庭際海石榴花盛發感而有寄','皮日休','唐','唐诗','tang','','[]','一夜春光綻絳囊，碧油枝上晝煌煌。',64,'全唐诗/poet.tang.33000.json','["一夜春光綻絳囊，碧油枝上晝煌煌。", "風勻秖似調紅露，日暖唯憂化赤霜。", "火齊滿枝燒夜月，金津含蘂滴朝陽。", "不知桂樹知情否，無限同遊阻陸郎。"]'),
('dc7fff4d-12b5-4bea-93ac-0feeb105212f','早春以橘子寄魯望','皮日休','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','箇箇和枝葉捧鮮，彩凝猶帶洞庭煙。',64,'全唐诗/poet.tang.33000.json','["箇箇和枝葉捧鮮，彩凝猶帶洞庭煙。", "不爲韓嫣金丸重，直是周王玉果圓。", "剖似日魂初破後，弄如星髓未銷前。", "知君多病仍中聖，盡送寒苞向枕邊。"]'),
('18fb49fc-db3c-4c31-92ed-0a76ac4d342d','病中書情寄上崔諫議','皮日休','唐','唐诗','tang','','[]','十日來來曠奉公，閉門無事忌春風。',64,'全唐诗/poet.tang.33000.json','["十日來來曠奉公，閉門無事忌春風。", "蟲絲度日縈琴薦，蛀粉經時落酒筒。", "馬足歇從殘漏外，魚須拋在亂書中。", "慇懃莫怪求醫切，只爲山櫻欲放紅。"]'),
('9ca3668d-597f-422d-b24e-c16d7a3c9937','病孔雀','皮日休','唐','唐诗','tang','','[]','煙花雖媚思沈冥，猶自擡頭護翠翎。',64,'全唐诗/poet.tang.33000.json','["煙花雖媚思沈冥，猶自擡頭護翠翎。", "強聽紫簫如欲舞，困眠紅樹似依屏。", "因思桂蠹傷肌骨，爲憶松鵝損性靈。", "盡日春風吹不起，鈿毫金縷一星星。"]'),
('561e8768-012a-4e74-acc4-49422fe9934b','奉和魯望上元日道室焚修','皮日休','唐','唐诗','tang','','[]','明真臺上下仙官，玄藻初吟萬籟寒。',64,'全唐诗/poet.tang.33000.json','["明真臺上下仙官，玄藻初吟萬籟寒。", "飆御有聲時杳杳，寶衣無影自珊珊。", "蘂書乞見齋心易，玉籍求添拜首難。", "端簡不知清景暮，靈蕪香燼落金壇。"]'),
('a57b8748-3c29-47da-b16f-852c81cf9564','奉詶魯望惜春見寄','皮日休','唐','唐诗','tang','','[]','十五日中春日好，可憐沈痼冷如灰。',64,'全唐诗/poet.tang.33000.json','["十五日中春日好，可憐沈痼冷如灰。", "以前雖被愁將去，向後須教醉領來。", "梅片盡飄輕粉靨，柳芽初吐爛金醅。", "病中無限花番次，爲約東風且住開。"]'),
('09724f18-974f-46d3-9c4b-3161a3d26f95','聞魯望遊顏家林園病中有寄','皮日休','唐','唐诗','tang','','[]','一夜韶姿著水光，謝家春草滿池塘。',64,'全唐诗/poet.tang.33000.json','["一夜韶姿著水光，謝家春草滿池塘。", "細挑泉眼尋新脉，輕把花枝嗅宿香。", "蝶欲試飛猶護粉，鶯初學囀尚羞簧。", "分明不得同君賞，盡日傾心羨索郎。"]'),
('207de7b4-8df4-4e4e-9b97-c44485d6d07d','奉和魯望春雨即事次韻','皮日休','唐','唐诗','tang','','[]','織恨凝愁映鳥飛，半旬飄灑掩韶暉。',64,'全唐诗/poet.tang.33000.json','["織恨凝愁映鳥飛，半旬飄灑掩韶暉。", "山容洗得如煙瘦，地脉流來似乳肥。", "野客正閑移竹遠，幽人多病探花稀。", "何年細濕華陽道，兩乘巾車相並歸。"]'),
('2d037543-38b2-4579-a8fd-728bb3a634fb','魯望春日多尋野景日休抱疾杜門因有是寄','皮日休','唐','唐诗','tang','','[]','野侶相逢不待期，半緣幽事半緣詩。',64,'全唐诗/poet.tang.33000.json','["野侶相逢不待期，半緣幽事半緣詩。", "烏紗任岸穿筋竹，白袷從披趁肉芝。", "數卷蠹書棊處展，幾升菰米釣前炊。", "病中不用君相憶，折取山櫻寄一枝。"]'),
('40982624-6c86-4d67-8443-1909cfbaf153','魯望以躬掇野蔬兼示雅什用以詶謝','皮日休','唐','唐诗','tang','','[]','杖擿春煙暖向陽，煩君爲我致盈筐。',64,'全唐诗/poet.tang.33000.json','["杖擿春煙暖向陽，煩君爲我致盈筐。", "深挑乍見牛脣液，細掐徐聞鼠耳香。", "紫甲採從泉脉畔，翠牙搜自石根傍。", "彫胡飯熟𩝊餬軟，不是高人不合嘗。"]'),
('8a80bee7-bfc1-4ad8-a5b2-4943f1ac7cb6','臥病感春寄魯望','皮日休','唐','唐诗','tang','','[]','烏皮几上困騰騰，玉柄清羸媿不能。',64,'全唐诗/poet.tang.33000.json','["烏皮几上困騰騰，玉柄清羸媿不能。", "昨夜眠時稀似鶴，今朝餐數減於僧。", "藥銷美祿應夭折，醫過芳辰定鬼憎。", "任是雨多遊未得，也須收在探花朋。"]'),
('e16cd355-514e-478b-b3d9-bbf961258148','奉和魯望徐方平後聞赦次韻','皮日休','唐','唐诗','tang','','[]','金雞煙外上臨軒，紫誥新垂作解恩。',64,'全唐诗/poet.tang.33000.json','["金雞煙外上臨軒，紫誥新垂作解恩。", "涿鹿未銷初敗血，新安頓雪已坑魂。", "空林葉盡蝗來郡，腐骨花生戰後村。", "未遣蒲車問幽隱，共君應老抱桐孫。"]'),
('a538a5d1-5a54-4a7f-a864-ce219ace9c2b','奉詶魯望見荅魚牋之什','皮日休','唐','唐诗','tang','','[]','輕如隱起膩如飴，除却鮫工解製稀。',64,'全唐诗/poet.tang.33000.json','["輕如隱起膩如飴，除却鮫工解製稀。", "欲寫恐成河伯詔，試裁疑是水仙衣。", "毫端白獺脂猶濕，指下冰蠶子欲飛。", "若用莫將閑處去，好題春思贈江妃。"]'),
('4a587124-934a-42bd-b479-d76dfcf26ea6','病後春思','皮日休','唐','唐诗','tang','','[]','連錢錦暗麝氛氳，荆思多才詠鄂君。',64,'全唐诗/poet.tang.33000.json','["連錢錦暗麝氛氳，荆思多才詠鄂君。", "孔雀鈿寒窺沼見，石榴紅重墮堦聞。", "牢愁有度應如月，春夢無心秖似雲。", "應笑病來慙滿願，花牋好作斷腸文。"]'),
('1c3c5a68-56b1-4add-9329-bedb4bb72729','偶成小酌招魯望不至以詩爲解因次韻詶之','皮日休','唐','唐诗','tang','','[]','醉侶相邀愛早陽，小筵催辦不勝忙。',64,'全唐诗/poet.tang.33000.json','["醉侶相邀愛早陽，小筵催辦不勝忙。", "衝深柳駐吳娃幰，倚短花排羯鼓牀。", "金鳳欲爲鶯引去，鈿蟬疑被蝶勾將。", "如何共是忘形者，不見漁陽摻一場。"]'),
('8e905c6c-4ac8-4038-88c1-2867c7cb51a1','以紗巾寄魯望因而有作','皮日休','唐','唐诗','tang','','[]','周家新樣替三梁，裹髪偏宜白面郎。',64,'全唐诗/poet.tang.33000.json','["周家新樣替三梁，裹髪偏宜白面郎。", "掩歛乍疑裁黑霧，輕明渾似戴玄霜。", "今朝定見看花昃，明日應聞漉酒香。", "更有一般君未識，虎文巾在絳霄房。"]'),
('08f288f1-db66-4c94-bf69-234028176b28','臨頓宅將有歸于之日魯望以詩見貺因抒懷詶之','皮日休','唐','唐诗','tang','','[]','共老林泉忍暫分，此生應不識迴文。',64,'全唐诗/poet.tang.33000.json','["共老林泉忍暫分，此生應不識迴文。", "幾枚竹笥送德曜，一乘柴車迎少君。", "舉案品多緣澗藥，承家事少爲谿雲。", "居然自是幽人事，輒莫教他孫壽聞。"]'),
('f335ff18-a7b9-4a8a-8c4b-a44a31498abf','奉和魯望謝惠巨魚之半','皮日休','唐','唐诗','tang','','[]','釣公來信自松江，三尺春魚撥刺霜。',64,'全唐诗/poet.tang.33000.json','["釣公來信自松江，三尺春魚撥刺霜。", "腹內舊鉤苔染澀，腮中新餌藻和香。", "冷鱗中斷榆錢破，寒骨平分玉筯光。", "何事貺君偏得所，秖緣同是越航郎。"]'),
('5ae5119c-4c57-454a-be5e-7ba0540dfa68','館娃宮懷古','皮日休','唐','唐诗','tang','','[]','豔骨已成蘭麝土，宮牆依舊壓層崖。',64,'全唐诗/poet.tang.33000.json','["豔骨已成蘭麝土，宮牆依舊壓層崖。", "弩臺雨壞逢金鏃，香徑泥銷露玉釵。", "硯沼只留溪鳥浴，屧廊空信野花埋。", "姑蘇麋鹿真閑事，須爲當時一愴懷。"]'),
('cf32246f-c16f-4924-ba35-f6ff4958588d','以紫石硯寄魯望兼詶見贈','皮日休','唐','唐诗','tang','','[]','樣如金蹙小能輕，微潤將融紫玉英。',64,'全唐诗/poet.tang.33000.json','["樣如金蹙小能輕，微潤將融紫玉英。", "石墨一研爲鳳尾，寒泉半勺是龍睛。", "騷人白芷傷心暗，狎客紅筵奪眼明。", "兩地有期皆好用，不須空把洗溪聲。"]'),
('060e6b75-d9a1-4593-928e-20fe6c561996','奉和魯望同遊北禪院','皮日休','唐','唐诗','tang','','[]','戚歷杉陰入草堂，老僧相見似相忘。',64,'全唐诗/poet.tang.33000.json','["戚歷杉陰入草堂，老僧相見似相忘。", "吟多幾轉蓮花漏，坐久重焚柏子香。", "魚慣齋時分淨食，鴿能閑處傍禪牀。", "雲林滿眼空羈滯，欲對彌天卻自傷。"]'),
('73b0fac5-6aad-4cc6-843a-b3b7e11454cf','孫發百篇將遊天台請詩贈行因以送之','皮日休','唐','唐诗','tang','','[]','孫子荆家思有餘，元戎曾薦入公車。',64,'全唐诗/poet.tang.33000.json','["孫子荆家思有餘，元戎曾薦入公車。", "百篇宮體喧金屋，一日官銜下玉除。", "紫府近通齋後夢，赤城新有寄來書。", "因逢二老如相問，正滯江南爲𩸃魚。"]'),
('f62bf65f-58c3-429a-820b-f9d372902828','奉和魯望薔薇次韻','皮日休','唐','唐诗','tang','','[]','誰繡連延滿戶陳，暫應遮得陸郎貧。',64,'全唐诗/poet.tang.33000.json','["誰繡連延滿戶陳，暫應遮得陸郎貧。", "紅芳掩歛將迷蝶，翠蔓飄颻欲挂人。", "低拂地時如墮馬，高臨牆處似窺鄰。", "秖應是董雙成戲，剪得神霞寸寸新。"]'),
('4c65d047-8a95-4441-b4dd-9a8138b9777e','聞開元寺開笋園寄章上人','皮日休','唐','唐诗','tang','','[]','園鏁開聲駭鹿羣，滿林鮮籜水犀文。',64,'全唐诗/poet.tang.33000.json','["園鏁開聲駭鹿羣，滿林鮮籜水犀文。", "森森競泫林梢雨，𡾼𡾼爭穿石上雲。", "並出亦如鵝管合，各生還似犬牙分。", "折煙束露如相遺，何胤明朝不茹葷。"]'),
('9d90c21f-4845-4f57-9ae8-7e245898bc21','開元寺佛鉢詩','皮日休','唐','唐诗','tang','','[]','帝青石作綠冰姿，曾得金人手自持。',64,'全唐诗/poet.tang.33000.json','["帝青石作綠冰姿，曾得金人手自持。", "拘律樹邊齋散後，提羅花下洗來時。", "乳麋味斷中天覺，麥麨香消大劫知。", "從此共君親頂戴，斜風應不等閑吹。"]'),
('9ed0eb94-827a-481e-9d25-3a8c51e8f2ee','夏首病愈因招魯望','皮日休','唐','唐诗','tang','','[]','曉入清和尚袷衣，夏陰初合掩雙扉。',64,'全唐诗/poet.tang.33000.json','["曉入清和尚袷衣，夏陰初合掩雙扉。", "一聲撥穀桑柘晚，數點舂鋤煙雨微。", "貧養山禽能箇瘦，病關芳草就中肥。", "明朝早起非無事，買得蓴絲待陸機。"]'),
('e7e23d29-65f1-4634-8738-5031ad614ceb','奉和魯望新夏東郊閑泛','皮日休','唐','唐诗','tang','','[]','水物輕明淡似秋，多情才子倚蘭舟。',70,'全唐诗/poet.tang.33000.json','["水物輕明淡似秋，多情才子倚蘭舟。", "碧莎裳下攜詩草，黃{𥫗/罒/伐}樓中挂酒篘。", "蓮葉蘸波初轉櫂，魚兒簇餌未諳鉤。", "共君莫問當時事，一點沙禽勝五侯。"]'),
('2fdbb6f5-9ef6-4839-9b04-de45d87c7134','奉和魯望四月十五日道室書事','皮日休','唐','唐诗','tang','','[]','忘朝齋戒是尋常，靜啓金根第幾章。',64,'全唐诗/poet.tang.33000.json','["忘朝齋戒是尋常，靜啓金根第幾章。", "竹葉飲爲甘露色，蓮花鮓作肉芝香。", "松膏背日凝雲磴，丹粉經年染石牀。", "剩欲與君終此志，頑仙唯恐鬢成霜。"]'),
('e929b1f0-41ec-4ee2-ae04-02530bfb8cb2','奉和魯望看壓新醅','皮日休','唐','唐诗','tang','','[]','一簀松花細有聲，旋將渠椀撇寒清。',64,'全唐诗/poet.tang.33000.json','["一簀松花細有聲，旋將渠椀撇寒清。", "秦吳只恐篘來近，劉項真能釀得平。", "酒德有神多客頌，醉鄉無貨沒人爭。", "五湖煙水郎山月，合向樽前問底名。"]'),
('bbebbf41-85d4-44a5-a7a3-91d27ca62cfe','登初陽樓寄懷北平郎中','皮日休','唐','唐诗','tang','','[]','危樓新製號初陽，白粉青葌射沼光。',64,'全唐诗/poet.tang.33000.json','["危樓新製號初陽，白粉青葌射沼光。", "避酒幾浮輕舴艋，下棊曾覺睡鴛鴦。", "投鉤列坐圍華燭，格簺分朋占靚妝。", "莫怪重登頻有恨，二年曾侍舊吳王。"]'),
('541ce5f8-6aea-4811-bf8b-07c925b40fe2','夏初訪魯望偶題小齋','皮日休','唐','唐诗','tang','','[]','半里芳陰到陸家，藜牀相勸飯胡麻。',66,'全唐诗/poet.tang.33000.json','["半里芳陰到陸家，藜牀相勸飯胡麻。", "林間度宿拋棊局，壁上經旬挂釣車。", "野客病時分竹米，鄰翁齋日乞藤花。", "踟躕爲放閑人去，半[岸]紗帩待月華。"]'),
('e700a962-d3d2-4d73-9733-c5901b271624','所居首夏水木尤清適然有作','皮日休','唐','唐诗','tang','','[]','病來無事草堂空，晝水休聞十二筒。',64,'全唐诗/poet.tang.33000.json','["病來無事草堂空，晝水休聞十二筒。", "桂靜似逢青眼客，松閑如見綠毛翁。", "潮期暗動庭泉碧，梅信微侵地障紅。", "盡日枕書慵起得，被君猶自笑從公。"]'),
('c4153730-8d0a-4e61-83e9-1bb91c0711b4','重玄寺元達年逾八十好種名藥凡所植者多至自天台四明包山句曲叢翠紛糅各可指名余奇而訪之因題二章 一','皮日休','唐','唐诗','tang','','[]','雨滌煙鋤傴僂賷，紺牙紅甲兩三畦。',64,'全唐诗/poet.tang.33000.json','["雨滌煙鋤傴僂賷，紺牙紅甲兩三畦。", "藥名却笑桐君少，年紀翻嫌竹祖低。", "白石靜敲蒸朮火，清泉閑洗種花泥。", "怪來昨日休持鉢，一尺彫胡似掌齊。"]'),
('30b88958-e8ee-4b87-b3b8-d308de1cedda','重玄寺元達年逾八十好種名藥凡所植者多至自天台四明包山句曲叢翠紛糅各可指名余奇而訪之因題二章 二','皮日休','唐','唐诗','tang','','[]','香蔓蒙蘢覆昔邪，桂煙杉露濕袈裟。',64,'全唐诗/poet.tang.33000.json','["香蔓蒙蘢覆昔邪，桂煙杉露濕袈裟。", "石盆換水撈松葉，竹徑穿牀避笋芽。", "藜杖移時挑細藥，銅缾盡日灌幽花。", "支公謾道憐神駿，不及今朝種一麻。"]'),
('2b6abb50-dd39-4253-a32e-63b2f118feb7','懷華陽潤卿博士三首 一','皮日休','唐','唐诗','tang','','[]','先生一向事虛皇，天市壇西與世忘。',64,'全唐诗/poet.tang.33000.json','["先生一向事虛皇，天市壇西與世忘。", "環堵養龜看氣訣，刀圭餌犬試仙方。", "靜探石腦衣裾潤，閑鍊松脂院落香。", "聞道徵賢須有詔，不知何日到良常。"]'),
('31d69f37-65d9-4949-a886-f1b012427546','懷華陽潤卿博士三首 二','皮日休','唐','唐诗','tang','','[]','冥心唯事白英君，不問人間爵與勳。',64,'全唐诗/poet.tang.33000.json','["冥心唯事白英君，不問人間爵與勳。", "林下醉眠仙鹿見，洞中閑話隱芝聞。", "石牀臥苦渾無蘚，藤篋開稀恐有雲。", "料得虛皇新詔樣，青瓊板上綠爲文。"]'),
('434b3294-4622-4f03-8ee2-804dc86abf8a','懷華陽潤卿博士三首 三','皮日休','唐','唐诗','tang','','[]','鳳骨輕來稱瘦容，華陽館主未成翁。',64,'全唐诗/poet.tang.33000.json','["鳳骨輕來稱瘦容，華陽館主未成翁。", "數行玉札存心久，一掬雲漿漱齒空。", "白石煮多熏屋黑，丹砂埋久染泉紅。", "他年欲事先生去，十賚須加陸逸沖。"]'),
('888711cd-1a3f-4784-8e50-3272c1973198','魯望以竹夾膝見寄因次韻詶謝','皮日休','唐','唐诗','tang','','[]','圓於玉柱滑於龍，來自衡陽彩翠中。',66,'全唐诗/poet.tang.33000.json','["圓於玉柱滑於龍，來自衡陽彩翠中。", "拂潤恐飛清夏雨，叩虛疑貯碧湘風。", "大勝書客裁成柬，頗賽谿翁截[作]筒。", "從此角巾因爾戴，俗人相訪若爲通。"]'),
('4d3c74f1-48a8-4d26-951b-550706dfe880','夏景無事因懷章來二上人二首 一','皮日休','唐','唐诗','tang','','[]','澹景微陰正送梅，幽人逃暑癭柟杯。',64,'全唐诗/poet.tang.33000.json','["澹景微陰正送梅，幽人逃暑癭柟杯。", "水花移得和魚子，山蕨收時帶竹胎。", "嘯館大都偏見月，醉鄉終竟不聞雷。", "更無一事唯留客，卻被高僧怕不來。"]'),
('eb329d28-ef4e-42f4-9220-757149ab1b63','夏景無事因懷章來二上人二首 二','皮日休','唐','唐诗','tang','','[]','佳樹盤珊枕草堂，此中隨分亦閑忙。',64,'全唐诗/poet.tang.33000.json','["佳樹盤珊枕草堂，此中隨分亦閑忙。", "平鋪風簟尋琴譜，靜掃煙窗著藥方。", "幽鳥見貧留好語，白蓮知臥送清香。", "從今有計消閑日，更爲支公置一牀。"]'),
('27c98c5d-e26e-41a1-98b5-9629416c15cd','寄瓊州楊舍人','皮日休','唐','唐诗','tang','','[]','德星芒彩瘴天涯，酒樹堪消謫宦嗟。',64,'全唐诗/poet.tang.33000.json','["德星芒彩瘴天涯，酒樹堪消謫宦嗟。", "行遇竹王因設奠，居逢木客又遷家。", "清齋淨溲桄榔麪，遠信閑封豆蔻花。", "清切會須歸有日，莫貪句漏足丹砂。"]'),
('66c0ec42-8d30-4cdc-be65-fdd9e2bcee93','魯望以輪鉤相示緬懷高致因作三篇 一','皮日休','唐','唐诗','tang','','[]','角柄孤輪細膩輕，翠篷十載伴君行。',64,'全唐诗/poet.tang.33000.json','["角柄孤輪細膩輕，翠篷十載伴君行。", "撚時解轉蟾蜍魄，拋處能啼絡緯聲。", "七里灘波喧一舍，五雲溪月靜三更。", "牛衣鮒足和蓑睡，誰信人間有利名。"]'),
('ffa9bd8a-04f7-41ba-8536-9567813589dd','魯望以輪鉤相示緬懷高致因作三篇 二','皮日休','唐','唐诗','tang','','[]','一線飄然下碧塘，溪翁無語遠相望。',64,'全唐诗/poet.tang.33000.json','["一線飄然下碧塘，溪翁無語遠相望。", "蓑衣舊去煙披重，篛笠新來雨打香。", "白鳥白蓮爲夢寐，清風清月是家鄉。", "明朝有物充君信，㰂酒三缾寄夜航。"]'),
('0d325359-d4de-4b19-9007-d308694786b3','魯望以輪鉤相示緬懷高致因作三篇 三','皮日休','唐','唐诗','tang','','[]','盡日悠然舴艋輕，小輪聲細雨溟溟。',64,'全唐诗/poet.tang.33000.json','["盡日悠然舴艋輕，小輪聲細雨溟溟。", "三尋絲帶桐江爛，一寸鉤含笠澤腥。", "用近詹何傳釣法，收和范蠡養魚經。", "孤篷半夜無餘事，應被嚴灘聒酒醒。"]'),
('2264271c-7b34-4739-8baa-ac1748a78a2e','吳中書事寄漢南裴尚書','皮日休','唐','唐诗','tang','','[]','萬家無事鏁蘭橈，鄉味腥多厭紫虈。',64,'全唐诗/poet.tang.33000.json','["萬家無事鏁蘭橈，鄉味腥多厭紫虈。", "水似棊文交度郭，柳如行障儼遮橋。", "青梅蔕重初迎雨，白鳥羣高欲避潮。", "唯望舊知憐此意，得爲傖鬼也逍遙。"]'),
('93777708-4d5b-44a3-98e8-8f82530d6506','夏景沖澹偶然作二首 一','皮日休','唐','唐诗','tang','','[]','秖隈蒲褥岸烏紗，味道澄懷景便斜。',64,'全唐诗/poet.tang.33000.json','["秖隈蒲褥岸烏紗，味道澄懷景便斜。", "紅印寄泉慙郡守，青筐與笋媿僧家。", "茗爐盡日燒松子，書案經時剝瓦花。", "園吏暫棲君莫笑，不妨猶更著南華。"]'),
('0cedfb88-2fa9-4890-8250-193289eda8c4','夏景沖澹偶然作二首 二','皮日休','唐','唐诗','tang','','[]','一室無喧事事幽，還如貞白在高樓。',64,'全唐诗/poet.tang.33000.json','["一室無喧事事幽，還如貞白在高樓。", "天台畫得千迴看，湖目芳來百度遊。", "無限世機吟處息，幾多身計釣前休。", "他年謁帝言何事，請贈劉伶作醉侯。"]'),
('d7fcc446-65c1-4784-aefe-543918779461','送李明府之任海南','皮日休','唐','唐诗','tang','','[]','五羊城在蜃樓邊，墨綬垂腰正少年。',64,'全唐诗/poet.tang.33000.json','["五羊城在蜃樓邊，墨綬垂腰正少年。", "山靜不應聞屈鳥，草深從使翳貪泉。", "蟹奴晴上臨潮檻，燕婢秋隨過海船。", "一事與君消遠宦，乳蕉花發訟庭前。"]'),
('88cdf775-079c-4c5f-aea0-e2fcae5324f5','寄題羅浮軒轅先生所居','皮日休','唐','唐诗','tang','','[]','亂峰四百三十二，欲問徵君何處尋。',64,'全唐诗/poet.tang.33000.json','["亂峰四百三十二，欲問徵君何處尋。", "紅翠數聲瑤室響，真檀一炷石樓深。", "山都遣負沽來酒，樵客容看化後金。", "從此謁師知不遠，求官先有葛洪心。"]'),
('51d34e2c-b432-4b00-ade3-2d8a3edcf27e','宿報恩寺水閣','皮日休','唐','唐诗','tang','','[]','寺鏁雙峰寂不開，幽人中夜獨裴回。',64,'全唐诗/poet.tang.33000.json','["寺鏁雙峰寂不開，幽人中夜獨裴回。", "池文帶月鋪金簟，蓮朵含風動玉杯。", "往往竹梢搖翡翠，時時杉子擲莓苔。", "可憐此際誰曾見，唯有支公盡看來。"]'),
('7e028684-1ffb-42c8-bd10-d22c2d48cf7a','醉中偶作呈魯望','皮日休','唐','唐诗','tang','','[]','谿雲澗鳥本吾儕，剛爲浮名事事乖。',64,'全唐诗/poet.tang.33000.json','["谿雲澗鳥本吾儕，剛爲浮名事事乖。", "十里尋山爲思役，五更看月是情差。", "分將吟詠華雙鬢，力以壺觴固百骸。", "爭得草堂歸臥去，共君同作太常齋。"]'),
('65f1c818-e1d1-4ed5-8fee-42d0c1191b15','寄滑州李副使員外','皮日休','唐','唐诗','tang','','[]','兵繞臨淮數十重，鐵衣才子正從公。',64,'全唐诗/poet.tang.33000.json','["兵繞臨淮數十重，鐵衣才子正從公。", "軍前草奏旄頭下，城上封書箭𦼮中。", "圍合只應聞曉雁，血腥何處避春風。", "故人勳重金章貴，猶在江湖積劒功。"]'),
('a5d01090-d09a-4b87-b32a-ce15bbc66757','傷史拱山人','皮日休','唐','唐诗','tang','','[]','一緘幽信自襄陽，上報先生去歲亡。',64,'全唐诗/poet.tang.33000.json','["一緘幽信自襄陽，上報先生去歲亡。", "山客爲醫翻貰藥，野僧因弔卻焚香。", "峰頭孤冢爲雲穴，松下靈筵是石牀。", "宗炳死來君又去，終身不復到柴桑。"]'),
('364d3de7-b26b-48d8-9704-ed012b0a0ee1','吳中言懷寄南海二同年','皮日休','唐','唐诗','tang','','[]','曲水分飛歲已賒，東南爲客各天涯。',64,'全唐诗/poet.tang.33000.json','["曲水分飛歲已賒，東南爲客各天涯。", "退公秖傍蘇勞竹，移宴多隨末利花。", "銅鼓夜敲溪上月，布帆晴照海邊霞。", "三年謾被鱸魚累，不得橫經侍絳紗。"]'),
('de5ff784-9320-4827-8c2e-f7330a0b1279','奉和魯望白鷗詩','皮日休','唐','唐诗','tang','','[]','雪羽䙰褷半惹泥，海雲深處舊巢迷。',64,'全唐诗/poet.tang.33000.json','["雪羽䙰褷半惹泥，海雲深處舊巢迷。", "池無飛浪爭教舞，洲少輕沙若遣棲。", "煙外失羣慙雁鶩，波中得志羨鳧鷖。", "主人恩重真難遇，莫爲心孤憶舊溪。"]'),
('0db03524-2bb0-4ae6-9a31-d2c67df6939e','奉和魯望懷楊台文楊鼎文二秀才','皮日休','唐','唐诗','tang','','[]','羊曇留我昔經春，各以篇章鬬五雲。',64,'全唐诗/poet.tang.33000.json','["羊曇留我昔經春，各以篇章鬬五雲。", "賓草每容閑處見，擊琴多任醉中聞。", "釣前青翰交加倚，醉後紅魚取次分。", "爲說風標曾入夢，上仙初著翠霞帬。"]'),
('1bdffcd3-de9c-4d5f-8d97-84af7e1283c8','友人以人參見惠因以詩謝之','皮日休','唐','唐诗','tang','','[]','神草延年出道家，是誰披露記三椏。',64,'全唐诗/poet.tang.33000.json','["神草延年出道家，是誰披露記三椏。", "開時的定涵雲液，斸後還應帶石花。", "名士寄來消酒渴，野人煎處撇泉華。", "從今湯劑如相續，不用金山焙上茶。"]'),
('99ffab9b-b374-46b4-805d-9dabf4d5e85c','傷進士嚴子重詩','皮日休','唐','唐诗','tang','','[]','十哭都門牓上塵，蓋棺終是五湖人。',64,'全唐诗/poet.tang.33000.json','["十哭都門牓上塵，蓋棺終是五湖人。", "生前有敵唯丹桂，沒後無家秖白蘋。", "箬下斬新醒處月，江南依舊詠來春。", "知君精爽應無盡，必在酆都頌帝晨。"]'),
('f471a654-f0a9-4964-aa18-5bc86012695f','奉和魯望早秋吳體次韻','皮日休','唐','唐诗','tang','','[]','書淫傳癖窮欲死，譊譊何必頻相仍。',64,'全唐诗/poet.tang.33000.json','["書淫傳癖窮欲死，譊譊何必頻相仍。", "日乾陰蘚厚堪剝，藤把欹松牢似繩。", "搗藥香侵白袷袖，穿雲潤破烏紗稜。", "安得瑤池飲殘酒，半醉騎下垂天鵬。"]'),
('65cc2913-da24-40f7-8e98-be927cb1fb74','奉和魯望秋賦有期次韻','皮日休','唐','唐诗','tang','','[]','十載江湖盡是閑，客兒詩句滿人間。',64,'全唐诗/poet.tang.33000.json','["十載江湖盡是閑，客兒詩句滿人間。", "郡侯聞譽親邀得，鄉老知名不放還。", "應帶瓦花經汴水，更攜雲實出包山。", "太微宮裏環岡樹，無限瑤枝待爾攀。"]'),
('ac19ce2e-2609-44c9-a262-469bbe37c3e1','奉和魯望病中秋懷次韻','皮日休','唐','唐诗','tang','','[]','貧病於君亦太兼，才高應亦被天嫌。',64,'全唐诗/poet.tang.33000.json','["貧病於君亦太兼，才高應亦被天嫌。", "因分鶴料家資減，爲置僧餐口數添。", "靜裏改詩空凭几，寒中注易不開簾。", "清詞一一侵真宰，甘取窮愁不用占。"]'),
('0be74746-3bb7-4950-aff3-2e7e22cd3c02','新秋即事三首 一','皮日休','唐','唐诗','tang','','[]','癡號多於顧愷之，更無餘事可從知。',64,'全唐诗/poet.tang.33000.json','["癡號多於顧愷之，更無餘事可從知。", "酒坊吏到常先見，鶴料符來每探支。", "涼後每謀清月社，晚來專赴白蓮期。", "共君無事堪相賀，又到金虀玉鱠時。"]'),
('c68cd992-02a6-40f9-afd3-8ca6e1237a77','新秋即事三首 二','皮日休','唐','唐诗','tang','','["\u592a\u6e56"]','堪笑高陽病酒徒，幅巾瀟灑在東吳。',64,'全唐诗/poet.tang.33000.json','["堪笑高陽病酒徒，幅巾瀟灑在東吳。", "秋期淨掃雲根瘦，山信迴緘乳管粗。", "白月半窗抄朮序，清泉一器授芝圖。", "乞求待得西風起，盡挽煙帆入太湖。"]'),
('d168d5c5-6b8c-4788-9869-cad38c4a5486','新秋即事三首 三','皮日休','唐','唐诗','tang','','[]','露槿風杉滿曲除，高秋無事似雲廬。',64,'全唐诗/poet.tang.33000.json','["露槿風杉滿曲除，高秋無事似雲廬。", "醉多已任家人厭，病久還甘吏道疎。", "青桂巾箱時寄藥，白綸臥具半拋書。", "君卿脣舌非吾事，且向江南問鰒魚。"]'),
('b5854d12-3ec9-40fb-9b09-15e1386bb7e5','南陽潤卿將歸雷平因而有贈','皮日休','唐','唐诗','tang','','[]','借問山中許道士，此迴歸去復何如。',64,'全唐诗/poet.tang.33000.json','["借問山中許道士，此迴歸去復何如。", "竹屏風扇抄遺事，柘步輿竿繫隱書。", "絳樹實多分紫鹿，丹沙泉淺種紅魚。", "東卿旄節看看至，靜啓茅齋慎掃除。"]'),
('18f9003a-86d9-49cf-9eb4-174f33d1c5e1','訪寂上人不遇','皮日休','唐','唐诗','tang','','[]','何處尋雲暫廢禪，客來還寄草堂眠。',64,'全唐诗/poet.tang.33000.json','["何處尋雲暫廢禪，客來還寄草堂眠。", "桂寒自落翻經案，石冷空消洗鉢泉。", "爐裏尚飄殘玉篆，龕中仍鏁小金仙。", "須將二百籤迴去，得得支公恐隔年。"]');
